-- ----------------------------
-- Table structure for acc_product_shipment
-- ----------------------------
DROP TABLE IF EXISTS `acc_product_shipment`;
CREATE TABLE `acc_product_shipment`  (
  `seq` int(18) UNSIGNED ZEROFILL NOT NULL AUTO_INCREMENT COMMENT 'id',
  `order_seq` int(11) NULL DEFAULT NULL COMMENT '生产订单seq',
  `po_no` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '生产订单po',
  `prou_order_seq` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '生产指令号',
  `customer_id` int(11) NULL DEFAULT NULL COMMENT '客户Id',
  `customer_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户编码',
  `customer_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `art_customer_article_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户型体号 ',
  `sku` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'sku',
  `basic_size_code` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '尺码（基本码）',
  `art_quarter_code` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '季度',
  `art_code` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工厂型体号',
  `art_name` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工厂型体名称',
  `art_color` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品资料颜色序号',
  `art_color_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品资料颜色名称',
  `warehouse` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '配码收货地址',
  `shipment_quantity` decimal(18, 0) NULL DEFAULT NULL COMMENT '出货数量',
  `shipment_at` datetime NULL DEFAULT NULL COMMENT '出货时间',
  `shipment_code` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '出库单号',
  `delivery_code` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '送货单号',
  `del_flag` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否删除：0-否,1-是',
  `created_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `update_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `delete_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `delete_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `remark` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `is_available` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否可用：0可用;1不可用',
  `price` decimal(10, 2) NULL DEFAULT NULL COMMENT '单价',
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `key`(`po_no`, `basic_size_code`, `shipment_code`, `shipment_at`, `prou_order_seq`) USING BTREE,
  INDEX `idx_query_conditions`(`del_flag`, `is_available`, `created_at`, `seq`) USING BTREE,
  INDEX `idx_created_at`(`created_at`) USING BTREE,
  INDEX `customer_id`(`customer_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1686337 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '成品出库信息表。mes同步资料' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for acc_product_shipment_new
-- ----------------------------
DROP TABLE IF EXISTS `acc_product_shipment_new`;
CREATE TABLE `acc_product_shipment_new`  (
  `firmId` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'firmId',
  `firmName` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'firmName',
  `shipment_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'outCode',
  `QUARTER_CODE` varchar(10) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `PO` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'po',
  `COLOR` varchar(10) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `basic_size_code` varchar(20) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'sizeName',
  `OUTDATE` datetime(3) NULL DEFAULT NULL COMMENT 'outDate',
  `SHIPMENT_QUANTITY` decimal(12, 0) NULL DEFAULT NULL COMMENT 'shipment_quantity',
  `created_by` varchar(20) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'cjName',
  `created_at` datetime(3) NULL DEFAULT NULL COMMENT 'cjTime',
  `SKU` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `OD_ORDER_DOC_SEQ` bigint(20) NULL DEFAULT NULL,
  `CUSTOMER_ID` bigint(20) NULL DEFAULT NULL,
  `TOTAL_NUMBER` bigint(20) NULL DEFAULT NULL,
  `QUOTATION_AMOUNT` decimal(14, 4) NULL DEFAULT NULL,
  `ORDER_CODE` varchar(60) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `CUSTOMER_NAME` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `MANUAL_PROD_CODE` varchar(100) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `DESTINATION` varchar(200) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `SIZE_CODES` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `CUSTOMER_ARTICLE_CODE` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `COLOR_NAME` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  PRIMARY KEY (`firmId`, `firmName`, `shipment_code`, `PO`, `basic_size_code`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for acc_reconciliation
-- ----------------------------
DROP TABLE IF EXISTS `acc_reconciliation`;
CREATE TABLE `acc_reconciliation`  (
  `seq` bigint(18) UNSIGNED ZEROFILL NOT NULL AUTO_INCREMENT COMMENT 'seq',
  `bill_no` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '应收款对账单号',
  `customer_id` int(11) NULL DEFAULT NULL COMMENT '客户id',
  `customer_code` varchar(11) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户编号',
  `customer_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `transaction_amount` decimal(18, 2) NULL DEFAULT NULL COMMENT '成交金额',
  `receivable_amount` decimal(18, 2) NULL DEFAULT 0.00 COMMENT '应收金额',
  `currency_type` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '币种',
  `payment_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '付款方式',
  `inventory_code` varchar(125) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '出库单号',
  `accounting` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '取年月日2025-04-01，计算的是4月',
  `bank_card_no` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司银行账号/来源 bas_company_bank',
  `remark` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `status` varchar(3) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '状态(0草稿，1待审校，2已审核待上传发票，3，已完成）',
  `is_available` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否可用：0可用，1不可用',
  `del_flag` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否删除：0-否,1-是',
  `created_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `update_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `delete_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `delete_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `created_by_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人姓名',
  `invoice_date` datetime NULL DEFAULT NULL COMMENT '开票日期',
  `invoice_file_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '发票附件名',
  `invoice_path` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '发票地址',
  `payment_identifier` int(11) NULL DEFAULT 0 COMMENT '收款标识',
  `amount_received` decimal(14, 4) NULL DEFAULT 0.0000 COMMENT '实收金额',
  `discount_amount` decimal(14, 4) NULL DEFAULT 0.0000 COMMENT '折扣金额',
  `payment_date` datetime NULL DEFAULT NULL COMMENT '收款日期',
  `payment_remark` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '收款备注',
  `expected_payment_date` datetime NULL DEFAULT NULL COMMENT '预计收款日期',
  `expected_invoice_date` datetime NULL DEFAULT NULL COMMENT '预计开票日期',
  `firm_id` int(11) NULL DEFAULT NULL COMMENT '接单公司seq',
  `firm_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '接单公司名称',
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `idx`(`bill_no`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 20 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '会计--对账表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for acc_reconciliation_deduction
-- ----------------------------
DROP TABLE IF EXISTS `acc_reconciliation_deduction`;
CREATE TABLE `acc_reconciliation_deduction`  (
  `seq` bigint(11) NOT NULL AUTO_INCREMENT COMMENT '扣款序号',
  `acc_reconciliation_seq` bigint(255) NOT NULL COMMENT '表头seq',
  `parent_bill_no` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '对账单号',
  `deduction_item` varchar(11) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '扣款项目',
  `deduction_amount` decimal(11, 2) NULL DEFAULT NULL COMMENT '扣款金额',
  `is_first` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否先扣款再扣: 0-先扣，1-后扣',
  `remark` varchar(1000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '扣款说明',
  `del_flag` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否删除：0-否,1-是',
  `created_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `update_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `delete_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `delete_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `is_available` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否可用：0-可用,1-不可用',
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `idx1`(`parent_bill_no`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '会计--扣款' ROW_FORMAT = DYNAMIC;

-- ----------------------------
