-- ----------------------------
DROP TABLE IF EXISTS `acc_reconciliation_deduction_attachment`;
CREATE TABLE `acc_reconciliation_deduction_attachment`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `acc_reconciliation_seq` int(11) NULL DEFAULT NULL COMMENT '应付对账表主键',
  `acc_reconciliation_deduction_seq` int(11) NULL DEFAULT NULL COMMENT '应付对账扣款主键',
  `attachment` varchar(2000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '附件',
  `attachment_name` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '附件名称',
  `del_flag` int(1) NULL DEFAULT 0 COMMENT '是否删除(0-否,1-是)',
