CREATE TABLE `acc_reconciliation_detail`  (
  `seq` bigint(11) UNSIGNED ZEROFILL NOT NULL AUTO_INCREMENT COMMENT 'id',
  `acc_reconciliation_seq` int(255) NULL DEFAULT NULL COMMENT '表头seq',
  `parent_bill_no` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '应收款对账单号，父级',
