  `sku` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'sku',
  `customer_id` int(11) NULL DEFAULT NULL COMMENT '客户id',
  `customer_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户编码',
  `customer_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `art_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工厂型体号',
  `art_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工厂型体名称',
  `basic_size_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '尺码（基本码）',
  `art_quarter_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '季度',
  `art_color` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品资料颜色序号',
  `art_color_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品资料颜色名称',
  `warehouse` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '配码收货地址',
  `shipment_quantity` decimal(18, 0) NULL DEFAULT NULL COMMENT '出货数量',
  `shipment_at` datetime NULL DEFAULT NULL COMMENT '出货时间',
  `shipment_code` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '出库单号',
  `delivery_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '送货单号',
  `reconciliation_quantity` decimal(18, 0) NULL DEFAULT NULL COMMENT '对账数量；出货数量',
  `reconciliation_price` decimal(18, 2) NULL DEFAULT NULL COMMENT '对账单价;   客户报价',
  `settlement_quantity` decimal(18, 0) NULL DEFAULT NULL COMMENT '结算数量；页面修改',
  `settlement_price` decimal(18, 2) NULL DEFAULT NULL COMMENT '结算单价；页面修改',
  `settlement_amount` decimal(18, 2) NULL DEFAULT NULL COMMENT '金额； 结算数量*结算单价',
  `del_flag` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否删除：0-否,1-是',
  `created_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `update_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `delete_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `delete_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `is_available` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否可用：0-可用,1-不可用',
