  `developseason` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '季节',
  `remarksbom` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'BOM备注',
  `shoetreeno` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '楦头编号',
  `middletypecode` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '中类',
  `sizerun` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '码段',
  `idslumenlength` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `stylenumber` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '款号',
  `developmentfactory` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工厂名称',
  `colorschemenumber` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '配色数量',
  `send_system` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `developmentplantcode` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工厂',
  `category` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '品类',
  `samplesize` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品码',
  `created_at` datetime NULL DEFAULT NULL COMMENT '同步时间',
  `status` int(1) NULL DEFAULT 0 COMMENT '是否已处理(1为已处理）',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1706 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '安踏bom清单--产品资料基础信息' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for anta_import_record
-- ----------------------------
DROP TABLE IF EXISTS `anta_import_record`;
CREATE TABLE `anta_import_record`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `po` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'po',
  `anta_json` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL,
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `supplier_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商编码',
  `order_date` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '订单创建日期',
  `row_no` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL,
  `status` int(11) NULL DEFAULT 0 COMMENT '订单生产状态(0.未生成  1.已生成)',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 15 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for api_cbd_order_info
-- ----------------------------
DROP TABLE IF EXISTS `api_cbd_order_info`;
CREATE TABLE `api_cbd_order_info`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `unique_id` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '一组BOM的唯一码   CBD版本号',
  `finished_product_factory` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '成品工厂   取CBD抬头-工厂',
  `price_doc_num` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '价格文件编号',
  `item_number` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '成品款/货号  CBD抬头-货号',
  `season` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '季节   CBD抬头-季节',
  `phase` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '阶段  取CBD抬头-阶段为确认样',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `status` int(11) NULL DEFAULT 1 COMMENT '状态（0已删除1未处理2已处理3处理失败）',
  `message` varchar(5000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '失败原因',
  `bomversionnumber` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'bom版本号 ',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3724 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = 'cbd Api接口订单信息表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for api_cbd_order_info_detail
-- ----------------------------
DROP TABLE IF EXISTS `api_cbd_order_info_detail`;
CREATE TABLE `api_cbd_order_info_detail`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `api_cbd_order_info_seq` int(11) NULL DEFAULT NULL COMMENT 'CBD api接口订单信息主表seq',
  `category` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '大类（区域编码）10-鞋面，20-内里，30-补强，40-搭配，50-底部，60-车线胶水，70-包装， 80-工艺， 90-人工管销， 100-其他, 110-利润',
  `component_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位编码  CBD-部位编码',
  `component_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位名称  CBD-部位名称',
  `material_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '材料编码',
  `material_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '材料名称',
  `specification` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '材料规格',
  `thickness` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '厚度',
  `width` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '宽幅',
  `color` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '颜色',
  `usage` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '使用量 小数4位',
  `vendor` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '厂商名称',
  `remark` varchar(2000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `lossrate` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '耗损  小数2位',
  `totaluse` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '毛用量  小数4位',
  `dosageusage` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '用量使用率  小数2位',
  `unitprice` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '材料单价 小数4位',
  `materialamount` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '金额  小数4位',
  `unitfee` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '运费单价 小数4位',
  `materfee` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '材料运费 小数4位',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `message` varchar(5000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '失败原因',
  `status` int(11) NULL DEFAULT 1 COMMENT '状态（0已删除1未处理2已处理3处理失败）',
  `lineno` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '行号',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 235814 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = 'cbd Api接口订单信息明细表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for ar_customer_deduction
-- ----------------------------
DROP TABLE IF EXISTS `ar_customer_deduction`;
CREATE TABLE `ar_customer_deduction`  (
  `seq` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键/序号（自增/雪花ID）',
  `reconciliation_seq` bigint(20) NULL DEFAULT NULL COMMENT '应收款对账单seq',
  `deduction_code` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '应收扣款单号（唯一索引，如YFKK202603110001）',
  `customer_id` bigint(20) NULL DEFAULT NULL COMMENT '客户ID（关联bas_custom.id）',
  `customer_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '客户名称（冗余存储）',
  `deduction_date` date NULL DEFAULT NULL COMMENT '扣款日期（业务发生日期）',
  `total_amount` decimal(18, 2) NOT NULL COMMENT '扣款总金额（明细汇总生成，只读）',
  `status` tinyint(4) NOT NULL COMMENT '单据状态：0-草稿、10-已提交',
  `is_confirm` tinyint(4) NOT NULL DEFAULT 0 COMMENT '是否确认',
  `write_off` tinyint(4) NOT NULL DEFAULT 0 COMMENT '是否核销',
  `is_push_ehr` tinyint(4) NOT NULL DEFAULT 0 COMMENT '是否推送给EHR 0-否 1-是',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '备注',
  `created_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人ID',
  `created_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人姓名',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '修改人ID',
  `updated_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '修改人姓名',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `is_deleted` tinyint(4) NOT NULL DEFAULT 0 COMMENT '是否删除：0-未删除、1-已删除',
  `deleted_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime(3) NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `uk_deduction_code`(`deduction_code`) USING BTREE,
  INDEX `idx_customer_id`(`customer_id`) USING BTREE,
  INDEX `idx_deduction_date`(`deduction_date`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_is_deleted`(`is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '客户扣款单主表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for ar_customer_deduction_item
-- ----------------------------
DROP TABLE IF EXISTS `ar_customer_deduction_item`;
CREATE TABLE `ar_customer_deduction_item`  (
  `seq` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID（自增）',
  `deduction_seq` bigint(20) NOT NULL COMMENT '扣款单主表ID（关联ar_customer_deduction.seq）',
  `deduction_code` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '扣款单号（冗余存储）',
  `deduction_item_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '扣款项目编码（对接数据字典）',
  `deduction_item_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '扣款项目名称（如A品、预付款、延期扣款）',
  `sku` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'SKU',
  `customer_order_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '客人订单号',
  `contract_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '订单合同号',
  `contract_seq` int(11) NULL DEFAULT NULL COMMENT '合同seq',
  `order_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '订单号',
  `po_no` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'PO号',
  `problem_desc` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '问题描述',
  `quantity` int(11) NULL DEFAULT NULL COMMENT '数量（用于计算扣款金额）',
  `deduction_price` decimal(18, 2) NULL DEFAULT NULL COMMENT '扣款单价（保留2位小数）',
  `deduction_amount` decimal(18, 2) NOT NULL COMMENT '扣款金额（数量*单价）',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '备注',
  `created_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人ID',
  `created_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人姓名',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '修改人ID',
  `updated_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '修改人姓名',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `is_deleted` tinyint(4) NOT NULL DEFAULT 0 COMMENT '是否删除：0-未删除、1-已删除',
  `deleted_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime(3) NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `idx_deduction_seq`(`deduction_seq`) USING BTREE,
  INDEX `idx_deduction_code`(`deduction_code`) USING BTREE,
  INDEX `idx_deduction_item_code`(`deduction_item_code`) USING BTREE,
  INDEX `idx_is_deleted`(`is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 32 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '客户扣款单明细表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for ar_po_receive_plan
-- ----------------------------
DROP TABLE IF EXISTS `ar_po_receive_plan`;
CREATE TABLE `ar_po_receive_plan`  (
  `reconciliation_no` varchar(60) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '对账单号',
  `seq` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `acc_reconciliation_detail_seq` bigint(20) NOT NULL COMMENT '对账表明细ID）',
  `acc_reconciliation_seq` int(11) NULL DEFAULT NULL COMMENT '对账单表头seq',
  `po_no` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'PO号',
  `contract_no` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '合同号',
  `contract_order_no` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '合同订单号',
  `contract_total_amount` decimal(12, 2) NULL DEFAULT NULL COMMENT '合同总金额',
  `contract_effective_date` date NULL DEFAULT NULL COMMENT '合同生效日期',
  `shipment_code` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '出库单号',
  `shipment_at` datetime NULL DEFAULT NULL COMMENT '出货时间',
  `customer_id` int(11) NULL DEFAULT NULL COMMENT '客户id',
  `customer_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `period_num` int(11) NOT NULL COMMENT '期数序号（1、2、3...）',
  `period_name` varchar(32) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '款项名称（如：定金、首付、尾款）',
  `invoice_date` date NULL DEFAULT NULL COMMENT '开票日期（账期计算基准，从对账单表头冗余）',
  `due_date` date NOT NULL COMMENT '计划到期日(应收款日期)',
  `last_payment_time` datetime NULL DEFAULT NULL COMMENT '最后收款时间',
  `detail_settlement_amount` decimal(18, 2) NULL DEFAULT NULL COMMENT '对应明细行的结算金额',
  `ratio` decimal(10, 2) NOT NULL COMMENT '结算比例（填写1就是1%，不能超过100）',
  `total_amount` decimal(18, 2) NOT NULL COMMENT '本期应收金额',
  `received_amount` decimal(18, 2) NOT NULL DEFAULT 0.00 COMMENT '本期累计实收金额',
  `balance_amount` decimal(18, 2) NOT NULL COMMENT '待收余额（=total_amount - received_amount）',
  `discount_amount` decimal(18, 2) NOT NULL DEFAULT 0.00 COMMENT '折扣金额',
  `is_overdoes` tinyint(4) NOT NULL DEFAULT 0 COMMENT '是否逾期：0-未逾期、1-已逾期',
  `overdoes_amount` decimal(18, 2) NOT NULL DEFAULT 0.00 COMMENT '逾期金额',
  `status` tinyint(4) NOT NULL COMMENT '状态：10-待收款、20-部分收款、30-已结清、40-已逾期',
  `is_notified` tinyint(4) NOT NULL DEFAULT 0 COMMENT '是否已通知：0-未通知、1-已通知',
  `last_notified_at` datetime NULL DEFAULT NULL COMMENT '最后通知时间',
  `remark` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '备注',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否删除',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人名称',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人名称',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人名称',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `accounting` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收款账期',
  `reconciliation_quantity` decimal(18, 2) NULL DEFAULT NULL COMMENT '对账数量:出货数量',
  `company_id` int(11) NULL DEFAULT NULL COMMENT '公司ID',
  `company_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '接单公司名称',
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `uk_detail_period`(`acc_reconciliation_detail_seq`, `period_num`, `is_deleted`) USING BTREE COMMENT '一行明细的一期仅一条计划',
  INDEX `idx_acc_reconciliation_seq`(`acc_reconciliation_seq`) USING BTREE,
  INDEX `idx_po_no`(`po_no`) USING BTREE,
  INDEX `idx_customer_id`(`customer_id`) USING BTREE,
  INDEX `idx_due_date`(`due_date`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `idx_is_deleted`(`is_deleted`) USING BTREE,
  INDEX `idx_reconciliation_no`(`reconciliation_no`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = 'PO级收款计划表（关联acc_reconciliation_detail）' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for article_price_update_log
-- ----------------------------
DROP TABLE IF EXISTS `article_price_update_log`;
CREATE TABLE `article_price_update_log`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `od_order_doc_article_seq` int(11) NULL DEFAULT NULL COMMENT '订单型体seq',
  `record_type` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '记录类型',
  `record_content` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '记录内容',
  `recorder` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '记录人',
  `record_time` datetime NULL DEFAULT NULL COMMENT '记录时间',
  `original_unit_price` decimal(14, 4) NULL DEFAULT NULL COMMENT '原单价',
  `new_unit_price` decimal(14, 4) NULL DEFAULT NULL COMMENT '新单价',
  `po` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'po',
  `size_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 267 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '单价修改记录表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for bar_code
-- ----------------------------
DROP TABLE IF EXISTS `bar_code`;
CREATE TABLE `bar_code`  (
  `seq` int(11) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'id',
  `sample_order_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品单号',
  `om_article_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '型体单号',
  `bar_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '条形码',
  `is_delete` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '是否删除：0-否,1-是',
  `sample_size` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品size',
  `sample_type` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品类型',
  `created_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `update_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `delete_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `delete_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '产品条码管理' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for bas_company
-- ----------------------------
DROP TABLE IF EXISTS `bas_company`;
CREATE TABLE `bas_company`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `seq` int(11) NULL DEFAULT NULL COMMENT '组织架构ID',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '编号',
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '名称',
  `company_name` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `simple_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '简称',
  `duty_paragraph` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '税号',
  `legal_person` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '法人',
  `register_address` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '注册地址',
  `website` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '网址',
  `fax` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '传真',
  `email` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '邮编',
  `besiness_range` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '经营范围',
  `country_address` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '办公地-国家',
  `province_address` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '办公地-省份',
  `city_address` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '办公地-市',
  `area_address` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '办公地-区/县',
  `detail_address` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '办公地-详细地址',
  `office_address` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '办公地址(不要了)',
  `company_phone` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司电话',
  `logo_image` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'logo图片',
  `set_date` datetime NULL DEFAULT NULL COMMENT '成立日期',
  `organization_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '组织机构代码',
  `business_regist_no` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工商注册号',
  `business_state` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '经营状态',
  `company_type` int(11) NULL DEFAULT NULL COMMENT '企业类型',
  `is_product_unit` int(11) NULL DEFAULT NULL COMMENT '是否生产单位',
  `mes_company_id` varchar(40) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'mes公司id',
  `remark` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '备注',
  `is_delete` int(11) NULL DEFAULT 0 COMMENT '是否删除',
  `enable` int(11) NULL DEFAULT 0 COMMENT '是否可用',
  `deleted_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime(3) NULL DEFAULT NULL COMMENT '删除时间',
  `created_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `updated_at` datetime(3) NULL DEFAULT NULL COMMENT '更新时间',
  `nice_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `start_date` int(11) NULL DEFAULT NULL COMMENT '开始日',
  `start_date_product` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '开始日项',
  `end_date` int(11) NULL DEFAULT NULL COMMENT '结束日',
  `end_date_product` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '结束日项',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_bas_company_mes_company_id`(`mes_company_id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '公司基础信息' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for bas_company_attachment
-- ----------------------------
DROP TABLE IF EXISTS `bas_company_attachment`;
CREATE TABLE `bas_company_attachment`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `company_id` int(11) NULL DEFAULT NULL COMMENT '公司ID',
  `loc_path` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '路径',
  `old_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '旧文件名',
  `url` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '文件路径',
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '新文件名',
  `is_delete` int(11) NULL DEFAULT 0 COMMENT '是否删除',
  `enable` int(11) NULL DEFAULT 0 COMMENT '是否可用',
  `deleted_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime(3) NULL DEFAULT NULL COMMENT '删除时间',
  `created_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `updated_at` datetime(3) NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '公司信息附件' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for bas_company_bank
-- ----------------------------
DROP TABLE IF EXISTS `bas_company_bank`;
CREATE TABLE `bas_company_bank`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键自增列',
  `company_id` int(11) NULL DEFAULT NULL COMMENT '公司id',
  `bank_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '银行名称',
  `open_bank` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '开户行',
  `bank_card_no` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '银行账号',
  `united_bank_no` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '联行号',
  `remark` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `is_delete` int(11) NULL DEFAULT 0 COMMENT '是否删除',
  `enable` int(11) NULL DEFAULT 0 COMMENT '是否可用',
  `deleted_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_at` datetime(3) NULL DEFAULT NULL COMMENT '创建时间',
  `created_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `updated_at` datetime(3) NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '公司银行账号' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for bas_company_bu_mapping
-- ----------------------------
DROP TABLE IF EXISTS `bas_company_bu_mapping`;
CREATE TABLE `bas_company_bu_mapping`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `company_seq` int(11) NULL DEFAULT NULL COMMENT '公司表 seq',
  `company_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '公司编码',
  `company_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '公司名称',
  `bu_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '业务单元编码（如 BU-00010）',
  `bu_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '业务单元名称',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `updated_by` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `updated_name` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `is_deleted` tinyint(4) NULL DEFAULT 0 COMMENT '是否删除 0=否 1=是',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '公司与业务单元对照表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for bas_company_contact
-- ----------------------------
DROP TABLE IF EXISTS `bas_company_contact`;
CREATE TABLE `bas_company_contact`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `company_id` int(11) NULL DEFAULT NULL COMMENT '公司id',
  `type` int(11) NULL DEFAULT NULL COMMENT '联系人类型（从字典表获取）',
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '姓名',
  `sex` int(11) NULL DEFAULT NULL COMMENT '性别',
  `department` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部门',
  `post` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '职务',
  `mobile_phone` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '移动电话',
  `fixed_phone` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '固定电话',
  `email` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '邮箱',
  `receipt_address_abb` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收货地简称',
  `receipt_address` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收货地址详细地址',
  `remark` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `is_delete` int(11) NULL DEFAULT 0 COMMENT '是否删除',
  `enable` int(11) NULL DEFAULT 0 COMMENT '是否可用',
  `deleted_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_at` datetime(3) NULL DEFAULT NULL COMMENT '创建时间',
  `created_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `updated_at` datetime(3) NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `company_id`(`company_id`) USING BTREE,
  INDEX `idx_address`(`receipt_address`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 7 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '公司联系人信息' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for bas_company_warehouse
-- ----------------------------
DROP TABLE IF EXISTS `bas_company_warehouse`;
CREATE TABLE `bas_company_warehouse`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `company_id` int(11) NULL DEFAULT NULL COMMENT '公司ID',
  `level` int(11) NULL DEFAULT NULL COMMENT '层级',
  `serial_no` int(11) NULL DEFAULT NULL COMMENT '同层级顺序号',
  `parent_id` int(11) NULL DEFAULT NULL COMMENT '父级id',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '编号',
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '名称',
  `path_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '路径全称',
  `warehouse_type_id` int(11) NULL DEFAULT NULL COMMENT '仓库类型id',
  `warehouse_type_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库类型名称',
  `charge_person_id` int(11) NULL DEFAULT NULL COMMENT '负责人id',
  `charge_person_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '负责人名称',
  `remark` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `is_lock_up` int(1) NULL DEFAULT 0 COMMENT '锁仓状态',
  `is_delete` int(11) NULL DEFAULT 0 COMMENT '是否删除',
  `enable` int(11) NULL DEFAULT 0 COMMENT '是否可用',
  `deleted_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_at` datetime(3) NULL DEFAULT NULL COMMENT '创建时间',
  `created_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `updated_at` datetime(3) NULL DEFAULT NULL COMMENT '更新时间',
  `node_type_name` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '节点类型名称',
  `location_type_id` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '储位类型ID',
  `location_type_name` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '储位类型名称',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `code`(`code`, `name`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1683 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '公司仓库' ROW_FORMAT = Dynamic;

