-- ----------------------------
-- Table structure for bas_custom
-- ----------------------------
DROP TABLE IF EXISTS `bas_custom`;
CREATE TABLE `bas_custom`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '编号',
  `category` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '简码',
