-- ----------------------------
-- Table structure for bas_order_forecast
-- ----------------------------
DROP TABLE IF EXISTS `bas_order_forecast`;
CREATE TABLE `bas_order_forecast`  (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `customer_id` int(11) NOT NULL COMMENT '客户id',
  `customer_brand_id` int(11) NOT NULL COMMENT '客户品牌（如耐克/阿迪）id',
  `receive_company_id` int(11) NOT NULL COMMENT '接单公司（如广州分厂/泉州分厂）id',
  `year_month` varchar(7) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '年月（格式YYYY-MM，如2026-03）',
  `year_num` int(11) NOT NULL COMMENT '年份（如2026）',
  `month_num` tinyint(4) NOT NULL COMMENT '月份（1-12）',
  `category` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '类别：预计接单/预计出货/预计出款/实际完成',
  `quantity` int(11) NULL DEFAULT 0 COMMENT '数量（仅预计接单/出货填值）',
  `amount` decimal(16, 2) NULL DEFAULT 0.00 COMMENT '金额（仅预计出款/实际完成填值）',
  `remark` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `is_delete` int(11) NULL DEFAULT 0 COMMENT '是否删除',
  `deleted_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `deleted_at` datetime(3) NULL DEFAULT NULL COMMENT '创建时间',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime(3) NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `updated_at` datetime(3) NULL DEFAULT NULL COMMENT '更新时间',
  `created_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `updated_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `idx_seq`(`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = 'ERP预计订单计划表' ROW_FORMAT = Dynamic;

