-- ----------------------------
-- Table structure for batch_list
-- ----------------------------
DROP TABLE IF EXISTS `batch_list`;
CREATE TABLE `batch_list`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `batch_seq` int(11) NULL DEFAULT NULL COMMENT '入库表seq',
  `material_seq` int(11) NULL DEFAULT NULL COMMENT '采购计划详情seq',
  `is_store` int(1) NULL DEFAULT NULL COMMENT '库存材料',
