-- ----------------------------
-- Table structure for bill_seq
-- ----------------------------
DROP TABLE IF EXISTS `bill_seq`;
CREATE TABLE `bill_seq`  (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `prefix` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `last_seq` int(11) NOT NULL,
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_by` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_at` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `idx`(`prefix`, `last_seq`) USING BTREE,
  INDEX `u_idx`(`prefix`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3046 CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for bill_setting
-- ----------------------------
DROP TABLE IF EXISTS `bill_setting`;
CREATE TABLE `bill_setting`  (
  `id` int(36) NOT NULL AUTO_INCREMENT,
  `bill_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '单据类型',
  `prefix` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '单据标识',
  `year` varchar(4) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '年份',
  `month` varchar(2) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '月份',
  `day` varchar(2) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '日',
  `serial_number` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单据流水码段断',
  `is_cost` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '是否和成本计算有关，0无关系；1有关系',
  `is_price` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '0有单价，1无单价；\r\n1）当成本为1的时候， 值为0或1 ；\r\n2）与成本无关, 本项不可用，默认是null',
  `is_check_accounts` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '是否参与对账',
  `is_inventory` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '是否与库存有关',
  `is_approve` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '是否审批',
  `created_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_at` datetime NULL DEFAULT NULL,
  `updated_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_at` datetime NULL DEFAULT NULL,
  `is_delete` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否删除，默认0不删除；1删除',
  `deleted_at` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_by` datetime NULL DEFAULT NULL,
  `created_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `pIdx`(`prefix`) USING BTREE COMMENT '单据前缀唯一',
  UNIQUE INDEX `nameIdx`(`bill_name`) USING BTREE COMMENT '单据名称唯一'
) ENGINE = InnoDB AUTO_INCREMENT = 78 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '单据配置表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for business_file
-- ----------------------------
DROP TABLE IF EXISTS `business_file`;
CREATE TABLE `business_file`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `business_seq` int(11) NULL DEFAULT NULL COMMENT '业务seq\r\n例如：附件属于型体，business_seq=所属型体seq',
  `file_seq` int(11) NULL DEFAULT NULL COMMENT '附件seq',
  `type` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '文件类型\r\n1：图片；\r\n2：文件；\r\n3：SKU(PDF)；\r\n4：logo',
  `business_type` varchar(2) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '业务类型（10：型体,20：系统应用,30:材料暂收附件;40:应付对账单）',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `business_seq_type_business_type`(`business_seq`, `business_type`, `type`) USING BTREE,
  INDEX `business_seq`(`business_seq`, `business_type`) USING BTREE,
  INDEX `business_seq_2`(`business_seq`, `type`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 33123 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '附件业务对应表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for business_flowable
-- ----------------------------
DROP TABLE IF EXISTS `business_flowable`;
CREATE TABLE `business_flowable`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `business_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '业务类型',
  `business_seq` int(11) NULL DEFAULT NULL COMMENT '业务序号',
  `flow_key` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '流程标识',
  `deployment_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '流程编号',
  `proc_def_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '流程Id',
  `proc_ins_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '流程实例Id',
  `deploy_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '同流程编号',
  `task_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '流程实例Id',
  `run_task_id` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '运行中的流程实例Id',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 15360 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '业务流程关联关系表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for cdjtkjl
-- ----------------------------
DROP TABLE IF EXISTS `cdjtkjl`;
CREATE TABLE `cdjtkjl`  (
  `DAYS` varchar(500) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL,
  `WKJ` bigint(20) NULL DEFAULT NULL,
  `KJ` bigint(20) NULL DEFAULT NULL,
  `KJL` decimal(20, 0) NULL DEFAULT NULL COMMENT 'kjl'
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for chat_messages
-- ----------------------------
DROP TABLE IF EXISTS `chat_messages`;
CREATE TABLE `chat_messages`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '娑堟伅ID',
  `session_id` varchar(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '浼氳瘽ID',
  `role` enum('user','ai','system') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '瑙掕壊',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '娑堟伅鍐呭?',
  `message_metadata` json NULL COMMENT '鍏冩暟鎹?(thoughts, sql_query, chart_data绛?',
  `feedback` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '鐢ㄦ埛鍙嶉? (like/dislike)',
  `feedback_text` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '鍙嶉?璇︽儏',
  `created_at` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3) COMMENT '鍒涘缓鏃堕棿',
  `updated_at` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3) COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_session_id_created_at`(`session_id`, `created_at`) USING BTREE,
  CONSTRAINT `chat_messages_ibfk_1` FOREIGN KEY (`session_id`) REFERENCES `chat_sessions` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 29 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '鑱婂ぉ娑堟伅琛' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for chat_sessions
-- ----------------------------
DROP TABLE IF EXISTS `chat_sessions`;
CREATE TABLE `chat_sessions`  (
  `id` varchar(36) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '浼氳瘽ID (UUID)',
  `user_id` bigint(20) NOT NULL COMMENT '鐢ㄦ埛ID',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '浼氳瘽鏍囬?',
  `created_at` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3) COMMENT '鍒涘缓鏃堕棿',
  `updated_at` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3) COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id`) USING BTREE,
  CONSTRAINT `chat_sessions_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '鑱婂ぉ浼氳瘽琛' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for contract_advance_payment
-- ----------------------------
DROP TABLE IF EXISTS `contract_advance_payment`;
CREATE TABLE `contract_advance_payment`  (
  `seq` bigint(18) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT 'seq',
  `bill_no` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '应收款对账单号',
  `customer_id` int(11) NULL DEFAULT NULL COMMENT '客户id',
  `customer_code` varchar(11) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户编号',
  `customer_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `transaction_amount` decimal(18, 4) NULL DEFAULT NULL COMMENT '成交金额',
  `receivable_amount` decimal(18, 4) NULL DEFAULT 0.0000 COMMENT '应收金额',
  `currency_type` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '币种',
  `payment_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '付款方式',
  `inventory_code` varchar(125) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '出库单号',
  `accounting` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '取年月日2025-04-01，计算的是4月',
  `bank_card_no` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司银行账号/来源 bas_company_bank',
  `remark` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `status` varchar(3) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '状态(0草稿，1待审校，2已审核待上传发票，3，已完成）',
  `is_available` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否可用：0可用，1不可用',
  `del_flag` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否删除：0-否,1-是',
  `created_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `update_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `delete_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `delete_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `created_by_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人姓名',
  `invoice_date` datetime NULL DEFAULT NULL COMMENT '开票日期',
  `invoice_file_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '发票附件名',
  `invoice_path` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '发票地址',
  `payment_identifier` int(11) NULL DEFAULT 0 COMMENT '收款标识',
  `amount_received` decimal(14, 4) NULL DEFAULT 0.0000 COMMENT '实收金额',
  `discount_amount` decimal(14, 4) NULL DEFAULT 0.0000 COMMENT '折扣金额',
  `payment_date` datetime NULL DEFAULT NULL COMMENT '收款日期',
  `payment_remark` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '收款备注',
  `expected_payment_date` datetime NULL DEFAULT NULL COMMENT '预计收款日期',
  `expected_invoice_date` datetime NULL DEFAULT NULL COMMENT '预计开票日期',
  `firm_id` int(11) NULL DEFAULT NULL COMMENT '接单公司seq',
  `firm_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '接单公司名称',
  `contract_amount` decimal(18, 4) NULL DEFAULT NULL COMMENT '合同金额',
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `idx`(`bill_no`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '合同预付款' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for contract_advance_payment_detail
-- ----------------------------
DROP TABLE IF EXISTS `contract_advance_payment_detail`;
CREATE TABLE `contract_advance_payment_detail`  (
  `seq` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `contract_advance_payment_seq` bigint(20) NULL DEFAULT NULL COMMENT '主表seq',
  `contract_seq` bigint(20) NULL DEFAULT NULL COMMENT '来源单据ID (关联 po_order_contract.seq)',
  `contract_item_seq` bigint(20) NULL DEFAULT NULL COMMENT '来源单据明细seq(关联 po_order_item.seq)',
  `contract_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '订单合同号 (方便快速查询)',
  `company_seq` bigint(20) NULL DEFAULT NULL COMMENT '接单公司ID',
  `company_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '接单公司名称',
  `customer_seq` bigint(20) NULL DEFAULT NULL COMMENT '客户ID',
  `customer_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '客户名称 (冗余字段，加快列表展示)',
  `sku` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `row_no` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'po',
  `quantity` decimal(14, 4) NOT NULL DEFAULT 0.0000 COMMENT '数量 (* 必填)',
  `unit_price` decimal(14, 4) NOT NULL DEFAULT 0.0000 COMMENT '单价(含税)',
  `tax_unit_price` decimal(14, 4) NOT NULL DEFAULT 0.0000 COMMENT '单价(不含税)',
  `deposit_ratio` decimal(14, 4) NOT NULL DEFAULT 0.0000 COMMENT '定金比例',
  `po_amount` decimal(14, 4) NOT NULL DEFAULT 0.0000 COMMENT 'PO金额',
  `deposit_amount` decimal(14, 4) NOT NULL DEFAULT 0.0000 COMMENT '定金金额',
  `payment_status` int(2) NOT NULL DEFAULT 0 COMMENT '收款状态: 0-待收款(未收), 1-部分收款, 2-已齐款(结案)',
  `created_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人 (通常为系统或提交合同的业务员)',
  `created_by_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人姓名',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间 (单据流入财务待处理的时间)',
  `update_at` datetime NULL DEFAULT NULL COMMENT '最新一次收款/更新的时间',
  `delete_at` datetime NULL DEFAULT NULL,
  `update_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `delete_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `status` int(2) NOT NULL DEFAULT 0 COMMENT '处理状态(0未处理，1已处理）',
  `actual_amount` decimal(14, 4) NULL DEFAULT NULL COMMENT '实收金额',
  `actual_discount_amount` decimal(14, 4) NULL DEFAULT NULL COMMENT '实收折扣金额',
  `actual_at` datetime NULL DEFAULT NULL COMMENT '实收时间',
  `del_flag` int(2) NOT NULL DEFAULT 0,
  `brand` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '品牌',
  `product_category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '产品类别',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `idx_contract_no`(`contract_no`) USING BTREE,
  INDEX `idx_payment_status`(`payment_status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 6 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '预收款明细' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for contract_advance_payment_record
-- ----------------------------
DROP TABLE IF EXISTS `contract_advance_payment_record`;
CREATE TABLE `contract_advance_payment_record`  (
  `seq` bigint(11) NOT NULL AUTO_INCREMENT COMMENT '扣款序号',
  `contract_advance_payment_seq` bigint(20) NOT NULL COMMENT '订单合同预收款seq',
  `payment_date` datetime NULL DEFAULT NULL COMMENT '收款日期',
  `amount_received` decimal(14, 4) NULL DEFAULT NULL COMMENT '收款金额',
  `discount_amount` decimal(14, 4) NULL DEFAULT NULL COMMENT '折扣金额',
  `remark` varchar(1000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `created_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_by_name` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人名称',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `contract_advance_payment_seq`(`contract_advance_payment_seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 4 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '收款登记' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for custom_payment_method
-- ----------------------------
DROP TABLE IF EXISTS `custom_payment_method`;
CREATE TABLE `custom_payment_method`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `bas_custom_seq` int(11) NULL DEFAULT NULL COMMENT '客户ID',
  `pay_stage` int(11) NOT NULL COMMENT '结算阶段（填写，1,2,3....）',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '结算项目标识（从字典表dict_data中获取）',
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '结算项目',
  `ratio` decimal(10, 2) NOT NULL COMMENT '结算比例（填写1就是1%，不能超过100）',
  `source_table` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '来源表',
  `source_table_field` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '来源表字段',
  `plan_pay_cycle` int(11) NOT NULL COMMENT '计划结算周期 (单位天)',
  `plan_invoicing_cycle` int(11) NULL DEFAULT NULL COMMENT '预计开票周期(单位天)',
  `remark` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `status` int(11) NOT NULL DEFAULT 0 COMMENT '状态（0正常 1停用）',
  `is_delete` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否删除',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人名称',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人名称',
  `updated_at` datetime NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人名称',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 32 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '客户结算方式' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for customer
-- ----------------------------
DROP TABLE IF EXISTS `customer`;
CREATE TABLE `customer`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '代号',
  `type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '类型\r\n从常用类别获取客户类型',
  `abb` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '简称',
  `name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '名称',
  `delivery_method` char(6) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '送货方式：获取基础数据sys_dict字典表code信息',
  `payment_method` char(6) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '付款方式：获取基础数据sys_dict字典表code信息',
  `en_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '英文名称',
  `is_deleted` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否删除',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` varchar(225) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '客户' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for customer_info
-- ----------------------------
DROP TABLE IF EXISTS `customer_info`;
CREATE TABLE `customer_info`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `customer_seq` int(11) NULL DEFAULT NULL COMMENT '客户序号',
  `fax_no` int(11) NULL DEFAULT NULL COMMENT '传真号',
  `phone1` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '联系方式1',
  `phone2` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '联系方式2',
  `contact` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '联系人',
  `postal_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '邮编',
  `business_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '业务员',
  `addr` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '地址',
  `en_address` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '英文地址',
  `head` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '负责人',
  `phone3` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报关电话',
  `fax2` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报关传真',
  `certificate_sno` varchar(18) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '税号',
  `customs_seq` int(11) NULL DEFAULT NULL COMMENT '主管海关',
  `administer_customs_seq` int(11) NULL DEFAULT NULL COMMENT '管辖海关',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `customer_seq`(`customer_seq`) USING BTREE,
  CONSTRAINT `customer_info_ibfk_1` FOREIGN KEY (`customer_seq`) REFERENCES `customer` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '客户详情' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for customer_order_main
-- ----------------------------
DROP TABLE IF EXISTS `customer_order_main`;
CREATE TABLE `customer_order_main`  (
  `seq` int(11) NOT NULL,
  `firm_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工厂名称',
  `customer_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `brand_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '品牌名称',
  `cj_time` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '导单时间',
  `season` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '季节',
  `customer_order` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客人订单号',
  `account_number` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '订货款号',
  `item_number` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客人型体号',
  `erp_guide_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'ERP导单号',
  `po` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'po',
  `production_directives` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '合并指令号',
  `production_date` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '生产日期',
  `color_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '颜色',
  `order_count` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '订单总数',
  `order_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '订单类型',
  `delivery_address` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收货地',
  `order_stats` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '订单属性',
  `taking_date` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '接单日期',
  `delivery_time` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '订单交期',
  `sign_time` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '签字交期',
  `outsole_mold` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '大底编号',
  `last_number` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '楦头编号',
  `size_segment` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '码段',
  `xg_time` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改时间',
  `yesterday_in_stock_num_by_cx` double(11, 2) NULL DEFAULT NULL COMMENT '/成型昨日累计入库数量',
  `actual_out_date` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '出货时间',
  `time_min_by_cx` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '成型实际上线时间',
  `totalIn_stock_num_by_cx` double(255, 0) NULL DEFAULT NULL COMMENT '成型累计入库数量',
  `todayIn_stock_num_by_cx` double(255, 0) NULL DEFAULT NULL COMMENT '成型当天入库数量',
  `time_max_by_zc` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '针车实际完成时间',
  `group_name_by_zc` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '针车组别',
  `time_min_by_zc` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '针车实际上线时间',
  `group_name_by_cx` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '/成型组别',
  `await_out_num` double(11, 2) NULL DEFAULT NULL COMMENT '待出货数量',
  `plan_out_num` double(11, 2) NULL DEFAULT NULL COMMENT '计划出货数量',
  `yesterday_in_stock_num_by_zc` double(11, 2) NULL DEFAULT NULL COMMENT '针车昨日累计入库数量',
  `time_max_by_cx` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '成型实际完成时间',
  `totalIn_stock_num_by_zc` double(11, 2) NULL DEFAULT NULL COMMENT '针车累计入库数量',
  `plan_out_date` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '计划出货日期',
  `today_in_stock_num_by_zc` double(11, 2) NULL DEFAULT NULL COMMENT '针车当天入库数量',
  `total_out_num` double(11, 2) NULL DEFAULT NULL COMMENT '出货数量',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `po`(`po`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '客户订单信息' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for db_connections
-- ----------------------------
DROP TABLE IF EXISTS `db_connections`;
CREATE TABLE `db_connections`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '杩炴帴ID',
  `user_id` bigint(20) NOT NULL COMMENT '鐢ㄦ埛ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '杩炴帴鍚嶇О',
  `type` enum('mysql','postgresql','mssql','clickhouse','sqlite','oracle','other') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '鏁版嵁搴撶被鍨',
  `host` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '涓绘満鍦板潃',
  `port` int(11) NOT NULL COMMENT '绔?彛鍙',
  `username` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '鏁版嵁搴撶敤鎴峰悕',
  `encrypted_password` varbinary(512) NOT NULL COMMENT '鍔犲瘑鍚庣殑鏁版嵁搴撳瘑鐮',
  `database_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '鏁版嵁搴撳悕',
  `created_at` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3) COMMENT '鍒涘缓鏃堕棿',
  `updated_at` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3) COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_id_name`(`user_id`, `name`) USING BTREE COMMENT '鍚屼竴鐢ㄦ埛涓嬬殑杩炴帴鍚嶇О搴斿敮涓',
  CONSTRAINT `db_connections_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '鏁版嵁搴撹繛鎺ラ厤缃?〃' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for demo_mail_schedule
-- ----------------------------
DROP TABLE IF EXISTS `demo_mail_schedule`;
CREATE TABLE `demo_mail_schedule`  (
  `ID` varchar(36) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `RECEIVERS` varchar(512) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `PATH` varchar(512) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `NAME` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `FORMAT` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `ENABLED` varchar(2) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `DELETED` varchar(2) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `COMPRESSED` varchar(2) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `MAIL_BODY` varchar(512) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `CREATER` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `CREATE_TIME` datetime NULL DEFAULT NULL,
  `LASTER` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `LASTUPDATE_TIME` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`ID`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '邮箱发送' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for depm_prog
-- ----------------------------
DROP TABLE IF EXISTS `depm_prog`;
CREATE TABLE `depm_prog`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `sample_order_seq` int(11) NULL DEFAULT NULL COMMENT '样品单序号',
  `customer_seq` int(11) NULL DEFAULT NULL COMMENT '客户序号',
  `speed` varchar(24) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '速度',
  `is_materials` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '1' COMMENT '是否备料完成',
  `materials_status` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备料情况',
  `is_scheduling` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '1' COMMENT '是否排产',
  `prod_quantity` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '生产数量',
  `prod_date` timestamp NULL DEFAULT NULL COMMENT '生产安排日期',
  `director` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '负责人',
  `is_delete` int(1) NULL DEFAULT 0 COMMENT '是否删除 0:未删除 1：删除',
  `created_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '创建时间',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建时间',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `sample_order_seq`(`sample_order_seq`) USING BTREE,
  INDEX `customer_seq`(`customer_seq`) USING BTREE,
  CONSTRAINT `depm_prog_ibfk_1` FOREIGN KEY (`sample_order_seq`) REFERENCES `sample_order` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `depm_prog_ibfk_2` FOREIGN KEY (`customer_seq`) REFERENCES `customer` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '样品开发进度' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for depm_prog_properties
-- ----------------------------
DROP TABLE IF EXISTS `depm_prog_properties`;
CREATE TABLE `depm_prog_properties`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `depm_prog_seq` int(11) NULL DEFAULT NULL COMMENT '产品开发进度表序号',
  `type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '类型',
  `key` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '类型key',
  `value` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '类型value',
  `is_delete` int(1) NULL DEFAULT 0 COMMENT '未删除：0  删除：1',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `depm_prog_seq`(`depm_prog_seq`) USING BTREE,
  CONSTRAINT `depm_prog_properties_ibfk_1` FOREIGN KEY (`depm_prog_seq`) REFERENCES `depm_prog` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '产品开发进度拓展表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for dict_data
-- ----------------------------
DROP TABLE IF EXISTS `dict_data`;
CREATE TABLE `dict_data`  (
  `dict_code` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '字典编码',
  `dict_sort` int(11) NULL DEFAULT 0 COMMENT '字典排序',
  `dict_label` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '字典标签',
  `dict_value` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '字典键值',
  `dict_type` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '字典类型',
  `css_class` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样式属性（其他样式扩展）',
  `list_class` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '表格回显样式',
  `is_default` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT 'N' COMMENT '是否默认（Y是 N否）',
  `status` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '状态（0正常 1停用）',
  `create_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`dict_code`) USING BTREE,
  INDEX `idx_dict_type_code`(`dict_type`, `dict_code`, `dict_value`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 609 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '字典数据表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for dict_type
-- ----------------------------
DROP TABLE IF EXISTS `dict_type`;
CREATE TABLE `dict_type`  (
  `dict_id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '字典主键',
  `dict_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '字典名称',
  `dict_type` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '字典类型',
  `status` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '状态（0正常 1停用）',
  `create_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '创建者',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '' COMMENT '更新者',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `remark` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `created_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`dict_id`) USING BTREE,
  UNIQUE INDEX `dict_type`(`dict_type`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 48 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '字典类型表' ROW_FORMAT = Dynamic;

-- ----------------------------
