-- ----------------------------
-- Table structure for email_sending_record
-- ----------------------------
DROP TABLE IF EXISTS `email_sending_record`;
CREATE TABLE `email_sending_record`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
