  `context` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '邮件内容',
  `recipient` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '收件人用逗号隔开',
