  `download_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '下载人名称',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1645 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '附件明细' ROW_FORMAT = DYNAMIC;

