) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_bin ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for formwork
-- ----------------------------
DROP TABLE IF EXISTS `formwork`;
CREATE TABLE `formwork`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `code` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '模板代号',
  `template` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '模板说明',
  `matter` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料类别',
  `material` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料状态',
  `level` int(1) NULL DEFAULT NULL COMMENT '危险等级',
  `supervisory` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '超收控制',
  `storehouse` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库类',
  `raw` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '原料科目',
  `process` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '在制科目',
  `safety_stock` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '安全库存',
  `max_stock` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '最大库存',
  `neg_stock` int(1) NULL DEFAULT 0 COMMENT '是否负库存 0:否 1：是',
  `warehouse_no` int(22) NULL DEFAULT NULL COMMENT '仓库',
  `place` int(22) NULL DEFAULT NULL COMMENT '储位',
  `delivery` int(1) NULL DEFAULT 0 COMMENT '允许快速收货 0:否 1：是\'',
  `delivery_po` int(1) NULL DEFAULT 0 COMMENT '允许无po出货 0:否 1：是\'',
  `materials` int(1) NULL DEFAULT 0 COMMENT '是否购买料 0:否 1：是\'',
  `quoted` int(1) NULL DEFAULT 0 COMMENT '是否报价请求 0:否 1：是\'',
  `requisition` int(1) NULL DEFAULT 0 COMMENT '是否先请购 0:否 1：是\'',
  `purchases` int(1) NULL DEFAULT 0 COMMENT '采购用量控制 0:否 1：是\'',
  `ectocyst` int(1) NULL DEFAULT 0 COMMENT '是否外包料 0:否 1：是\'',
  `business` int(1) NULL DEFAULT 0 COMMENT '是否交易 0:否 1：是\'',
  `max_purchases` int(1) NULL DEFAULT 0 COMMENT '最大采购量 0:否 1：是\'',
  `safe` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购安全期',
  `create_date` date NULL DEFAULT NULL COMMENT '创建时间',
  `create_by` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `update_date` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '更新时间',
  `update_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '更新人',
  `is_delete` int(1) NULL DEFAULT 0 COMMENT '是否删除 0：否 1：是',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '物料模板' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for group_dispatch_order
-- ----------------------------
DROP TABLE IF EXISTS `group_dispatch_order`;
CREATE TABLE `group_dispatch_order`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
