  `material_info_colour` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码颜色编码',
  `mx_material_category_unit_seq` int(11) NULL DEFAULT NULL COMMENT '物料单位seq',
  `mx_material_category_unit_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料单位名称',
