-- ----------------------------
-- Table structure for knife
-- ----------------------------
DROP TABLE IF EXISTS `knife`;
CREATE TABLE `knife`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `code` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '斩刀代号',
  `part_no` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位编号',
