-- ----------------------------
-- Table structure for llm_configs
-- ----------------------------
DROP TABLE IF EXISTS `llm_configs`;
CREATE TABLE `llm_configs`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '閰嶇疆ID',
  `user_id` bigint(20) NOT NULL COMMENT '鐢ㄦ埛ID',
  `provider` enum('openai','qwen','deepseek','anthropic','moonshot','ollama','gemini','other') CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'LLM鎻愪緵鍟',
  `model_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '妯″瀷鍚嶇О',
  `encrypted_api_key` varbinary(1024) NOT NULL COMMENT '鍔犲瘑鍚庣殑API瀵嗛挜',
  `base_url` varchar(512) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '鑷?畾涔堿PI绔?偣',
  `temperature` float NULL DEFAULT NULL COMMENT '娓╁害鍙傛暟',
  `created_at` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3) COMMENT '鍒涘缓鏃堕棿',
  `updated_at` datetime(3) NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3) COMMENT '鏇存柊鏃堕棿',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id_provider`(`user_id`, `provider`) USING BTREE COMMENT '蹇??鏌ユ壘鐢ㄦ埛鐨凩LM閰嶇疆',
  CONSTRAINT `llm_configs_ibfk_1` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 2 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = 'LLM閰嶇疆琛' ROW_FORMAT = Dynamic;

