-- ----------------------------
-- Table structure for mat_customer_material
-- ----------------------------
DROP TABLE IF EXISTS `mat_customer_material`;
CREATE TABLE `mat_customer_material`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键seq',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '季度序号',
  `order_quarter_code` int(11) NULL DEFAULT NULL COMMENT '下单季度',
  `quarter_name` varchar(40) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '季度名称',
  `article_seq_list` varchar(1000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品seq列表',
  `customer_seq` int(11) NOT NULL COMMENT '客户信息seq',
  `material_info_seq` int(11) NULL DEFAULT NULL COMMENT '物料信息seq',
  `material_info_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码',
  `material_info_colour` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码颜色编码',
  `material_info_colour_name` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `material_info_size` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料尺码size',
  `material_category_seq` int(11) NULL DEFAULT NULL COMMENT '物料简码序号',
  `material_category_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料简码编号',
  `material_category_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '简码名称',
  `provider_seq` int(11) NULL DEFAULT NULL COMMENT '默认供应商id',
  `provider_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '默认供应商名称',
  `purchase_unit_seq` int(11) NULL DEFAULT NULL COMMENT '采购单位id',
  `purchase_unit_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购单位名称',
  `article_sku_list` varchar(1000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品sku列表',
  `is_inquiry` int(11) NOT NULL DEFAULT 0 COMMENT '是否询价 1询价  0未询价',
  `created_time` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `source` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '产品资料' COMMENT '来源',
  `order_time` datetime NULL DEFAULT NULL COMMENT '下单时间',
  `update_time` datetime NULL DEFAULT NULL,
  `update_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `idx_seq`(`seq`) USING BTREE,
  INDEX `idex_1`(`provider_seq`, `customer_seq`, `material_info_seq`, `quarter_code`) USING BTREE,
  INDEX `idex_2`(`provider_seq`, `customer_seq`, `material_info_code`, `quarter_code`, `order_quarter_code`) USING BTREE,
  INDEX `idx_source_seq`(`is_inquiry`, `source`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 109482 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '客户物料关联关系表' ROW_FORMAT = Dynamic;

