-- Table structure for mat_price_inquiry
-- ----------------------------
DROP TABLE IF EXISTS `mat_price_inquiry`;
CREATE TABLE `mat_price_inquiry`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
