-- ----------------------------
-- Table structure for mat_price_inquiry_copy1
-- ----------------------------
DROP TABLE IF EXISTS `mat_price_inquiry_copy1`;
CREATE TABLE `mat_price_inquiry_copy1`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `code` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '询价单号',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '季度序号',
  `inquiry_person_num` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '询价人账号',
  `inquiry_person` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '询价人',
  `inquiry_dept_id` int(11) NULL DEFAULT NULL COMMENT '询价部门id',
  `inquiry_dept_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '询价部门名称',
  `inquiry_status` varchar(5) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '询价单状态：51-草稿,10-提交,20-待审批,21-审批中,22-转办,23-委派,24-抄送,25-退回,26-驳回,1-撤回,50-完成，52 询价中，53 询价完成',
  `quote_status` varchar(5) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价单状态：0-草稿,1-提交,2-待审批3-审批中,4-转办,5-委派,6-抄送,7-退回,8-驳回,9-撤回,10-完成,11-供应商报价中,12-供应商完成',
  `remark` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `is_def_supplier` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '是否带入默认供应商:0-否,1-是',
  `is_deleted` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否删除:0-否,1-是',
  `enable` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '1' COMMENT '是否有效:0-否,1-是',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `status` int(255) NULL DEFAULT NULL COMMENT '状态',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 100 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '物料询价单' ROW_FORMAT = Dynamic;

