  `internal_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商内部物料编码',
  `internal_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商内部物料名称',
  `effective_date_begin` date NULL DEFAULT NULL COMMENT '生效起',
  `effective_date_end` date NULL DEFAULT NULL COMMENT '生效止',
