  `estimated_unit_price` decimal(12, 4) NULL DEFAULT NULL COMMENT '预估单价',
  `bulk_unit_price` decimal(12, 4) NULL DEFAULT NULL COMMENT '大货单价',
  `min_quantity` int(11) NULL DEFAULT NULL COMMENT '最小采购量',
  `min_quantity_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '最小采购量单价',
  `max_quantity` int(11) NULL DEFAULT NULL COMMENT '最大采购量',
  `max_quantity_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '最大采购量单价',
  `confirm_quotation` int(1) NULL DEFAULT 0 COMMENT '是否确认报价',
  `submit_quotation` int(1) NULL DEFAULT 0 COMMENT '提交状态(0草稿，1提交报价(待询价详情确认报价))',
  `sku` varchar(1000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'sku',
  `customer_seq` int(11) NULL DEFAULT NULL COMMENT '客户Id',
  `customer_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `created_by` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_by` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `created_by_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `material_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码',
  `material_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '物料名称',
  `color_name` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '颜色名称',
  `category_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料简码',
  `inquiry_material_info_seq` int(11) NULL DEFAULT NULL COMMENT '询价明细seq',
  `order_quarter_code` int(11) NULL DEFAULT NULL COMMENT '下单季度',
  `sync_status` int(11) NULL DEFAULT 0 COMMENT '0初始值，1采购单同步完成 2委外采购单同步完成 3暂收同步完成 4委外暂收同步完成 5品检同步完成 6入库同步完成 7库存入库表同步完成 8库存出库表同步完成 9库存明细表同步完成',
  `is_deleted` int(11) NULL DEFAULT 0 COMMENT '删除标识',
  `material_info_seq` int(11) NULL DEFAULT NULL COMMENT '物料 info seq',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '开发季度',
  `store_unit_price` decimal(14, 4) NULL DEFAULT 0.0000 COMMENT '库存单价',
  `remark` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `idx_inquiry_info_query`(`customer_seq`, `supplier_seq`, `order_quarter_code`, `effective_date_begin`, `effective_date_end`, `mat_price_inquiry_seq`, `customer_material_seq`) USING BTREE,
  INDEX `inquiry_material_info_seq`(`inquiry_material_info_seq`) USING BTREE,
  INDEX `customer_material_seq`(`customer_material_seq`, `mat_price_inquiry_seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 64114 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '报价明细表' ROW_FORMAT = Dynamic;

