-- ----------------------------
-- Table structure for material_batch
-- ----------------------------
DROP TABLE IF EXISTS `material_batch`;
CREATE TABLE `material_batch`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `type` int(2) NULL DEFAULT NULL COMMENT '单据分类',
  `receipt` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收货单号',
  `supplier_seq` int(11) NULL DEFAULT NULL COMMENT '供应商编号',
  `receipt_date` datetime NULL DEFAULT NULL COMMENT '收货日期',
  `send_date` datetime NULL DEFAULT NULL COMMENT '送货日期',
  `send_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '送货单号',
  `create_by` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '建档人',
