DROP TABLE IF EXISTS `material_batch_info`;
CREATE TABLE `material_batch_info`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `batch_no` int(11) NOT NULL COMMENT '外键',
  `procurement_seq` int(11) NULL DEFAULT NULL COMMENT '采购计划子表主键',
  `no` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单据号',
  `bath_no` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '批次号',
  `storage` int(11) NULL DEFAULT NULL COMMENT '数量',
  `surplus` int(11) NULL DEFAULT NULL COMMENT '剩余数量',
  `unit` varchar(4) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单位（包/双/件）',
  `mater_stock` int(2) NULL DEFAULT NULL COMMENT '库存标识(0:入库 1：出库)',
  `resource` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '来源',
  `price` double(2, 0) NULL DEFAULT NULL COMMENT '单价(不含税)',
  `sum_price` varchar(12) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '金额（不含税）',
  `tax` double(3, 0) NULL DEFAULT NULL COMMENT '税率',
  `resource_no` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '原单据号(仅出库有)',
  `accounting` date NULL DEFAULT NULL COMMENT '会计期待',
  `edit_time` date NULL DEFAULT NULL COMMENT '变更时间',
  `is_delete` int(2) NULL DEFAULT 0 COMMENT '是否删除（0：未删除 1：删除）',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `material_batch_foregin_key`(`batch_no`) USING BTREE,
  CONSTRAINT `material_batch_foregin_key` FOREIGN KEY (`batch_no`) REFERENCES `material_batch` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '物料库存明细' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for material_inventory
-- ----------------------------
DROP TABLE IF EXISTS `material_inventory`;
CREATE TABLE `material_inventory`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `code` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单据号',
  `bath_no` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '批次号',
  `mater_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码',
  `mater_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料名称',
  `storage` int(11) NULL DEFAULT NULL COMMENT '入库数量',
  `out_storage` int(11) NULL DEFAULT NULL COMMENT '出库数量',
  `unit` varchar(2) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单位',
  `is_size` int(1) NULL DEFAULT 0 COMMENT '是否码号管理',
  `resource` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '来源',
  `price` double(10, 2) NULL DEFAULT NULL COMMENT '单价',
  `sum_price` double(10, 2) NULL DEFAULT NULL COMMENT '金额',
  `tax` double(255, 0) NULL DEFAULT NULL COMMENT '税率',
  `supplier` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商编码',
  `edit_time` datetime NULL DEFAULT NULL COMMENT '变更时间',
  `create_date` datetime NULL DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '物料出入库表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for material_inventory_info
-- ----------------------------
DROP TABLE IF EXISTS `material_inventory_info`;
CREATE TABLE `material_inventory_info`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `batch_no` int(11) NOT NULL COMMENT '外键',
  `mater_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码',
  `size` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '码号',
  `storage` int(11) NULL DEFAULT NULL COMMENT '数量',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `material_inventory_foregin_key`(`batch_no`) USING BTREE,
  CONSTRAINT `material_inventory_foregin_key` FOREIGN KEY (`batch_no`) REFERENCES `material_inventory` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '物料出入库表明细' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for material_procurement
-- ----------------------------
DROP TABLE IF EXISTS `material_procurement`;
CREATE TABLE `material_procurement`  (
  `formal_order_code` varchar(150) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `SKU` varchar(50) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL,
  `manual_prod_code` varchar(150) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `position_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `ROW_NO` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL,
  `material_info_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `SL` decimal(10, 4) NULL DEFAULT NULL,
  INDEX `idx_procurement_join`(`SKU`, `manual_prod_code`, `position_name`, `ROW_NO`, `material_info_code`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for material_procurement_bl
-- ----------------------------
DROP TABLE IF EXISTS `material_procurement_bl`;
CREATE TABLE `material_procurement_bl`  (
  `formal_order_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `sku` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `manual_prod_code` varchar(150) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `position_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `row_no` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `material_info_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `sl` decimal(10, 4) NULL DEFAULT NULL,
  INDEX `idx_procurement_join`(`sku`, `manual_prod_code`, `position_name`, `row_no`, `material_info_code`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for material_procurement_bl_new
-- ----------------------------
DROP TABLE IF EXISTS `material_procurement_bl_new`;
CREATE TABLE `material_procurement_bl_new`  (
  `formal_order_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `sku` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `manual_prod_code` varchar(150) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `position_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `row_no` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `material_info_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `sl` decimal(10, 4) NULL DEFAULT NULL,
  UNIQUE INDEX `idx_procurement_join`(`sku`, `manual_prod_code`, `position_name`, `row_no`, `material_info_code`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for material_procurement_new
-- ----------------------------
DROP TABLE IF EXISTS `material_procurement_new`;
CREATE TABLE `material_procurement_new`  (
  `formal_order_code` varchar(150) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `SKU` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `manual_prod_code` varchar(150) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `position_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `ROW_NO` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `material_info_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `SL` decimal(10, 4) NULL DEFAULT NULL,
  UNIQUE INDEX `idx_procurement_join`(`SKU`, `manual_prod_code`, `position_name`, `ROW_NO`, `material_info_code`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for material_receive
-- ----------------------------
DROP TABLE IF EXISTS `material_receive`;
CREATE TABLE `material_receive`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `vender_no` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '厂别代号',
  `type` char(6) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单据类型',
  `no` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单号',
  `apply_company_seq` int(11) NULL DEFAULT NULL COMMENT '申领单位',
  `apply_date` datetime NULL DEFAULT NULL COMMENT '申领时间',
  `filing_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '建档人',
  `filing_date` datetime NULL DEFAULT NULL COMMENT '建档日期',
  `backset_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '锁档人',
  `backset_date` datetime NULL DEFAULT NULL COMMENT '锁档日期',
  `is_backset` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '是否锁档：N-否，Y-是',
  `memo` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `customer_seq` int(11) NULL DEFAULT NULL COMMENT '客户序号',
  `created_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `is_delete` int(1) NULL DEFAULT 0 COMMENT '0:未删除 1：删除',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '材料申领单' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for material_receive_info
-- ----------------------------
DROP TABLE IF EXISTS `material_receive_info`;
CREATE TABLE `material_receive_info`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `sample_order_seq` int(11) NULL DEFAULT NULL COMMENT '样品单号',
  `material_receive_seq` int(11) NULL DEFAULT NULL COMMENT '材料申领表seq',
  `amount` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '申领数量',
  `actual_amount` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '实际数量',
  `price` decimal(10, 2) NULL DEFAULT NULL COMMENT '单价',
  `sum` decimal(10, 2) NULL DEFAULT NULL COMMENT '金额',
  `is_delete` int(1) NULL DEFAULT 0 COMMENT '0:未删除 1：删除',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `material_receive_seq`(`material_receive_seq`) USING BTREE,
  INDEX `sample_order_seq`(`sample_order_seq`) USING BTREE,
  CONSTRAINT `material_receive_info_ibfk_1` FOREIGN KEY (`material_receive_seq`) REFERENCES `material_receive` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `material_receive_info_ibfk_2` FOREIGN KEY (`sample_order_seq`) REFERENCES `sample_order` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '材料申领详情' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for material_replenishment
-- ----------------------------
DROP TABLE IF EXISTS `material_replenishment`;
CREATE TABLE `material_replenishment`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `code` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '补料单号',
  `product_order_code` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '生产订单号',
  `fill_date` date NULL DEFAULT NULL COMMENT '补料日期',
  `sku_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'sku名称',
  `req_material_factory_id` int(11) NULL DEFAULT NULL COMMENT '请料工厂id',
  `req_material_factory_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '请料工厂名称',
  `status` varchar(5) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '状态：51-草稿,10-提交,20-待审批,21-审批中,22-转办,23-委派,24-抄送,25-退回,26-驳回,27-作废,1-撤回,50-完成',
  `factory_floor_id` int(11) NULL DEFAULT NULL COMMENT '工厂车间id',
  `factory_floor` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工厂车间',
  `aritcle` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '形体',
  `customer_article_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户型体',
  `shop_team` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '车间小组',
  `receiver_dept` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '领取部门',
  `receiver_person` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '领取人',
  `receiver_type` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '领取类型',
  `even_num` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '领料双数',
  `duty_ownership` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '责任归属',
  `reason` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '补料原因',
  `remark` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `is_deleted` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否删除',
  `enable` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '1' COMMENT '是否有效',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `size_map` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '前端参数',
  `created_by_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '昵称',
  `manual_prod_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '手工排产单号',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 13 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '材料补料单' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for material_replenishment_matching
-- ----------------------------
DROP TABLE IF EXISTS `material_replenishment_matching`;
CREATE TABLE `material_replenishment_matching`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `material_replenishment_seq` int(11) NULL DEFAULT NULL COMMENT '材料补料seq',
  `od_product_order_order_position_seq` int(11) NULL DEFAULT NULL COMMENT '生产订单-正式订单型体部位-物料信息seq',
  `order_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '订单合同号',
  `sku` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'sku',
  `customer_article_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户型体名称',
  `customer_article_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户型体编号',
  `customer` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户',
  `instruct` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '指令',
  `unit_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单位',
  `category_material_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_estonian_ci NULL DEFAULT NULL COMMENT '物料简码',
  `material_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码',
  `material_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料名称',
  `supplier` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供方',
  `material_add_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料简码',
  `colour_id` int(11) NULL DEFAULT NULL COMMENT '颜色id',
  `colour_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '颜色名称',
  `part_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位编码',
  `part_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位名称',
  `is_matching` int(1) NULL DEFAULT NULL COMMENT '是否配码:0-否,1-是',
  `average_usage` decimal(18, 4) NULL DEFAULT NULL COMMENT '平均用量',
  `plan_usage` decimal(18, 4) NULL DEFAULT NULL COMMENT '预估用量',
  `actual_usage` decimal(18, 4) NULL DEFAULT NULL COMMENT '实际用量',
  `manual_prod_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '手工排产单号',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 194 CHARACTER SET = utf8 COLLATE = utf8_estonian_ci COMMENT = '材料补料配码' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for material_replenishment_matching_size
-- ----------------------------
DROP TABLE IF EXISTS `material_replenishment_matching_size`;
CREATE TABLE `material_replenishment_matching_size`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `material_replenishment_matching_seq` int(11) NULL DEFAULT NULL COMMENT '配码seq',
  `size` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '尺码',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 49 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '材料补料配码size' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for material_replenishment_matching_size_value
-- ----------------------------
DROP TABLE IF EXISTS `material_replenishment_matching_size_value`;
CREATE TABLE `material_replenishment_matching_size_value`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `material_replenishment_matching_size_seq` int(11) NULL DEFAULT NULL COMMENT '材料补料配码size',
  `left_size_num` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '左脚数量',
  `right_size_num` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '右脚数量',
  `average_usage` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '评均用量',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 49 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '配码size数量表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for material_replenishment_matching_value
-- ----------------------------
DROP TABLE IF EXISTS `material_replenishment_matching_value`;
CREATE TABLE `material_replenishment_matching_value`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `material_replenishment_matching_seq` int(11) NOT NULL COMMENT '材料补料配码seq',
  `num_key` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '码号',
  `num_value` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '数量',
  `average_usage` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2934 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '不配码材料数量' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for material_replenishment_orders
-- ----------------------------
DROP TABLE IF EXISTS `material_replenishment_orders`;
CREATE TABLE `material_replenishment_orders`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `material_replenishment_seq` int(11) NULL DEFAULT NULL COMMENT '材料补料seq',
  `order_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '正式订单号',
  `order_row` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '正式订单行标识',
  `is_check` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '是否勾选:0-否,1-是',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 13 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '材料补料正式订单关联表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for material_return_materials
-- ----------------------------
DROP TABLE IF EXISTS `material_return_materials`;
CREATE TABLE `material_return_materials`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `return_materials_type` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '退料类型 1加工材料退料2 原材料退料',
  `return_materials_number` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '退料单号',
  `return_materials_at` datetime NULL DEFAULT NULL COMMENT '退料日期',
  `return_materials_address` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '退料地址',
  `outbound_at` datetime NULL DEFAULT NULL COMMENT '出库日期',
  `operator` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '经办人',
  `factory_id` int(11) NULL DEFAULT NULL,
  `factory` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工厂',
  `warehouse` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库',
  `status` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '状态(0暂存，1提交)',
  `printing_frequency` int(11) NULL DEFAULT 0 COMMENT '打印次数',
  `submit_at` datetime NULL DEFAULT NULL COMMENT '提交日期',
  `workshop_team` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '车间小组',
