  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `mat_warehouse_out_seq` int(11) NOT NULL COMMENT '材料转仓出库主键',
  `prod_order_code` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '生产订单号',
  `manual_prod_code` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '指令号',
  `company_out_seq` int(11) NOT NULL COMMENT '转出工厂seq',
  `warehouse_out_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '转出仓库code',
