  INDEX `more_index`(`prod_order_code`, `sku`, `material_info_code`, `warehouse_out_code`, `company_out_seq`, `mat_warehouse_out_seq`) USING BTREE,
  FULLTEXT INDEX `material_warehouse_out_extra_material_name_index`(`material_name`),
  CONSTRAINT `material_warehouse_out_extra_material_warehouse_out_seq_fk` FOREIGN KEY (`mat_warehouse_out_seq`) REFERENCES `material_warehouse_out` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT
