-- ----------------------------
-- Table structure for mes_message_async_task
-- ----------------------------
DROP TABLE IF EXISTS `mes_message_async_task`;
CREATE TABLE `mes_message_async_task`  (
  `seq` int(11) NOT NULL COMMENT '序号',
  `business_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '业务类型',
  `business_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '业务code',
  `business_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '业务序号',
  `content` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '发送内容',
  `status` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '处理状态',
  `execute_count` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '处理次数',
  `max_retry_count` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '失败时最大重试次数',
  `last_execute_time` datetime NULL DEFAULT NULL COMMENT '最后处理时间',
