  INDEX `po`(`po`) USING BTREE,
  INDEX `status`(`status`) USING BTREE,
  INDEX `idx_mes_outbound_api_status_po`(`po`, `size_name`, `status`) USING BTREE,
  INDEX `idx_mes_outbound_api_po_size`(`po`, `size_name`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 135519 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = 'mes po出库单接口' ROW_FORMAT = Dynamic;

