-- ----------------------------
-- Table structure for mx_material_category
-- ----------------------------
DROP TABLE IF EXISTS `mx_material_category`;
CREATE TABLE `mx_material_category`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `category_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料简码',
  `old_category_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '原物料简码',
  `material_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '物料名称',
  `old_material_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '原物料名称',
  `type_seq` int(11) NULL DEFAULT NULL COMMENT '物料类型id',
  `type_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料类型名称',
  `class_seq` int(11) NULL DEFAULT NULL COMMENT '物料类别id',
  `class_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料类别名称',
  `class_path_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料类别路径名称',
  `group_seq` int(11) NULL DEFAULT NULL COMMENT '物料分组id',
  `group_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料分组名称',
  `unit_seq` int(11) NULL DEFAULT NULL COMMENT '单位id',
  `unit_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单位名称',
  `provider_seq` int(11) NULL DEFAULT NULL COMMENT '默认供应商id',
  `provider_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '默认供应商名称',
  `is_match_size` int(1) NULL DEFAULT 0 COMMENT '是否配码（0-否，1-是）',
  `is_each_expend` int(1) NULL DEFAULT 0 COMMENT '是否码段用量(0-否，1-是)',
  `is_used` int(1) NULL DEFAULT 0 COMMENT '是否使用',
  `enable` int(1) NULL DEFAULT 0 COMMENT '是否停用(0-否，1-是)',
  `is_out_sourcing` int(1) NULL DEFAULT 0 COMMENT '是否外发加工(0-否,1-是)',
  `is_color_constraint` int(1) NULL DEFAULT 0 COMMENT '是否颜色约束',
  `money_type_seq` int(11) NULL DEFAULT NULL COMMENT '币种id',
  `money_type_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '币种名称',
  `purchase_unit_seq` int(11) NULL DEFAULT NULL COMMENT '采购单位id',
  `purchase_unit_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购单位名称',
  `purchase_convert_rate1` varchar(18) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购转换比率（比值）',
  `purchase_convert_rate` decimal(18, 4) NULL DEFAULT 0.0000 COMMENT '采购转换比率',
  `provider_type_seq` int(11) NULL DEFAULT NULL COMMENT '供方id',
  `provider_type_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供方名称',
  `purchase_hit_rate` decimal(18, 2) NULL DEFAULT 0.00 COMMENT '采购打大率',
  `many_purchase_rate` decimal(18, 2) NULL DEFAULT 0.00 COMMENT '允许多采比率',
  `many_receive_rate` decimal(18, 2) NULL DEFAULT 0.00 COMMENT '允许多收比率',
  `is_exempt_verify` int(1) NULL DEFAULT 0 COMMENT '是否免检(0-否,1-是)',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除(0-否,1-是)',
  `data_source` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '数据来源',
  `item_source` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单据来源',
  `approve_status` bit(2) NULL DEFAULT NULL COMMENT '审批状态',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `dna_id` int(11) NULL DEFAULT NULL,
  `created_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `updated_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `idx_seq`(`seq`) USING BTREE,
  INDEX `idx_class_seq`(`class_seq`, `class_name`, `is_deleted`, `seq`) USING BTREE,
  INDEX `category_code`(`category_code`, `is_out_sourcing`, `is_deleted`, `material_name`(255), `created_by`, `created_at`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 31404 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '物料简码' ROW_FORMAT = DYNAMIC;

