-- ----------------------------
-- Table structure for od_order_doc
-- ----------------------------
DROP TABLE IF EXISTS `od_order_doc`;
CREATE TABLE `od_order_doc`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `code` varchar(60) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '订单合同号',
  `type` int(11) NULL DEFAULT NULL COMMENT '订单类型',
  `type_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '订单名称',
  `pay_way_seq` int(50) NULL DEFAULT NULL COMMENT '付款方式(字典序号)',
  `pay_way_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '付款方式(字典名称)',
  `order_date` date NULL DEFAULT NULL COMMENT '下单日期',
  `money_type_seq` int(11) NULL DEFAULT NULL COMMENT '币种序号(目标币种)',
  `money_type` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '币种编码(目标币种)',
  `money_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '币种名称(目标币种)',
  `money_type_rate` decimal(18, 2) NULL DEFAULT NULL COMMENT '汇率(原币种：人民币与目标币种的汇率)',
  `custom_seq` int(11) NULL DEFAULT NULL COMMENT '客户序号',
  `custom_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `custom_contact_seq` int(11) NULL DEFAULT NULL COMMENT '客户联系人序号(根据选中客户查询联系人后选中)',
  `custom_contact_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户联系人名称(选中联系人带出)',
  `custom_contact_fax` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户传真(选中联系人带出)',
  `custom_contact_receipt_address` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收货地址(选中联系人带出)',
  `custom_contact_receipt_address_abb` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收货地址简称(选中联系人带出)',
  `custom_contact_mobile_phone` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户联系电话(选中联系人带出)',
  `freight_mode_seq` int(11) NULL DEFAULT NULL COMMENT '货运方式(字典seq)',
  `freight_mode` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '货运方式(字典名称)',
  `receiving_department` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '接单部门(默认当前登录用户所在部门，可修改)',
  `comp_seq` int(11) NULL DEFAULT NULL COMMENT '公司序号(根据当前登录用户获取所在公司)',
  `comp_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司名称(根据当前登录用户获取所在公司)',
  `comp_contact_seq` int(11) NULL DEFAULT NULL COMMENT '公司联系人seq(根据当前登录用户所在公司查询联系人后选中)',
  `comp_contact_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司联系人名称(选中联系人带出)',
  `comp_contact_mobile_phone` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司联系人联系电话(选中联系人带出)',
  `comp_bank_seq` int(11) NULL DEFAULT NULL COMMENT '公司账户序号(根据当前登录用户获取所在公司查询账号信息)',
  `comp_bank_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司账户名称(根据当前登录用户获取所在公司查询账号信息)',
  `current_account` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '往来账户(数据格式：公司名称/公司账号名称)',
  `total_number` int(11) NULL DEFAULT 0 COMMENT '订单总数',
  `memo` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '备注',
  `status_code` int(11) NULL DEFAULT NULL COMMENT '状态编码',
  `status` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '状态名称',
  `enable` tinyint(1) NULL DEFAULT 1 COMMENT '是否可用',
  `is_deleted` tinyint(1) NULL DEFAULT 0 COMMENT '是否删除',
  `version` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '版本号',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人昵称',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `data_source` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '数据来源（导入、手动新增、流程单据）',
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `idx_key`(`seq`) USING BTREE,
  INDEX `ky_code`(`code`, `enable`, `is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 357 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '正式订单基础表信息' ROW_FORMAT = Dynamic;

