DROP TABLE IF EXISTS `od_order_doc_art_position_material`;
CREATE TABLE `od_order_doc_art_position_material`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `od_order_doc_seq` int(11) NULL DEFAULT NULL COMMENT '正式订单序号',
  `order_doc_aritcle_seq` int(11) NULL DEFAULT NULL COMMENT '正式订单型体表序号',
  `od_order_doc_art_position` int(11) NULL DEFAULT NULL COMMENT '正式订单型体部位表序号',
  `art_seq` int(11) NULL DEFAULT NULL COMMENT '型体seq',
  `art_post_seq` int(11) NULL DEFAULT NULL COMMENT '型体部位序号',
  `parent_seq` int(11) NULL DEFAULT NULL COMMENT '物料父级seq',
  `position_type` int(11) NULL DEFAULT NULL COMMENT '部位材料类型（0：型体部位材料；1：包材部位材料）',
  `no` int(11) NULL DEFAULT NULL,
  `key` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'key',
  `base_each_expend` decimal(11, 4) NULL DEFAULT NULL COMMENT '当前物料单耗（(单耗=1*A1单耗)：1*子材料单耗*子材料单耗*...）\r\nA(外加工材料,单耗1)\r\nA1(单耗=1*A1单耗)\r\nA11(单耗=1*A1单耗*A11单耗)\r\nA12(单耗=1*A1单耗*A12单耗)\r\nA2(单耗=1*A2单耗)',
  `material_category_seq` int(11) NULL DEFAULT NULL COMMENT '物料简码序号',
  `material_category_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料简码',
  `material_category_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '物料简码名称',
  `provider_seq` int(11) NULL DEFAULT NULL COMMENT '供应商seq',
  `provider_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商名称',
  `provider_type_seq` int(11) NULL DEFAULT NULL COMMENT '供方类型seq',
  `provider_type_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供方类型名称',
  `material_info_seq` int(11) NULL DEFAULT NULL COMMENT '物料编码seq',
  `material_info_size` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码size',
  `material_info_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码',
  `material_info_colour` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码颜色编码',
  `material_info_colour_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码颜色名称',
  `material_info_is_match_size` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料是否配码',
  `material_info_is_each_expend` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料是否码段用量',
  `material_info_is_out_sourcing` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料是否外加工',
  `material_category_unit_seq` int(11) NULL DEFAULT NULL COMMENT '物料单位seq',
  `material_category_unit_name` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料单位名称',
  `ie_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工艺名称',
  `grading_type_seq` int(11) NULL DEFAULT NULL COMMENT '物料单位级放类型seq',
  `grading_type_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料单位级放类型',
  `grading_rate` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品类别级放类型级放比率',
  `grading_count` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品类别级放类型级放数量',
  `is_deleted` int(11) NULL DEFAULT 0 COMMENT '是否删除',
  `memo` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '备注',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `idx_key_seq`(`seq`) USING BTREE,
  INDEX `idx_position_size`(`od_order_doc_art_position`, `key`, `material_category_code`, `material_info_code`, `is_deleted`, `art_post_seq`) USING BTREE,
  INDEX `idx_odr_seq`(`od_order_doc_seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1170269 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '正式订单型体部位-物料明细' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for od_order_doc_art_position_size_dosage
-- ----------------------------
DROP TABLE IF EXISTS `od_order_doc_art_position_size_dosage`;
CREATE TABLE `od_order_doc_art_position_size_dosage`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
