  `order_doc_aritcle_seq` int(11) NULL DEFAULT NULL COMMENT '正式订单型体表序号',
  `art_position_size_seq` int(11) NULL DEFAULT NULL COMMENT '型体部位尺码表序号',
  `art_position_size_dosage_seq` int(11) NULL DEFAULT NULL COMMENT '型体部位尺码用量表序号',
  `order_doc_aritcle_position_seq` int(11) NULL DEFAULT NULL COMMENT '正式订单型体部位物料序号',
  `art_size_seq` int(11) NULL DEFAULT NULL COMMENT '型体size序号',
  `material_info_seq` int(11) NULL DEFAULT NULL COMMENT '物料编码序号',
  `material_size_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料尺码名称',
  `key` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'key',
  `each_expend` varchar(255) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '用量',
  `is_deleted` int(11) NOT NULL DEFAULT 0 COMMENT '是否被删除',
  `deleted_at` datetime NULL DEFAULT NULL,
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `order_doc_aritcle_position_seq`(`order_doc_aritcle_position_seq`) USING BTREE,
  INDEX `idx_position_size`(`order_doc_aritcle_position_seq`, `material_info_seq`, `key`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 11318492 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '正式订单型体部位各码用量明细' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for od_order_doc_article
-- ----------------------------
DROP TABLE IF EXISTS `od_order_doc_article`;
CREATE TABLE `od_order_doc_article`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `od_order_doc_seq` int(11) NULL DEFAULT NULL COMMENT '订单序号',
  `row_no` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'PO（原行标识）',
  `is_pre_compensation` int(1) NULL DEFAULT 0 COMMENT '是否预补',
  `art_seq` int(11) NULL DEFAULT NULL COMMENT '产品资料序号',
