  `sku` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品编号',
  `code` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工厂型体编号',
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '型体名称',
  `customer_article_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户型体名称',
  `customer_article_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户型体编号',
  `color` int(11) NULL DEFAULT NULL COMMENT '颜色序号',
  `color_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '颜色名称',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '下单季度序号',
  `product_class_seq` int(11) NULL DEFAULT NULL COMMENT '产品类别seq',
  `product_class_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品类别名称',
  `basic_size_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'size模版(size模版seq)',
  `basic_size_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '基本码',
  `size_range` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '码段',
  `sex` int(11) NULL DEFAULT NULL COMMENT '样鞋性别（字典表seq）',
  `last_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '楦头代号',
  `outside_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '大底代号',
  `cutter_cod` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '刀模编号',
  `face_material_seq` int(11) NULL DEFAULT NULL COMMENT '帮面材质seq',
  `face_material_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '帮面材质',
  `implement_standard` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '国家执行标准',
  `country_barcode` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '国家条码',
  `sample_stage_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品阶段id',
  `sample_stage_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品阶段名称',
  `total_number` int(11) NULL DEFAULT 0 COMMENT '订单型体总数',
  `dispatch_group_number` int(11) NULL DEFAULT 0 COMMENT '派工数量',
  `order_quarter` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '下单季度',
  `manual_prod_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '指令号',
  `customer_code` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客人订单号',
  `version` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT 'V1.0.0' COMMENT '版本号',
  `mrp_status` int(1) NULL DEFAULT 0 COMMENT '0:未运算；1:部分运算；2:全部运算',
  `status` varchar(3) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '状态\r\n',
  `memo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '型体说明',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除',
  `enable` int(1) NULL DEFAULT 1 COMMENT '是否有效',
  `end_delivery_date` date NULL DEFAULT NULL COMMENT '最晚交期时间',
  `destination` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '目的地',
  `size_codes` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '尺码列表',
  `discharge_date` date NULL DEFAULT NULL COMMENT '生产日期',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `bom_updated_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '包材更新人',
  `bom_updated_at` datetime NULL DEFAULT NULL COMMENT '绑定的包材更新时间',
  `sync_status` int(1) NULL DEFAULT 0 COMMENT '推送MES状态(0.未同步  1.已同步  2.同步失败)',
  `price_sync_status` int(1) NULL DEFAULT 0 COMMENT '单价推送MES状态(0.未同步  1.已同步  2.同步失败)',
  `package_bom_result` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '包材绑定结果',
  `binding_quotation_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '绑定报价更新人',
  `binding_quotation_at` datetime NULL DEFAULT NULL COMMENT '绑定报价更新时间',
  `quotation_seq` int(11) NULL DEFAULT NULL COMMENT '报价的seq',
  `quotation_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价的编号',
  `quotation_amount` decimal(14, 4) NULL DEFAULT NULL COMMENT '报价金额',
  `new_and_old_styles` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '新旧款',
  `brand` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '品牌',
  `before_status` varchar(3) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '终止前的状态',
  `is_signed` int(2) NULL DEFAULT 0 COMMENT '是否签合',
  `contract_no` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '合同号',
  `order_no` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '合同订单号',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `od_order_doc_seq`(`od_order_doc_seq`) USING BTREE,
  INDEX `od_proc`(`row_no`, `od_order_doc_seq`) USING BTREE,
  INDEX `idx_article_doc_seq_row`(`od_order_doc_seq`, `row_no`, `quotation_amount`) USING BTREE,
  INDEX `od_order_doc_article_manual_prod_code_IDX`(`manual_prod_code`, `row_no`) USING BTREE,
  INDEX `idx_od_order_doc_article_row_no`(`row_no`) USING BTREE,
  CONSTRAINT `od_order_doc_article_ibfk_1` FOREIGN KEY (`od_order_doc_seq`) REFERENCES `od_order_doc` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 11596 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '正式订单型体' ROW_FORMAT = DYNAMIC;

