  `handle_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '处理人',
  `handle_time` datetime NULL DEFAULT NULL COMMENT '处理时间',
  `new_and_old_styles` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '新旧款',
  `brand` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '品牌',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `od_order_doc_seq`(`od_order_doc_seq`) USING BTREE,
  INDEX `od_proc`(`row_no`, `od_order_doc_seq`) USING BTREE,
  CONSTRAINT `od_order_doc_article_preview_ibfk_1` FOREIGN KEY (`od_order_doc_seq`) REFERENCES `od_order_doc_preview` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 10527 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '正式订单型体' ROW_FORMAT = DYNAMIC;

