  `custom_contact_seq` int(11) NULL DEFAULT NULL COMMENT '客户联系人序号(根据选中客户查询联系人后选中)',
  `custom_contact_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户联系人名称(选中联系人带出)',
  `custom_contact_fax` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户传真(选中联系人带出)',
  `custom_contact_receipt_address` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收货地址(选中联系人带出)',
