  `comp_seq` int(11) NULL DEFAULT NULL COMMENT '公司序号(根据当前登录用户获取所在公司)',
  `comp_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司名称(根据当前登录用户获取所在公司)',
  `comp_contact_seq` int(11) NULL DEFAULT NULL COMMENT '公司联系人seq(根据当前登录用户所在公司查询联系人后选中)',
  `comp_contact_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司联系人名称(选中联系人带出)',
  `comp_contact_mobile_phone` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司联系人联系电话(选中联系人带出)',
  `comp_bank_seq` int(11) NULL DEFAULT NULL COMMENT '公司账户序号(根据当前登录用户获取所在公司查询账号信息)',
  `comp_bank_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司账户名称(根据当前登录用户获取所在公司查询账号信息)',
  `current_account` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '往来账户(数据格式：公司名称/公司账号名称)',
  `total_number` int(11) NULL DEFAULT 0 COMMENT '订单总数',
  `memo` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '备注',
  `status_code` int(11) NULL DEFAULT NULL COMMENT '状态编码',
  `status` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '状态名称',
  `enable` tinyint(1) NULL DEFAULT 1 COMMENT '是否可用',
  `is_deleted` tinyint(1) NULL DEFAULT 0 COMMENT '是否删除',
  `version` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '版本号',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人昵称',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `data_source` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '数据来源（导入、手动新增、流程单据）',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `ky_code`(`code`, `enable`, `is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 290 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '正式订单基础表信息' ROW_FORMAT = Dynamic;

