  INDEX `idx_check_id`(`seq`, `is_deleted`) USING BTREE,
  INDEX `idx_od_prod_sku`(`od_order_doc_code`, `sku`, `row_no`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 10688 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '生产订单' ROW_FORMAT = DYNAMIC;

