  `od_order_delivery_seq` int(11) NULL DEFAULT NULL COMMENT '正式订单交期表序号',
  `delivery_time` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '交期',
  `num` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '交期数量',
  `no` int(11) NULL DEFAULT NULL COMMENT '顺序号',
  `discharge_date` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '出厂日期',
  `latest_shipping_date` timestamp NULL DEFAULT NULL COMMENT '最晚装船日',
  `transp_way` int(1) NULL DEFAULT NULL COMMENT '运输方式',
