  `destination` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '目的地',
  `packing_location` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '装箱地',
  `unloading_location` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '卸货地',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除',
  `memo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `product_order_order_size_seq`(`product_order_order_size_seq`) USING BTREE,
  INDEX `product_order_seq`(`product_order_seq`) USING BTREE,
  CONSTRAINT `od_product_order_doc_size_delivery_time_ibfk_1` FOREIGN KEY (`product_order_order_size_seq`) REFERENCES `od_product_order_order_size` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 65271 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '生产订单型体尺码交期' ROW_FORMAT = DYNAMIC;

