  `mx_material_category_purchase_convert_rate1` varchar(8) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购转换比率（比值）',
  `mx_material_category_purchase_hit_rate` decimal(18, 2) NULL DEFAULT NULL COMMENT '物料采购打大率',
  `mx_material_category_many_purchase_rate` decimal(18, 2) NULL DEFAULT NULL COMMENT '物料允许多采比率',
  `order_size` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '正式订单尺码',
  `ie_name` varchar(600) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工艺名称',
  `version` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '版本号',
  `is_deleted` int(11) NULL DEFAULT 0 COMMENT '是否删除',
