-- ----------------------------
-- Table structure for om_article
-- ----------------------------
DROP TABLE IF EXISTS `om_article`;
CREATE TABLE `om_article`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `sku` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'sku',
  `origin_sku` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '原始型体数据sku值',
  `sku_logo` int(11) NULL DEFAULT NULL COMMENT 'sku主图片',
  `supplier_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '所属工厂序号',
  `supplier_name` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `original_code` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '原始型体编号\r\n（当型体为新创建时，该字段为空\r\n   当型体为型体更新时，为原始型体编号\r\n    当型体为复制新增时，为复制形体号）',
  `code` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工厂型体编号',
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '型体名称',
  `customer_seq` int(11) NULL DEFAULT NULL COMMENT '客户Id',
  `customer_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `customer_article_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户型体名称',
  `customer_article_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户型体编号',
  `color` int(11) NULL DEFAULT NULL COMMENT '颜色序号',
  `color_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '颜色名称',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '季度序号',
  `product_class_seq` int(11) NULL DEFAULT NULL COMMENT '产品类别seq',
  `product_class_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品类别名称',
  `om_size_seq` int(11) NULL DEFAULT NULL COMMENT '尺码模板序号',
  `om_size_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '尺码模板名称',
  `basic_size_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '基本码序号',
  `basic_size_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '基本码',
  `accounting_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价码',
  `size_range` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '码段',
  `sex` int(11) NULL DEFAULT NULL COMMENT '样鞋性别（字典表seq）',
  `inner_cavity_height` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'IDS内腔长度',
  `heel_height` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '后跟高度',
  `waist_height` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '外腰高度',
  `inner_waist_height` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '内腰高度',
  `vamp_length` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '鞋头长度',
  `vamp_height` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '鞋头高度',
  `collar_inside_height` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '领口内高度',
  `collar_outside_height` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '领口外高度',
  `last_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '楦头代号',
  `outside_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '大底代号',
  `cutter_cod` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '刀模编号',
  `face_material_seq` int(11) NULL DEFAULT NULL COMMENT '帮面材质seq',
  `face_material_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '帮面材质',
  `implement_standard` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '国家执行标准',
  `country_bar_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '国家条码',
  `sample_stage_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品阶段id',
  `sample_stage_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品阶段名称',
  `is_inquire` int(1) NULL DEFAULT 0 COMMENT '是否完成询价（0：否；1：是）',
  `is_many_each_expend` int(11) NULL DEFAULT NULL COMMENT '是否多码段级放',
  `version` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '版本号',
  `status` varchar(3) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '状态\r\n0:草稿\r\n10：待审核\r\n11：撤回\r\n12：审核中\r\n13：驳回\r\n20：审核通过\r\n\r\n40: \r\n401:用量维护中\r\n1: 草稿\r\n30：用量维护待处理',
  `dosage_status` varchar(3) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '用量状态\r\n40:用量已维护\r\n401:用量维护中\r\n1: 草稿\r\n30：用量维护待处理',
  `is_abnormal` int(1) NULL DEFAULT 0 COMMENT '数据是否异常\r\n1：是\r\n0：否',
  `error_message` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '异常信息',
  `way` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '方式',
  `article_seq` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '关联型体seq(关联型体seq值，用“,”隔开，便于查询关联型体信息)',
  `memo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '型体说明',
  `tag_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '吊牌价',
  `loss_rate` decimal(10, 2) NULL DEFAULT NULL COMMENT '损耗率',
  `origin_seq` int(11) NULL DEFAULT NULL COMMENT '原始型体seq(为型体申请变更记录原seq)',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除',
  `enable` int(1) NULL DEFAULT 1 COMMENT '是否有效',
  `dosage_created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '用量创建人',
  `dosage_created_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '用量创建人名称',
  `dosage_created_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '用量创建时间',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人昵称',
  `created_at` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `change_at` datetime NULL DEFAULT NULL COMMENT '变更时间',
  `change_username` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '变更人',
  `dna_id` int(11) NULL DEFAULT NULL,
  `pull_mes` int(1) NULL DEFAULT 0 COMMENT '推送mes状态(0：未推送；1：推送成功；2：推送失败）',
  `pull_mes_memo` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `pull_mes_ie` int(1) NULL DEFAULT 0 COMMENT '产品工艺报价同步mes状态(0：未推送；1：推送成功；2：推送失败）',
  `pull_mes_ie_memo` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `pull_mes_dosage` int(1) NULL DEFAULT 0 COMMENT '产品用量同步mes状态(0：未推送；1：推送成功；2：推送失败）',
  `pull_mes_dosage_memo` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `print_count` int(11) NULL DEFAULT 0 COMMENT '打印次数',
  `sample_number` int(11) NULL DEFAULT NULL,
  `updated_by_qty` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '用量修改人',
  `updated_at_qty` timestamp NULL DEFAULT NULL COMMENT '用量修改时间',
  `bomversionnumber` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'BOM版本号',
  `is_craft_quotation` int(11) NULL DEFAULT 0 COMMENT '是否工艺报价  1.是 0.否',
  `brand` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '品牌',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `customer_seq`(`customer_seq`) USING BTREE,
  INDEX `idx_sku_art`(`sku`, `seq`, `customer_article_code`, `quarter_code`) USING BTREE,
  INDEX `idx_om_article_enabled`(`is_deleted`, `enable`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 7094 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '产品资料' ROW_FORMAT = DYNAMIC;

