-- ----------------------------
-- Table structure for om_article_change_record
-- ----------------------------
DROP TABLE IF EXISTS `om_article_change_record`;
CREATE TABLE `om_article_change_record`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
