  `product_class_seq` int(11) NULL DEFAULT NULL COMMENT '产品类型seq',
  `product_class_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品类别名称',
  `art_version` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建成功后的版本',
