  `active` int(11) NOT NULL DEFAULT 1 COMMENT '数据有效标识 1有效 0删除',
  `art_audit_username` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '型体审批人',
  `art_audit_time` datetime NULL DEFAULT NULL COMMENT '型体审批时间',
  `dosage_audit_username` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '用量审批人',
  `dosage_audit_time` datetime NULL DEFAULT NULL COMMENT '用量审批时间',
  `business_audit_username` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '业务审批人',
  `business_audit_time` datetime NULL DEFAULT NULL COMMENT '业务审批时间',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `created_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人昵称',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `is_confirm` int(11) NULL DEFAULT 0 COMMENT '是否确认  0.未确认  1.已确认',
  `confirm_user` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '确认人',
  `confirm_date` datetime NULL DEFAULT NULL COMMENT '确认时间',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `idx_seq_status`(`seq`, `status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2575 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '生产订单变更记录' ROW_FORMAT = DYNAMIC;

