  `purchase_unit_seq` int(11) NULL DEFAULT NULL COMMENT '采购单位序号',
  `purchase_unit_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购单位名称',
