  `instruction_difference_usage` decimal(10, 2) NULL DEFAULT NULL COMMENT '指令用量差异',
  `original_planned_usage` decimal(10, 2) NULL DEFAULT NULL COMMENT '原计划用量',
  `latest_planned_usage` decimal(10, 2) NULL DEFAULT NULL COMMENT '现计划用量',
  `planned_difference_usage` decimal(10, 2) NULL DEFAULT NULL COMMENT '计划用量差异',
  `original_is_quoted` int(1) NULL DEFAULT NULL COMMENT '原指令材料是否已报价',
  `latest_is_quoted` int(1) NULL DEFAULT NULL COMMENT '现指令材料是否已报价',
