  `latest_amount` decimal(10, 2) NULL DEFAULT NULL COMMENT '现指令材料总金额',
  `amount_difference` decimal(10, 2) NULL DEFAULT NULL COMMENT '指令材料总金额差异',
  `purchased_quantity_todo` decimal(10, 2) NULL DEFAULT NULL COMMENT '待采购数量',
  `purchased_quantity` decimal(10, 2) NULL DEFAULT NULL COMMENT '已采数量',
  `received_quantity` decimal(10, 2) NULL DEFAULT NULL COMMENT '已收数量',
