  `is_handle` int(11) NULL DEFAULT 0 COMMENT '是否已经处理 1是0否',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `customer_seq`(`customer_seq`) USING BTREE,
  INDEX `idx_sku_art`(`sku`, `seq`, `customer_article_code`, `quarter_code`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 23 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '产品资料_dna' ROW_FORMAT = DYNAMIC;

