  `position_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位编号',
  `position_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位名称',
  `process_seq` int(11) NULL DEFAULT NULL COMMENT '制程主键',
  `process_name` varchar(55) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '制程名称',
  `material_category_seq` int(11) NULL DEFAULT NULL COMMENT '物料简码序号',
  `material_category_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料简码',
  `material_category_name` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料简码名称',
  `material_category_unit_seq` int(11) NULL DEFAULT NULL COMMENT '物料简码单位序号',
  `material_category_unit_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料简码单位名称',
  `material_info_seq` int(11) NULL DEFAULT NULL COMMENT '物料编码seq',
  `material_info_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料code',
  `material_info_colour` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码颜色编码',
  `material_info_colour_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码颜色名称',
  `material_type_seq` int(11) NULL DEFAULT NULL COMMENT '部位物料分类序号',
  `material_type_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位物料类型',
  `group_seq` int(11) NULL DEFAULT NULL COMMENT '分组序号',
  `group_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '分组名称',
  `provider_seq` int(11) NULL DEFAULT NULL COMMENT '供应商seq',
  `provider_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商名称',
  `provider_type_seq` int(11) NULL DEFAULT NULL COMMENT '供方类型seq',
  `provider_type_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供方类型名称',
  `grading_type_seq` int(11) NULL DEFAULT NULL COMMENT '物料单位级放类型seq',
  `grading_type_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料单位级放类型',
  `grading_rate` decimal(10, 4) NULL DEFAULT NULL COMMENT '级放比率',
  `grading_count` int(11) NULL DEFAULT NULL COMMENT '级放数量',
  `material_info_is_match_size` int(11) NULL DEFAULT NULL COMMENT '材料是否配码 1是 0否',
  `material_info_is_each_expend` int(11) NULL DEFAULT NULL COMMENT '是否码段用量 1是 0否',
  `material_info_is_out_sourcing` int(11) NULL DEFAULT NULL COMMENT '物料是否外加工',
  `loss_rate` decimal(10, 2) NULL DEFAULT NULL COMMENT '损耗率',
  `is_new_data` int(11) NOT NULL COMMENT '是否为新增数据 1是 0否',
  `is_craft` int(11) NULL DEFAULT NULL COMMENT '是否工艺 1是 0否',
  `ie_name` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工艺名称',
  `status` int(11) NOT NULL COMMENT '状态 0未修改,1修改，2删除 3新增',
  `change_type` int(11) NULL DEFAULT NULL COMMENT '变更类型 1.仅变更用量 2.变更数据明细',
  `change_remark` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '变更详情备注',
  `dosage_info` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '用量信息数据',
  `position_size_info` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位尺码信息',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `is_match_system` int(11) NULL DEFAULT 0 COMMENT '品牌系统是否处理  0未处理 1.已处理',
  `handle_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '处理人',
  `handle_time` datetime NULL DEFAULT NULL COMMENT '处理时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 28090 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '型体物料部位待变更数据' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for om_article_pro_order_change
-- ----------------------------
DROP TABLE IF EXISTS `om_article_pro_order_change`;
CREATE TABLE `om_article_pro_order_change`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
