-- ----------------------------
-- Table structure for om_article_size_snapshot
-- ----------------------------
DROP TABLE IF EXISTS `om_article_size_snapshot`;
CREATE TABLE `om_article_size_snapshot`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '型体尺存序号',
  `business_id` int(11) NULL DEFAULT NULL COMMENT '生成业务Id',
  `article_seq` int(11) NOT NULL COMMENT '型体表序号',
  `size_seq` int(11) NULL DEFAULT NULL COMMENT 'size序号',
  `size_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `no` int(11) NULL DEFAULT NULL,
  `size_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `group_name` varchar(300) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `product_bar_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品条码(客户产品类别获取)',
  `is_standard_code` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '是否基本码',
  `is_quotation` int(11) NULL DEFAULT NULL COMMENT '是否已报价 0未报价  1已报价',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除',
  `memo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `snapshot_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '快照时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1089 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '型体大小(用于产品资料变更保存原始数据)' ROW_FORMAT = DYNAMIC;

