  `size_range` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '码段',
  `sex` int(11) NULL DEFAULT NULL COMMENT '样鞋性别（字典表seq）',
