  `country_bar_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '国家条码',
  `sample_stage_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品阶段id',
  `sample_stage_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品阶段名称',
  `is_inquire` int(1) NULL DEFAULT 0 COMMENT '是否完成询价（0：否；1：是）',
  `is_many_each_expend` int(11) NULL DEFAULT NULL COMMENT '是否多码段级放',
  `version` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '版本号',
  `status` varchar(3) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '状态\r\n0:草稿\r\n10：待审核\r\n11：撤回\r\n12：审核中\r\n13：驳回\r\n20：审核通过\r\n\r\n40: \r\n401:用量维护中\r\n1: 草稿\r\n30：用量维护待处理',
  `way` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '方式',
  `article_seq` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '关联型体seq(关联型体seq值，用“,”隔开，便于查询关联型体信息)',
  `memo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '型体说明',
  `tag_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '吊牌价',
  `loss_rate` decimal(10, 2) NULL DEFAULT NULL COMMENT '损耗率',
  `origin_seq` int(11) NULL DEFAULT NULL COMMENT '原始型体seq(为型体申请变更记录原seq)',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除',
  `enable` int(1) NULL DEFAULT 1 COMMENT '是否有效',
  `dosage_created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `dosage_created_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `dosage_created_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人昵称',
  `created_at` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `dna_id` int(11) NULL DEFAULT NULL,
  `sample_number` int(11) NULL DEFAULT NULL
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Dynamic;

