) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for output_feedback
-- ----------------------------
DROP TABLE IF EXISTS `output_feedback`;
CREATE TABLE `output_feedback`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `artrcle_seq` int(11) NULL DEFAULT NULL COMMENT '型体序号',
  `sample_order_seq` int(11) NULL DEFAULT NULL COMMENT '样品单号',
  `customer_seq` int(11) NULL DEFAULT NULL COMMENT '客户序号',
  `name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '姓名',
  `process` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工序',
  `process_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工序名称',
  `size` double NULL DEFAULT NULL COMMENT '尺码',
  `complete_time` timestamp NULL DEFAULT NULL COMMENT '完成日期',
  `is_delete` int(1) NULL DEFAULT 0 COMMENT '0：未删除  1：删除',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '产能回馈' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for package_packing
-- ----------------------------
DROP TABLE IF EXISTS `package_packing`;
CREATE TABLE `package_packing`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `enable` int(1) NULL DEFAULT 1 COMMENT '是否可用\r\n变更过的单据为不可用（0）',
  `status` int(2) NULL DEFAULT NULL COMMENT '0：待处理\r\n10：草稿\r\n11：提交\r\n12：中止\r\n20：审批通过',
  `is_updated` int(1) NULL DEFAULT 0 COMMENT '是否已变更（1：是；0：否）',
  `id` int(11) NULL DEFAULT NULL COMMENT 'mes装箱单id',
  `zx_dh` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '装箱单号',
  `po` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'po',
  `delivery_address` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收货地',
  `product_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品名称',
  `customer_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `customer_order` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户订单号',
  `season` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '季节',
  `production_directives` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '指令号',
  `color_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '颜色',
  `sku` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'sku',
  `firm_id` int(11) NULL DEFAULT NULL COMMENT '公司Id',
  `firm_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司',
  `warehouse_id` int(11) NULL DEFAULT NULL COMMENT '入库仓库id',
  `warehouse_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '入库仓库',
  `warehouse_category` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '入库仓库类别',
  `in_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '入库单号',
  `cj_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `cj_time` timestamp NULL DEFAULT NULL,
  `xg_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `xg_time` timestamp NULL DEFAULT NULL,
  `count` int(5) NULL DEFAULT NULL COMMENT '总箱数',
  `total` int(11) NULL DEFAULT NULL COMMENT '总双数',
  `art` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '型体',
  `original_seq` int(11) NULL DEFAULT NULL COMMENT '原始序号',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_nick_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_at` datetime NULL DEFAULT NULL,
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_nick_name` varchar(0) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_at` datetime NULL DEFAULT NULL,
  `deleted_nick_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人昵称',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除',
  `version` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `enable`(`enable`, `status`, `zx_dh`, `is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3981 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '装箱单' ROW_FORMAT = Dynamic;

