-- Table structure for package_packing_result_info
-- ----------------------------
DROP TABLE IF EXISTS `package_packing_result_info`;
CREATE TABLE `package_packing_result_info`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `package_packing_seq` int(11) NULL DEFAULT NULL COMMENT '装箱单序号',
  `package_packing_info_seq` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '装箱单明细序号',
  `no` int(11) NULL DEFAULT NULL,
  `id` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '外箱条码',
  `cm` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '包装尺寸',
  `xh` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '箱号',
  `packing_code` int(11) NULL DEFAULT NULL COMMENT '箱号',
  `po` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'po',
  `art_colour` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '型体颜色',
  `size_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '尺码',
  `sku` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'SKU',
  `total` varchar(11) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '总数量(箱数)',
  `num` int(10) NULL DEFAULT NULL COMMENT '每箱双数',
  `mkg` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '总毛用量',
  `jkg` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '总净用量',
  `way` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '装箱方式',
  `position_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位序号',
  `position_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位code',
  `position_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位名称',
  `processing` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '制程序号',
  `processing_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '制程名称',
  `material_category_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料简码序号',
  `material_category_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料简码',
  `material_category_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料名称',
  `material_category_unit_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料单位',
  `material_category_unit_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料单位名称',
  `provider_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料供应商',
  `provider_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商名称',
  `provider_type_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供方类型',
  `provider_type_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供方类型名称',
  `material_info_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `material_info_size` double NULL DEFAULT NULL,
  `material_info_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `material_info_colour` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `material_info_colour_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `material_info_is_match_size` double NULL DEFAULT NULL,
  `material_info_is_each_expend` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `material_info_is_out_sourcing` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `is_craft` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `ie_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `memo` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL,
  `is_updated` int(1) NULL DEFAULT 0 COMMENT '是否修改',
  `is_deleted` int(1) NULL DEFAULT 0,
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_at` datetime NULL DEFAULT NULL,
  `updated_by` varchar(155) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_at` datetime NULL DEFAULT NULL,
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_at` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 49858 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '装箱单结果明细' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for package_packing_size
-- ----------------------------
DROP TABLE IF EXISTS `package_packing_size`;
CREATE TABLE `package_packing_size`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `package_packing_seq` int(11) NULL DEFAULT NULL COMMENT '装箱单序号',
  `size_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '尺码',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 45568 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '装箱单尺码信息' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for package_packing_size_info
-- ----------------------------
DROP TABLE IF EXISTS `package_packing_size_info`;
CREATE TABLE `package_packing_size_info`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `package_packing_seq` int(11) NULL DEFAULT NULL COMMENT '装箱单序号',
  `package_packing_info_seq` int(11) NULL DEFAULT NULL COMMENT '装箱单明细序号',
  `size_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '尺码',
  `num` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '数量',
  `mkg` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '毛用量',
  `jkg` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '净用量',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 545224 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '装箱单明细尺码信息' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for package_packing_synchronize_records
-- ----------------------------
DROP TABLE IF EXISTS `package_packing_synchronize_records`;
CREATE TABLE `package_packing_synchronize_records`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `execute_at` timestamp NULL DEFAULT NULL COMMENT '执行时间',
  `start_time` timestamp NULL DEFAULT NULL COMMENT '数据时间范围起',
  `end_time` timestamp NULL DEFAULT NULL COMMENT '数据时间范围止',
  `operate_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '执行人',
  `status` int(1) NULL DEFAULT 1 COMMENT '状态',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1901 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '装箱单数据同步记录' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for payment_method
-- ----------------------------
DROP TABLE IF EXISTS `payment_method`;
CREATE TABLE `payment_method`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `bas_custom_seq` int(11) NULL DEFAULT NULL COMMENT '客户ID',
  `bas_supplier_seq` int(11) NULL DEFAULT NULL COMMENT '供应商ID',
  `pay_stage` int(11) NOT NULL COMMENT '结算阶段（填写，1,2,3....）',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '结算项目标识（从字典表dict_data中获取）',
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '结算项目',
  `ratio` decimal(10, 2) NOT NULL COMMENT '结算比例（填写1就是1%，不能超过100）',
  `source_table` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '来源表',
  `source_table_field` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '来源表字段',
  `plan_pay_cycle` int(11) NOT NULL COMMENT '计划结算周期 (单位天)',
  `plan_invoicing_cycle` int(11) NULL DEFAULT NULL COMMENT '预计开票周期(单位天)',
  `remark` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `status` int(11) NOT NULL DEFAULT 0 COMMENT '状态（0正常 1停用）',
  `is_delete` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否删除',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人名称',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人名称',
  `updated_at` datetime NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人名称',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 25 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '客户结算方式（已经废弃）' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for pdm_roll_store
-- ----------------------------
DROP TABLE IF EXISTS `pdm_roll_store`;
CREATE TABLE `pdm_roll_store`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT 'id',
  `store_order_no` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '转入单号',
  `busi_date` datetime NULL DEFAULT NULL COMMENT '入库时间',
  `printing_frequency` int(11) NULL DEFAULT 0 COMMENT '打印次数',
  `printing_date` datetime NULL DEFAULT NULL COMMENT '打印时间',
  `company_out_id` int(11) NOT NULL COMMENT '转出工厂',
  `company_out_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '转出工厂名称',
  `warehouse_out_id` int(11) NOT NULL COMMENT '转出仓库id',
  `warehouse_out_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '转出仓库名称',
  `company_in_id` int(11) NOT NULL COMMENT '转入工厂(公司)id',
  `company_in_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '转入工厂名称',
  `warehouse_in_id` int(11) NOT NULL COMMENT '转入仓库id',
  `warehouse_in_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '转入仓库名称',
  `memo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注说明',
  `status` char(2) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '状态',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除(0-否,1-是)',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `created_username` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `code` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '转仓出库单号',
  `warehouse_in_code` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '转入仓库code',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 124 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '转仓入库表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for pdm_roll_store_info
-- ----------------------------
DROP TABLE IF EXISTS `pdm_roll_store_info`;
CREATE TABLE `pdm_roll_store_info`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT 'id',
  `pdm_roll_store_seq` int(11) NULL DEFAULT NULL COMMENT '转仓入库表seq',
  `material_warehouse_out_info_seq` int(255) NULL DEFAULT NULL COMMENT '转出仓库明细id',
  `store_qty` decimal(11, 4) NULL DEFAULT NULL COMMENT '转入数量',
  `customer_seq` int(11) NOT NULL COMMENT '客户Seq',
  `customer_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '客户名称',
  `prod_order_seq` int(11) NULL DEFAULT NULL COMMENT '生成订单seq',
  `prod_order_code` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '指令单号',
  `provider_seq` int(11) NOT NULL COMMENT '供应商seq',
  `provider_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '供应商名称',
  `material_category_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料简码',
  `material_info_seq` int(11) NOT NULL COMMENT '物料编码主键',
  `material_info_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '物料编码',
  `material_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '物料名称',
  `color_code` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '颜色编码',
  `color_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料颜色',
  `size_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料尺码',
  `size_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '尺码',
  `unit_seq` int(11) NOT NULL COMMENT '物料单位seq',
  `unit_name` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料单位',
  `location_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '转出储位编号',
  `location_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '转出储位名称',
  `sku` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'sku',
  `memo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注说明',
  `quantity_to_be_transferred` decimal(14, 4) NULL DEFAULT 0.0000 COMMENT '待转数量',
  `position_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位seq',
  `position_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位code',
  `position_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位名称',
  `manual_prod_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '指令号',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '季度',
  `row_no` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '行标识',
  `customer_article_code` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户形体号',
  `location_seq` int(11) NULL DEFAULT NULL COMMENT '转出储位Seq',
  `unit_price` decimal(14, 4) NULL DEFAULT NULL COMMENT '含税单价',
  `store_price` decimal(14, 4) NULL DEFAULT NULL COMMENT '库存单价',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3610 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '转仓入库明细表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for po_advance_payment_pending
-- ----------------------------
DROP TABLE IF EXISTS `po_advance_payment_pending`;
CREATE TABLE `po_advance_payment_pending`  (
  `seq` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `contract_seq` bigint(20) NULL DEFAULT NULL COMMENT '来源单据ID (关联 po_order_contract.seq)',
  `contract_item_seq` bigint(20) NULL DEFAULT NULL COMMENT '来源单据明细seq(关联 po_order_item.seq)',
  `contract_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '订单合同号 (方便快速查询)',
  `company_seq` bigint(20) NULL DEFAULT NULL COMMENT '接单公司ID',
  `company_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '接单公司名称',
  `customer_seq` bigint(20) NULL DEFAULT NULL COMMENT '客户ID',
  `customer_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '客户名称 (冗余字段，加快列表展示)',
  `sku` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `row_no` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'po',
  `quantity` decimal(14, 4) NULL DEFAULT 0.0000 COMMENT '数量 (* 必填)',
  `unit_price` decimal(14, 4) NULL DEFAULT 0.0000 COMMENT '单价(含税)',
  `tax_unit_price` decimal(14, 4) NULL DEFAULT 0.0000 COMMENT '单价(不含税)',
  `deposit_ratio` decimal(14, 4) NULL DEFAULT 0.0000 COMMENT '定金比例',
  `po_amount` decimal(14, 4) NULL DEFAULT 0.0000 COMMENT 'PO金额',
  `deposit_amount` decimal(14, 4) NULL DEFAULT 0.0000 COMMENT '定金金额',
  `payment_status` int(2) NULL DEFAULT 0 COMMENT '收款状态: 0-待收款(未收), 1-部分收款, 2-已齐款(结案)',
  `created_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人 (通常为系统或提交合同的业务员)',
  `created_by_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人姓名',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间 (单据流入财务待处理的时间)',
  `update_at` datetime NULL DEFAULT NULL COMMENT '最新一次收款/更新的时间',
  `update_by` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `brand` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '品牌',
  `product_category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '产品类别',
  `status` int(2) NULL DEFAULT 0 COMMENT '处理状态(0未处理，1已处理）',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `idx_contract_no`(`contract_no`) USING BTREE,
  INDEX `idx_payment_status`(`payment_status`) USING BTREE,
  INDEX `contract_seq`(`contract_seq`) USING BTREE,
  INDEX `contract_item_seq`(`contract_item_seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 45 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '预收款待处理表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for po_defective_product
-- ----------------------------
DROP TABLE IF EXISTS `po_defective_product`;
CREATE TABLE `po_defective_product`  (
  `record_date` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '日期',
  `firm_id` int(11) NULL DEFAULT NULL COMMENT '公司Id',
  `firm_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司名称',
  `department_id` int(11) NULL DEFAULT NULL COMMENT '部门Id',
  `department_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部门名称',
  `group_id` int(11) NULL DEFAULT NULL COMMENT '组别Id',
  `group_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '组别名称',
  `process` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '制程名称',
  `check_num` double(13, 2) NULL DEFAULT NULL COMMENT '不良数量',
  `p_id` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '制程代号',
  UNIQUE INDEX `record_date`(`record_date`, `firm_id`, `department_id`, `group_id`, `p_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '品质不良数据' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for po_order_contract
-- ----------------------------
DROP TABLE IF EXISTS `po_order_contract`;
CREATE TABLE `po_order_contract`  (
  `seq` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `contract_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '合同编号',
  `order_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '订单号',
  `company_seq` bigint(20) NULL DEFAULT NULL COMMENT '接单公司ID',
  `company_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '接单公司名称',
  `customer_seq` bigint(20) NULL DEFAULT NULL COMMENT '客户 ID',
  `customer_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `total_amount` decimal(12, 2) NULL DEFAULT NULL COMMENT '合同总金额',
  `deposit_ratio` decimal(5, 2) NULL DEFAULT NULL COMMENT '定金比例',
  `deposit_status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '定金状态(0未交 1已申请 2已收)',
  `total_deposit` decimal(12, 2) NULL DEFAULT NULL COMMENT '合同总定金',
  `status` tinyint(4) NULL DEFAULT NULL COMMENT '状态: 0 = 草稿 / 暂存 1 = 已提交 2 = 作废',
  `delivery_date` date NULL DEFAULT NULL COMMENT '交期',
  `collection_flag` int(2) NULL DEFAULT NULL COMMENT '预收款标识: 0-未收款, 1-部分收款, 2-已齐款',
  `collected_amount` decimal(18, 4) NULL DEFAULT NULL COMMENT '累计预收款金额',
  `creater` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_time` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updater` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '更新人',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `submiter` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '提交人',
  `submit_time` datetime NULL DEFAULT NULL COMMENT '提交时间',
  `is_deleted` int(11) NULL DEFAULT 0 COMMENT '0=未删除, 1=已删除',
  `effective_date` date NULL DEFAULT NULL COMMENT '生效日期',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 385 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '订单合同主表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for po_order_item
-- ----------------------------
DROP TABLE IF EXISTS `po_order_item`;
CREATE TABLE `po_order_item`  (
  `seq` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `contract_seq` bigint(20) NULL DEFAULT NULL COMMENT '关联主表ID(erp_order_contract.id)',
  `po_collection_flag` int(2) NULL DEFAULT 0 COMMENT 'PO预收款标识',
  `po_collected_amount` decimal(18, 4) NULL DEFAULT NULL COMMENT 'PO预收款金额',
  `contract_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '合同号',
  `po_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'PO 号',
  `sku` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'SKU',
  `brand` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '品牌',
  `product_class_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '产品类别',
  `business_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '业务导单号',
  `instruction_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '指令号',
  `customer_order_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '客人订单号',
  `customer_model_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '客户型体号',
  `reconciliation_qty` int(11) NULL DEFAULT 0 COMMENT '对账数量',
  `reconciliation_price` decimal(10, 2) NULL DEFAULT 0.00 COMMENT '对账单价 (元)',
  `settle_qty` int(11) NULL DEFAULT 0 COMMENT '结算数量 (* 必填)',
  `settle_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '结算单价(元)(*必填)',
  `quantity` int(11) NULL DEFAULT NULL COMMENT '数量',
  `unit_price_tax` decimal(18, 4) NULL DEFAULT NULL COMMENT '含税单价',
  `unit_price_net` decimal(18, 4) NULL DEFAULT NULL COMMENT '不含税单价',
  `po_amount` decimal(12, 2) NULL DEFAULT NULL COMMENT '单 PO 金额',
  `po_total_amount` decimal(18, 4) NULL DEFAULT NULL COMMENT 'PO总金额(数量 * 含税单价)',
  `deposit_amount` decimal(12, 2) NULL DEFAULT 0.00 COMMENT '分摊到本 PO 的定金',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `is_placed` int(2) NULL DEFAULT 0 COMMENT '是否下单',
  `item_is_deleted` int(2) NULL DEFAULT 0 COMMENT '是否删除',
  `delivery_date` date NULL DEFAULT NULL COMMENT '成品交期',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `idx_contract_seq`(`contract_seq`) USING BTREE,
  INDEX `idx_contract_no`(`contract_no`) USING BTREE,
  INDEX `idx_po_no`(`po_no`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 475 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '订单 PO 明细表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
