-- ----------------------------
-- Table structure for position
-- ----------------------------
DROP TABLE IF EXISTS `position`;
CREATE TABLE `position`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `sys_dict_seq` int(11) NOT NULL COMMENT '所属类',
  `no` int(11) NULL DEFAULT NULL COMMENT '排序',
  `id` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '过滤值',
  `code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '代号',
  `name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '名称',
  `name_en` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '英文名称',
  `enable` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '1' COMMENT '是否可用',
  `is_used` int(11) NULL DEFAULT 0 COMMENT '是否使用',
  `is_deleted` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否删除',
  `processing` int(11) NULL DEFAULT NULL COMMENT '制程(制程维护)',
  `processing_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '制程名称',
  `material_type_seq` int(11) NULL DEFAULT NULL COMMENT '物料类型序号',
  `material_type_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料类型名称',
  `memo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `pull_mes` int(1) NULL DEFAULT 0 COMMENT '推送mes状态(0：未推送；1：推送成功；2：推送失败）',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '修改时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `created_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `code`(`code`) USING BTREE,
  INDEX `idx_positon`(`name`, `processing_name`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 6047 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '部位信息' ROW_FORMAT = DYNAMIC;

