  `apply_provider_id` int(11) NULL DEFAULT NULL COMMENT '申请供应商 ID',
  `apply_provider_name` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '申请供应商名称',
  `status` int(11) NOT NULL COMMENT '状态',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  `submit_at` datetime NULL DEFAULT NULL COMMENT '提交时间',
  `print_count` int(11) NOT NULL DEFAULT 0 COMMENT '打印次数',
  `is_deleted` tinyint(1) UNSIGNED NOT NULL DEFAULT 0 COMMENT '是否删除（0-否，1-是）',
  `created_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_by_name` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '创建人姓名',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `idx_code_unique`(`code`) USING BTREE,
  INDEX `idx_company_in_id`(`company_in_id`) USING BTREE,
  INDEX `idx_warehouse_code`(`warehouse_code`) USING BTREE,
