  `material_category_unit_name` varchar(32) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '物料基本单位',
  `size` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '尺码',
  `warehouse_quantity_in` decimal(18, 6) NOT NULL COMMENT '入库数量（不得大于申请数量）',
  `location_seq` int(11) NOT NULL DEFAULT 0 COMMENT '储位seq',
  `location_code` varchar(64) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '储位编号',
  `location_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '储位名称',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  `unit_price` decimal(10, 4) NULL DEFAULT 0.0000 COMMENT '单价',
  `store_price` decimal(18, 4) NULL DEFAULT NULL COMMENT '库存单价',
  `supplier_reconciliation_status` int(1) NULL DEFAULT 0 COMMENT '供应商对账状态',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '季度',
  `reconciliation_hold_seq` int(11) NULL DEFAULT NULL COMMENT '应付管理-对账挂起seq ',
  `reconciliation_hold_status` int(11) NULL DEFAULT 0 COMMENT '挂起状态：0==未挂起，1==挂起审核中，2==已挂起',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 13 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '手动入库单明细表' ROW_FORMAT = Dynamic;

