-- ----------------------------
-- Table structure for proc_material_change_todo
-- ----------------------------
DROP TABLE IF EXISTS `proc_material_change_todo`;
CREATE TABLE `proc_material_change_todo`  (
  `seq` int(10) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键序列',
  `change_code` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '变更单号（生产订单变更/包材变更）',
  `change_source` int(11) NOT NULL COMMENT '变更来源',
  `change_record_seq` int(11) NULL DEFAULT NULL COMMENT '变更记录seq',
  `change_record_info_seq` int(11) NULL DEFAULT NULL COMMENT '变更明细记录seq',
  `business_type` int(11) NOT NULL COMMENT '变更业务类型（1.原材料采购单；2.委外加工单）',
  `business_seq` int(11) NOT NULL COMMENT '业务seq',
  `business_info_seq` int(11) NOT NULL COMMENT '业务明细seq',
  `business_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '业务单号',
  `sku` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'sku',
  `customer_seq` int(11) NOT NULL COMMENT '订单客户seq',
  `customer_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '订单客户名称',
  `company_id` int(11) NOT NULL COMMENT '公司ID',
  `company_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '公司名称',
  `provider_seq` int(11) NOT NULL COMMENT '供应商seq',
  `provider_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '供应商名称',
  `procurement_seq` int(11) NOT NULL COMMENT '采购需求Seq',
  `procurement_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '采购需求单号',
  `manual_prod_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '指令号',
  `prod_order_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '生产订单号',
  `row_no` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'po',
  `quarter_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '季度',
  `position_seq` int(11) NOT NULL COMMENT '部件序号',
  `position_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '部位编号',
  `position_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '部位名称',
  `material_category_seq` int(11) NOT NULL COMMENT '物料简码序号',
  `material_category_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '物料简码',
  `material_category_name` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '物料简码名称',
  `material_category_unit_seq` int(11) NULL DEFAULT NULL COMMENT '物料简码单位序号',
  `material_category_unit_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '物料简码单位名称',
  `material_info_seq` int(11) NOT NULL COMMENT '物料编码seq',
  `material_info_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '物料编码',
  `material_info_colour` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '物料编码颜色编码',
  `material_info_colour_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '物料编码颜色名称',
  `size` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL COMMENT '尺码',
  `old_need_quantity` decimal(19, 4) NOT NULL COMMENT '原需求数量',
  `old_procurement_quantity` decimal(19, 4) NOT NULL COMMENT '原采购数量',
  `new_need_quantity` decimal(19, 4) NOT NULL COMMENT '现需求数量',
  `new_procurement_quantity` decimal(19, 4) NOT NULL COMMENT '现采购数量',
  `change_date` datetime NOT NULL COMMENT '变更日期',
  `change_by_user` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '变更人',
  `change_reason` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '变更原因',
  `change_remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '变更明细备注',
  `maintain_remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '维持原单原因',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `status` int(11) NOT NULL DEFAULT 0 COMMENT '确认状态（0未确认；1已确认；2维持原单）',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否删除（0未删除；1已删除）',
  `create_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `updated_by` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '更新用户',
  `updated_user_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '更新用户ID',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 74325 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '采购变更待办表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for proc_material_list
-- ----------------------------
DROP TABLE IF EXISTS `proc_material_list`;
CREATE TABLE `proc_material_list`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购单号',
  `procurement_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购类型',
  `sum_price` varchar(12) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '含税金额',
