  INDEX `idx_seq_is_deleted`(`seq`, `is_deleted`) USING BTREE,
  INDEX `idx_code`(`code`) USING BTREE,
  INDEX `idx_receiving_company`(`receiving_company`) USING BTREE,
  INDEX `idx_pa_filter`(`is_deleted`, `seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 8124 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '物料采购单' ROW_FORMAT = DYNAMIC;

