  INDEX `proc_material_list_info_manual_prod_code_IDX`(`manual_prod_code`, `row_no`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 547893 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '采购订单详情' ROW_FORMAT = DYNAMIC;

