DROP TABLE IF EXISTS `proc_material_list_info_size_dosage`;
CREATE TABLE `proc_material_list_info_size_dosage`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `proc_material_list_seq` int(11) NULL DEFAULT NULL COMMENT '采购单序号',
  `proc_material_list_info_seq` int(11) NULL DEFAULT NULL COMMENT '采购单明细序号',
  `proc_material_procurement_seq` int(11) NULL DEFAULT NULL COMMENT '采购需求计划单序号',
  `proc_material_procurement_info_seq` int(11) NULL DEFAULT NULL COMMENT '采购需求计划单明细序号',
  `key` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'key',
  `each_expend` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '用量',
  `change_num` decimal(12, 4) NULL DEFAULT NULL COMMENT '变更数量',
  `unused_storage` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '剩余可用量',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `idx_dosage`(`proc_material_list_seq`, `proc_material_list_info_seq`, `key`) USING BTREE,
  INDEX `idx_proc_material_list_seq_info_key`(`proc_material_list_seq`, `proc_material_list_info_seq`, `key`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 127616 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '采购单明细部位各码总用量' ROW_FORMAT = Dynamic;

