  `remarks` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `first_delivery_at` datetime NULL DEFAULT NULL,
  `end_delivery_at` datetime NULL DEFAULT NULL COMMENT '最后交期',
