  `first_confirm_date` date NULL DEFAULT NULL COMMENT '第一次交期',
  `second_confirm_date` date NULL DEFAULT NULL COMMENT '第二次交期',
  `third_confirm_date` date NULL DEFAULT NULL COMMENT '第三次交期',
