  `price_date` datetime NULL DEFAULT NULL COMMENT '单价更新时间',
  `order_quarter_code` int(11) NULL DEFAULT NULL COMMENT '下单季度编号',
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `idx_seq`(`seq`) USING BTREE,
  INDEX `version_index`(`version`) USING BTREE,
  INDEX `idx_t_filter`(`is_deleted`, `created_at`, `purchase_unit_price`, `provider_seq`, `mx_material_category_seq`) USING BTREE,
  INDEX `idx_mat_seq`(`proc_material_list_seq`, `mx_material_category_code`, `mx_material_info_code`, `is_deleted`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 339257 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '采购订单详情汇总' ROW_FORMAT = Dynamic;

