  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `picking_division` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '领料部门',
  `picking_factory_id` int(11) NULL DEFAULT NULL COMMENT '领料工厂id',
  `created_by_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '昵称',
  `factory_id` int(11) NULL DEFAULT NULL,
  `requisition_factory_id` int(11) NULL DEFAULT NULL COMMENT '发料工厂',
  `requisition_factory` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '发料工厂',
  `warehouse_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库code',
  `picking_division_id` int(255) NULL DEFAULT NULL COMMENT '领料部门id',
  `group_id` int(11) NULL DEFAULT NULL COMMENT '组别id',
  `group_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '组别名称',
  `outbound_type_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '出库类型名称',
  `other_factory_id` int(11) NULL DEFAULT NULL,
  `other_factory_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `other_division_id` int(11) NULL DEFAULT NULL,
  `other_division_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `other_team_id` int(11) NULL DEFAULT NULL,
  `other_team_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 15100 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '材料出库' ROW_FORMAT = Dynamic;

