-- ----------------------------
-- Table structure for proc_material_out_process_order
-- ----------------------------
DROP TABLE IF EXISTS `proc_material_out_process_order`;
CREATE TABLE `proc_material_out_process_order`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '委外加工单号',
  `procurement_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购类型',
  `sum_price` varchar(12) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '含税金额',
  `excluding_tax_price` varchar(12) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '不含税金额',
  `tax_price` varchar(12) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '税率',
  `mx_material_category_provider_seq` int(11) NULL DEFAULT NULL COMMENT '物料供应商',
  `mx_material_category_provider_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料供应商',
  `payment_terms` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '付款条件',
  `payment_method` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '付款方式',
  `contract_currency` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '合同币别',
  `supplier_contact_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商联系人姓名',
  `currency_rate` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '币种汇率',
  `phone` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '电话',
  `purchaser` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购人信息',
  `receiving_company_id` int(11) NULL DEFAULT NULL,
  `receiving_company` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收料公司',
  `receiving_warehouse` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收料仓库',
  `receiving_contacts` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收料联系人',
  `invoice_contacts` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '发票联系人',
  `demand_department` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '需求部门',
  `receiving_address_abb` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收料地址简称',
  `receiving_contacts_phone` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收料联系人电话',
  `invoice_contacts_phone` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '发票联系人电话',
  `purchase_date` datetime NULL DEFAULT NULL COMMENT '采购日期',
  `invoice_address_abb` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '发票地址简称',
  `current_account` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '往来账户',
  `receiving_address` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收料地址',
  `invoice_address` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '发票地址',
  `remark` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `contract_text` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '合同文本',
  `status` int(255) NULL DEFAULT 0 COMMENT '状态(0暂存，1提交，27作废)',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除',
  `first_delivery_at` datetime NULL DEFAULT NULL COMMENT '首件交货日期',
  `latest_delivery_at` datetime NULL DEFAULT NULL COMMENT '最晚交货日期',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `created_by_name` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人名称',
  `change_type` int(11) NULL DEFAULT NULL COMMENT '变更类型 1修改 2删除 3新增, 4数量变更, 5数量增加, 6数量减少',
  `mx_material_category_is_match_size` int(11) NULL DEFAULT NULL COMMENT '是否配码',
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `codeIdx`(`code`) USING BTREE,
  INDEX `idx_seq_is_deleted`(`seq`, `is_deleted`) USING BTREE,
  INDEX `idx_code`(`code`) USING BTREE,
  INDEX `idx_receiving_company`(`receiving_company`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 2428 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '物料委外加工单' ROW_FORMAT = DYNAMIC;

