  `return_factory_date` datetime NULL DEFAULT NULL COMMENT '回厂日期',
  `check_and_accept_number` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '验收单号',
