  `sending_at` datetime NULL DEFAULT NULL COMMENT '发货时间',
  `release_at` datetime NULL DEFAULT NULL COMMENT '上线时间',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `receiving_warehouse_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库编号',
  `receiving_warehouse_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库名称',
  `proc_material_status_monitor_info_seq` int(11) NULL DEFAULT NULL COMMENT '采购需求计划的状态监控表seq',
  `od_product_order_order_position_seq` int(11) NULL DEFAULT NULL COMMENT '生产订单与部位关联表seq',
  `seq_string` varchar(2000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `size` varchar(1000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `size_dosage_map` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL,
  `out_process_order_subtotal_seq` int(255) NULL DEFAULT NULL,
  `proc_material_list_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '委外加工单号',
  `purchase_unit_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '采购单价',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '季节编号',
  `location_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '储位',
  `location_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '储位',
  `remaining_quantity` decimal(13, 4) NULL DEFAULT NULL COMMENT '暂收剩余量',
  `inspection_remaining_quantity` decimal(13, 4) NULL DEFAULT NULL COMMENT '品检剩余量',
  `inv_remaining_quantity` decimal(13, 4) NULL DEFAULT NULL COMMENT '入库剩余量',
  `warehouse_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库编码',
  `warehouse_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库名称',
  `change_type` int(11) NULL DEFAULT NULL COMMENT '变更类型 1修改 2删除 3新增, 4数量变更, 5数量增加, 6数量减少',
  `change_num` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '变更数量',
  `has_dispose` int(11) NULL DEFAULT NULL COMMENT '是否处理异常数据 1已处理 ',
  `inquiry_price_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价单号',
  `price_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单价更新人',
  `price_date` datetime NULL DEFAULT NULL COMMENT '单价更新时间',
  `order_quarter_code` int(11) NULL DEFAULT NULL COMMENT '下单季度编号',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `idx_out_process_order_seq`(`out_process_order_seq`) USING BTREE,
  INDEX `idx_product_order_code`(`product_order_code`) USING BTREE,
  INDEX `idx_mx_material_info_code`(`mx_material_info_code`) USING BTREE,
  INDEX `proc_material_out_process_order_info_uuid_index`(`uuid`) USING BTREE,
  INDEX `idx_proc_material_procurement_info_seq`(`proc_material_procurement_info_seq`) USING BTREE,
  INDEX `idx_out_process_order_subtotal_seq`(`out_process_order_subtotal_seq`) USING BTREE,
  INDEX `idx_mx_material_category_seq_IDX`(`mx_material_category_seq`) USING BTREE,
  INDEX `idx_new`(`proc_material_procurement_code`, `mx_material_info_code`, `position_code`, `position_name`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 96249 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '材料外加工单_详情' ROW_FORMAT = DYNAMIC;

