-- ----------------------------
-- Table structure for proc_material_out_process_temporarily_receiving
-- ----------------------------
DROP TABLE IF EXISTS `proc_material_out_process_temporarily_receiving`;
CREATE TABLE `proc_material_out_process_temporarily_receiving`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `receiving_materials_numbers` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收料单号',
  `is_quality_inspection` int(1) NULL DEFAULT 0 COMMENT '是否品检',
  `is_appearance_quality_inspection` int(1) NULL DEFAULT 0 COMMENT '是否外观品检',
  `receiving_date` datetime NULL DEFAULT NULL COMMENT '收货日期',
  `provider_seq` int(11) NULL DEFAULT NULL COMMENT '供应商seq',
  `provider_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商名称',
  `receiving_factory_id` int(11) NULL DEFAULT NULL COMMENT '收料工厂id',
  `receiving_factory` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收料工厂',
  `consignee` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收货人',
  `receiving_department` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收货部门',
  `receiving_warehouse` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收料仓库',
  `is_attached_receipt` int(1) NULL DEFAULT 0 COMMENT '附收货回单',
  `is_attached_inspection_report` int(1) NULL DEFAULT 0 COMMENT '附验货报告',
  `is_attached_accessories` int(1) NULL DEFAULT 0 COMMENT '附搭配件',
  `is_attached_invoice` int(1) NULL DEFAULT 0 COMMENT '附发票',
  `batch_number` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '批号',
  `status` char(2) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '状态',
  `remarks` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除(0-否,1-是)',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `upstream_status` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '上游状态',
  `is_receive_again` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否再次接收',
  `created_by_name` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人名称',
  `zs_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购暂收、委外加工单暂收、采购品检不良退暂收、委外加工单品检不良退暂收',
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `codeIdx`(`receiving_materials_numbers`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 7803 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '加工材料暂收' ROW_FORMAT = DYNAMIC;

