  INDEX `formal_order_code`(`formal_order_code`, `sku`, `art_quarter_code`, `company_name`) USING BTREE,
  INDEX `idx_ppa_filter`(`row_no`, `is_deleted`, `process_status`, `seq`) USING BTREE
