  `mx_material_category_group_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料分组名称',
  `mx_material_category_unit_seq` int(11) NULL DEFAULT NULL COMMENT '物料单位序号',
  `mx_material_category_unit_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料单位名称',
  `mx_material_category_provider_seq` int(11) NULL DEFAULT NULL COMMENT '物料默认供应商seq',
  `mx_material_category_provider_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料默认供应商',
  `mx_material_category_is_exempt_verify` int(1) NULL DEFAULT 0 COMMENT '物料是否免检(0-否,1-是)',
  `mx_material_category_is_out_sourcing` int(1) NULL DEFAULT 0 COMMENT '物料是否外发加工(0-否,1-是)',
  `mx_material_category_is_each_expend` int(1) NULL DEFAULT NULL COMMENT '是否码段用量',
  `mx_material_category_is_match_size` int(1) NULL DEFAULT NULL COMMENT '是否配码',
  `mx_material_category_is_color_constraint` int(1) NULL DEFAULT 0 COMMENT '物料是否颜色约束',
  `mx_material_category_money_type_seq` int(11) NULL DEFAULT NULL COMMENT '物料币种id',
  `mx_material_category_money_type_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料币种名称',
  `mx_material_category_purchase_unit_seq` int(11) NULL DEFAULT NULL COMMENT '物料采购单位id',
  `mx_material_category_purchase_unit_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料采购单位名称',
  `mx_material_category_purchase_convert_rate1` varchar(18) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购转换比率（比值）',
  `mx_material_category_purchase_convert_rate` decimal(18, 4) NULL DEFAULT NULL COMMENT '物料采购转换比率',
  `mx_material_category_provider_type_seq` int(11) NULL DEFAULT NULL COMMENT '物料供方id',
  `mx_material_category_provider_type_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料供方类型',
  `mx_material_category_purchase_hit_rate` decimal(18, 4) NULL DEFAULT NULL COMMENT '物料采购打大率',
  `mx_material_category_many_purchase_rate` decimal(18, 4) NULL DEFAULT NULL COMMENT '物料允许多采比率',
  `mx_material_category_many_receive_rate` decimal(18, 4) NULL DEFAULT NULL COMMENT '物料允许多收比率',
  `storage` double(13, 4) NULL DEFAULT NULL COMMENT '需求数量（物料各尺码正式订单数量总和）',
  `system_calculation_quantity` double(13, 4) NULL DEFAULT NULL COMMENT '系统计算最大采购量\r\n（需求数量+需求数量*采购大大率）',
  `unused_storage` double(13, 4) NULL DEFAULT NULL COMMENT '剩余需求数量（系统计算最大采购量-计划数量）',
  `plan_storage` double(13, 4) NULL DEFAULT NULL COMMENT '计划数量（页面输入各尺码计划数量总和）默认等于需求数量',
  `basic_quantity` double(13, 4) NULL DEFAULT NULL COMMENT '基本单位数量',
  `status` char(2) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '状态\r\n（0：草稿\r\n10：提交\r\n61：审批完成\r\n62：部分创建采购单\r\n63：全部创建采购单\r\n64：部分创建委外加工单\r\n65：全部创建委外加工单）',
  `size_key` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '尺码',
  `order_size` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '正式订单下单尺码',
  `change_type` int(11) NULL DEFAULT NULL COMMENT '变更类型 1修改 2删除 3新增, 4数量变更, 5数量增加, 6数量减少',
  `memo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注说明',
  `size_category` int(1) UNSIGNED ZEROFILL NULL DEFAULT 0 COMMENT '尺码类别(0-全,1-左,2右)',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除(0-否,1-是)',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `material_replenishment_seq` int(11) NULL DEFAULT NULL COMMENT '采购类型序号（字典表序号）存code',
  `material_replenishment_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `art_customer_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名',
  `art_customer_seq` int(11) NULL DEFAULT NULL COMMENT '客户seq',
  `art_product_class_name` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品类别',
  `receiving_warehouse_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库编号',
  `receiving_warehouse_name` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库名称',
  `end_delivery_date` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '交期',
  `version` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '版本(包材)',
  `before_status` varchar(3) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '终止前的状态',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `material_procurement_foregin_key`(`proc_material_procurement_seq`) USING BTREE,
  INDEX `uuid_index`(`uuid`) USING BTREE,
  INDEX `manual_prod_code_index`(`manual_prod_code`) USING BTREE,
  INDEX `idx_code_position_color`(`proc_material_procurement_code`, `position_code`, `position_name`, `mx_material_info_code`) USING BTREE,
  INDEX `product_order_code`(`product_order_code`, `position_code`) USING BTREE,
  INDEX `idx_ppinfo_filter`(`proc_material_procurement_seq`, `is_deleted`, `change_type`, `position_name`, `manual_prod_code`, `mx_material_info_code`, `storage`) USING BTREE,
  CONSTRAINT `material_procurement_foregin_key` FOREIGN KEY (`proc_material_procurement_seq`) REFERENCES `proc_material_procurement` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 3761939 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '采购需求计划物料详情' ROW_FORMAT = DYNAMIC;

