  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '品检单号',
  `test_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '品检员',
  `test_by_username` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '品检员账号',
  `test_department_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '品检部门',
  `test_department_seq` int(11) NULL DEFAULT NULL COMMENT '品检部门序号',
  `record_status` int(11) NULL DEFAULT 0 COMMENT '品检记录状态',
  `test_date` datetime NULL DEFAULT NULL COMMENT '品检日期',
  `inspection_standards` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '检验标准',
  `inspection_standards_seq` int(11) NULL DEFAULT NULL COMMENT '检验标准序号',
  `inspection_results` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '检验结果',
  `inspection_results_seq` int(11) NULL DEFAULT NULL COMMENT '检验结果序号',
