  `status` char(2) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '状态',
  `memo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注说明',
  `is_deleted` tinyint(1) NULL DEFAULT 0 COMMENT '是否删除（0：未删除 1：删除）',
  `enable` tinyint(1) NULL DEFAULT NULL COMMENT '是否可用',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建日期',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_by_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人名称',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `upstream_status` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '上游状态',
  `receiving_factory_id` int(11) NULL DEFAULT NULL COMMENT '收料工厂id',
  `receiving_factory` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收料工厂',
  `is_out_sourcing` int(11) NULL DEFAULT NULL COMMENT '0，原材料；1外加工',
  `is_unispection_inv` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '不合格品是否入库',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 20891 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '原材料品检' ROW_FORMAT = Dynamic;

