  `created_at` datetime NULL DEFAULT NULL COMMENT '创建日期',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `size_category` int(11) NULL DEFAULT NULL COMMENT '尺码类别',
  `purchase_order_number` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购单号',
  `inspection_unit_price` decimal(12, 4) NULL DEFAULT NULL COMMENT '品检单价',
  `art_customer_seq` int(11) NULL DEFAULT NULL COMMENT '客户序号',
  `art_customer_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `warehouse_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库编号',
  `warehouse_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库名称',
  `location_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '储位编号',
  `location_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '储位名称',
  `delivery_note_number` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '送货单号',
  `batch_number` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '送货批次号',
  `receiving_materials_quantity` decimal(11, 4) NULL DEFAULT NULL COMMENT '计划品检数量',
  `treat_inspection_quantity` decimal(11, 4) NULL DEFAULT NULL COMMENT '待品检的数量',
  `return_materials_number` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '退料单号',
  `mx_material_info_seq` int(11) NULL DEFAULT NULL COMMENT '物料seq',
  `mx_material_info_colour_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料颜色',
  `art_customer_article_code` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '客户型体',
  `size` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `sku` varchar(2000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `mx_material_category_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '简码 seq',
  `mx_material_info_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '简码 seq',
  `mx_material_category_seq` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料简码',
  `provider_seq` int(11) NULL DEFAULT NULL COMMENT '供应商',
  `provider_name` varchar(1000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商',
  `is_out_sourcing` smallint(6) NULL DEFAULT 0 COMMENT '是否委外单',
  `actual_unqualified_quantity` decimal(11, 2) NULL DEFAULT 0.00 COMMENT '实际不合格数量',
  `is_unispection_inv` int(11) NULL DEFAULT 0 COMMENT '不合格品是否退供应商',
  `manual_prod_code` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '手工排产单号',
  `position_name` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位昵称',
