-- ----------------------------
-- Table structure for proc_material_requisition
-- ----------------------------
DROP TABLE IF EXISTS `proc_material_requisition`;
CREATE TABLE `proc_material_requisition`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `please_material_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '领料单号',
  `please_material_division` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '请料部门',
  `picking_type` int(11) NULL DEFAULT NULL COMMENT '领料类型1车间领料出库 ；2加工材料出库；3转仓出库',
  `please_material_date` datetime NULL DEFAULT NULL COMMENT '请料日期',
  `please_material_people` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '请料人',
  `please_material_factory_id` int(11) NULL DEFAULT NULL,
  `please_material_factory` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '请料工厂',
  `material_warehouse` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '发料仓库',
  `please_material_workshop` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '请料车间',
  `require_issue_date` datetime NULL DEFAULT NULL COMMENT '要求发料日期',
