  `source` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '来源',
  `remarks` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `is_effective` int(1) NULL DEFAULT 0 COMMENT '是否可用(0-否,1-是)',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除(0-否,1-是)',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `upstream_status` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '上游状态',
  `created_by_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '昵称',
  `requisition_factory_id` int(11) NULL DEFAULT NULL COMMENT '发料工厂',
  `requisition_factory` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '发料工厂',
  `picking_type_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '类型名称',
  `please_material_division_id` int(11) NULL DEFAULT NULL COMMENT '请料部门',
  `workshop_team_id` int(11) NULL DEFAULT NULL COMMENT '车间小组',
  `please_material_workshop_id` int(11) NULL DEFAULT NULL COMMENT '请料车间',
  `requisition_warehouse_id` int(11) NULL DEFAULT NULL COMMENT '发料仓库code',
  `requisition_warehouse` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '发料仓库',
  `busi_user_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '经办人',
  `requisition_warehouse_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '发料仓库code',
  `other_factory_id` int(11) NULL DEFAULT NULL,
  `other_factory_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `other_division_id` int(11) NULL DEFAULT NULL,
  `other_division_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `other_team_id` int(11) NULL DEFAULT NULL,
  `other_team_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `other_picking_type` int(11) NULL DEFAULT NULL,
