  `delivery_note_number` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '送货单号',
  `batch_number` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '送货批次号',
  `source` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '来源单号（材料暂收单、委外暂收单）',
  `art_customer_article_code` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '客户型体号',
  `od_prod_order_code` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '生产订单号',
  `manual_prod_code` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '手工排产单号',
  `od_order_doc_code` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '正式订单号',
