  `provider_seq` int(255) NULL DEFAULT NULL COMMENT '供应商seq',
  `provider_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商名称',
  `is_out_sourcing` int(2) NULL DEFAULT 0 COMMENT '1\\0\\2',
