  `mx_material_info_colour_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料颜色',
  `art_customer_seq` int(255) NULL DEFAULT NULL,
  `art_customer_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名',
  `test_date` datetime NULL DEFAULT NULL COMMENT '检测日期',
