  `location_seq` int(11) NULL DEFAULT NULL COMMENT '储位seq',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '季度',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `od_product_order_order_position_seq`(`business_seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 251857 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '材料入库待办表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
