DROP TABLE IF EXISTS `proc_process_statement`;
CREATE TABLE `proc_process_statement`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `account_payable_order` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '应付款单号',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商编码',
