  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `is_check` int(11) NULL DEFAULT 1 COMMENT '是否确认1是0否',
  `manual_prod_code` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '指令号',
  `po` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'po',
  `color_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '颜色',
  `size` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '尺码',
  `produce_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '生产订单号',
  `node` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '节点',
  `part_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位',
  `parts` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位',
  `pid` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '制程',
  `wf_dispatch_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '外发单号',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '供应商对账明细' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for proc_supplier_statement
-- ----------------------------
DROP TABLE IF EXISTS `proc_supplier_statement`;
CREATE TABLE `proc_supplier_statement`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `account_payable_order` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '应付款单号',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商编码',
  `name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商名称',
  `payment_currency` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '付款币种',
  `payment_method` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '付款方式',
  `payment_terms` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '付款账期',
  `current_account` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '往来账户',
  `payment_amount` decimal(12, 2) NULL DEFAULT NULL COMMENT '付款金额',
  `receiving_factory` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '收料工厂',
  `is_available` int(1) NULL DEFAULT 1 COMMENT '是否可用',
  `status` int(1) NULL DEFAULT 0 COMMENT '对账状态(0供应商暂存，1供应商提交 2财务暂存，3财务确认）',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除(0-否,1-是)',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `settlement_amount` decimal(12, 2) NULL DEFAULT NULL COMMENT '结算金额',
  `customer_seq` int(11) NULL DEFAULT NULL COMMENT '客户seq',
  `custom_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `supplier_seq` int(11) NULL DEFAULT NULL COMMENT '供应商seq',
  `created_by_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人名称',
  `receiving_factory_id` int(11) NULL DEFAULT NULL COMMENT '收料工厂id',
  `accounting_month` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '记账月份',
  `warehousing_month` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '入库月份',
  `estimated_payment_month` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '预计付款月份',
  `remarks` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `tax_return_path` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '纳税申报附件地址',
  `tax_return_file_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '纳税申报附件名',
  `tax_payment_certificate_path` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '完税凭证附件地址',
  `tax_payment_certificate_file_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '完税凭证附件名',
  `certificate_no_tax_arrears_path` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '无欠税证明附件地址',
  `certificate_no_tax_arrears_file_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '无欠税证明附件名',
  `annual_tax_rating` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '年度纳税等级',
  `purchase_order_number` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '采购单号',
  `warehouse_entry_number` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '入库单号',
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `idx_unique_code`(`account_payable_order`) USING BTREE,
  INDEX `idx_factory_customer_suq_seq`(`receiving_factory`, `customer_seq`, `supplier_seq`) USING BTREE,
  INDEX `created_at`(`created_at`) USING BTREE,
  INDEX `status_is_deleted_created_at`(`created_at`, `is_deleted`, `status`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1180 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '供应商对账单' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for proc_supplier_statement_deduction
-- ----------------------------
DROP TABLE IF EXISTS `proc_supplier_statement_deduction`;
CREATE TABLE `proc_supplier_statement_deduction`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `supplier_statement_seq` int(11) NULL DEFAULT NULL COMMENT '供应商对账表主键',
  `deduction_items` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '扣款项目',
  `amount` decimal(12, 2) NULL DEFAULT NULL COMMENT '金额',
  `deduction_explanation` varchar(2000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '扣款说明',
  `is_deduction_first` int(11) NULL DEFAULT NULL COMMENT '是否先扣款再扣%',
  `attachment` varchar(2000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '附件',
  `attachment_name` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '附件名称',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除(0-否,1-是)',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 15 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '供应商对账扣款费用' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for proc_supplier_statement_deduction_attachment
-- ----------------------------
DROP TABLE IF EXISTS `proc_supplier_statement_deduction_attachment`;
CREATE TABLE `proc_supplier_statement_deduction_attachment`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `supplier_statement_seq` int(11) NULL DEFAULT NULL COMMENT '供应商对账表主键',
  `supplier_statement_deduction_seq` int(11) NULL DEFAULT NULL COMMENT '供应商对账扣款主键',
  `attachment` varchar(2000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '附件',
  `attachment_name` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '附件名称',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除(0-否,1-是)',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 10 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '供应商对账扣款费用附件' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for proc_supplier_statement_info
-- ----------------------------
DROP TABLE IF EXISTS `proc_supplier_statement_info`;
CREATE TABLE `proc_supplier_statement_info`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `supplier_statement_seq` int(11) NULL DEFAULT NULL COMMENT '供应商对账表主键',
  `warehousing_seq` int(11) NULL DEFAULT NULL COMMENT '入库单seq',
  `sku` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'sku',
  `customer_seq` int(11) NULL DEFAULT NULL COMMENT '客户seq',
  `custom_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `material_name` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料名称',
  `material_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码',
  `material_info_seq` int(11) NULL DEFAULT NULL COMMENT '物料编码主键',
  `material_info_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料信息编码',
  `unit` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单位',
  `purchase_order_number` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购单号',
  `warehouse_entry_number` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '入库单号',
  `warehouse_entry_date` datetime NULL DEFAULT NULL COMMENT '入库时间',
  `delivery_note_number` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '送货单号',
  `purchase_convert_rate` decimal(13, 4) NULL DEFAULT NULL COMMENT '采购转换比率',
  `purchase_unit` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购单位',
  `warehouse_accounting_quantity` decimal(13, 4) NULL DEFAULT NULL COMMENT '入库记账数量',
  `warehouse_unit_price` decimal(13, 4) NULL DEFAULT NULL COMMENT '入库单价',
  `warehouse_amount` decimal(13, 4) NULL DEFAULT NULL COMMENT '入库金额',
  `supplier_statement_number` decimal(13, 4) NULL DEFAULT NULL COMMENT '供应商对账数量',
  `supplier_statement_unit_price` decimal(13, 4) NULL DEFAULT NULL COMMENT '供应商对账单价',
  `settlement_quantity` decimal(13, 4) NULL DEFAULT NULL COMMENT '结算数量',
  `settlement_unit_price` decimal(13, 4) NULL DEFAULT NULL COMMENT '结算单价',
  `settlement_amount` decimal(13, 4) NULL DEFAULT NULL COMMENT '结算金额',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '季节号',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除(0-否,1-是)',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `is_check` int(11) NULL DEFAULT 0 COMMENT '是否确认1是0否',
  `manual_prod_code` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '指令号',
  `po` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'po',
  `color_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '颜色',
  `size` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '尺码',
  `data_type` int(11) NULL DEFAULT 0 COMMENT '来源(0入库单， 1出库单)',
  `is_reconciliation_check` int(11) NULL DEFAULT 0 COMMENT '对账确认1是0否',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `warehousing_seq`(`warehousing_seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 261814 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '供应商对账明细' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for proc_supplier_statement_otherfees
-- ----------------------------
DROP TABLE IF EXISTS `proc_supplier_statement_otherfees`;
CREATE TABLE `proc_supplier_statement_otherfees`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `supplier_statement_seq` int(11) NULL DEFAULT NULL COMMENT '对账单主键',
  `proc_material_list_seq` int(11) NULL DEFAULT NULL COMMENT '采购订单主键',
  `otherfees_seq` int(11) NULL DEFAULT NULL COMMENT '其他费用主键',
  `items` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '项目',
  `amount` decimal(12, 4) NULL DEFAULT NULL COMMENT '金额',
  `remark` varchar(2000) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '说明',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_by_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `proc_material_list_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '采购单号',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 77 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '对账其他费用' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for procurement_sample
-- ----------------------------
DROP TABLE IF EXISTS `procurement_sample`;
CREATE TABLE `procurement_sample`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `procurement_seq` int(11) NOT NULL COMMENT '外键',
  `article_seq` int(11) NULL DEFAULT NULL COMMENT '型体表序号',
  `sample_seq` int(11) NULL DEFAULT NULL COMMENT '样品表序号',
  `is_delete` int(2) NULL DEFAULT 0 COMMENT '是否删除（0：未删除 1：删除）',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `procurement_sample_foregin_key`(`procurement_seq`) USING BTREE,
  CONSTRAINT `procurement_sample_foregin_key` FOREIGN KEY (`procurement_seq`) REFERENCES `proc_material_procurement_info` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '物料型体样品关联表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for procurement_terms
-- ----------------------------
DROP TABLE IF EXISTS `procurement_terms`;
CREATE TABLE `procurement_terms`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `item` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '内容',
  `create_by` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `create_date` date NULL DEFAULT NULL COMMENT '创建时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '采购条款' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for prompt_information
-- ----------------------------
DROP TABLE IF EXISTS `prompt_information`;
CREATE TABLE `prompt_information`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `id` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '状态码',
  `memo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '提示信息' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for prompt_information_info
-- ----------------------------
DROP TABLE IF EXISTS `prompt_information_info`;
CREATE TABLE `prompt_information_info`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `prompt_information_seq` int(11) NULL DEFAULT NULL COMMENT '提示信息序号',
  `type` varchar(3) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '语言类型\r\n1：中文\r\n2：英语\r\n3：越南语',
  `content` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '提示信息',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '提示信息详情' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for purchases
-- ----------------------------
DROP TABLE IF EXISTS `purchases`;
CREATE TABLE `purchases`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `no` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单号',
  `procurement_seq` int(11) NOT NULL COMMENT '样品采购计划表主键',
  `supplier_seq` int(11) NOT NULL COMMENT '供应商表主键',
  `status` int(1) NULL DEFAULT 0 COMMENT '状态（0：未审核 1：已审核）',
  `verify_date` date NULL DEFAULT NULL COMMENT '审核时间',
  `insert_all` int(2) NULL DEFAULT 1 COMMENT '是否全部入库(0:否 1:是)',
  `create_date` date NULL DEFAULT NULL COMMENT '创建时间',
  `create_by` varchar(24) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `is_delete` int(2) NULL DEFAULT 0 COMMENT '是否删除（0：未删除 1：删除）',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `material_procurement_foregin_key1`(`procurement_seq`) USING BTREE,
  INDEX `material_procurement_foregin_key2`(`supplier_seq`) USING BTREE,
  CONSTRAINT `material_procurement_foregin_key1` FOREIGN KEY (`procurement_seq`) REFERENCES `proc_material_procurement` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `material_procurement_foregin_key2` FOREIGN KEY (`supplier_seq`) REFERENCES `bas_supplier_bak1` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '采购清单(暂时没用)' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for rabbitmq_msg_record
-- ----------------------------
DROP TABLE IF EXISTS `rabbitmq_msg_record`;
CREATE TABLE `rabbitmq_msg_record`  (
  `snow_id` bigint(20) NOT NULL COMMENT '唯一ID（雪花算法生成）',
  `module` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '模块标识（如 pdm、oms）',
  `target_exchange` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '目标交换机名称',
  `target_queue` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '目标队列名称',
  `message_data` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '消息数据',
  `business_name` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '业务名称',
  `business_status_name` varchar(40) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '业务状态昵称',
  `status` int(11) NOT NULL DEFAULT 0 COMMENT '消息状态（0:异常 1:待处理 2:处理中 3:已完成',
  `remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `create_user_id` bigint(20) NULL DEFAULT NULL COMMENT '创建人用户ID',
  `create_user_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '创建人名称',
  `update_time` datetime NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`snow_id`) USING BTREE,
  INDEX `idx_module_create_time`(`module`, `create_time`) USING BTREE,
  INDEX `idx_status`(`status`) USING BTREE,
  INDEX `exchange_index`(`target_exchange`) USING BTREE,
  INDEX `idx_user_id`(`create_user_id`) USING BTREE,
  INDEX `queue_index`(`target_queue`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = 'RabbitMQ消息记录表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for reconciliation_hold
-- ----------------------------
DROP TABLE IF EXISTS `reconciliation_hold`;
CREATE TABLE `reconciliation_hold`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `hold_no` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '挂起单号',
  `hold_person` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '挂起人',
  `hold_reason` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '挂起原因',
  `bas_supplier_seq` int(11) NOT NULL COMMENT '供应商ID',
  `bas_supplier_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '供应商名称',
  `is_confirmed` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否确认',
  `confirmed_at` datetime NULL DEFAULT NULL COMMENT '确认时间',
  `status` int(11) NOT NULL DEFAULT 0 COMMENT '状态：0==草稿，1==审批中，2==挂起，3==取消挂起',
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0 COMMENT '是否删除',
  `hold_at` datetime NULL DEFAULT NULL COMMENT '挂起日期',
  `audit_node_status` int(11) NULL DEFAULT 0 COMMENT '审批节点状态：0==未发起，其它参考ReconciliationHoldEnum枚举类',
  `created_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_at` datetime NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  `deleted_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_at` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 20 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '应付管理-对账挂起' ROW_FORMAT = Dynamic;

