-- ----------------------------
-- Table structure for replenishment_supplier_deduction_slip
-- ----------------------------
DROP TABLE IF EXISTS `replenishment_supplier_deduction_slip`;
CREATE TABLE `replenishment_supplier_deduction_slip`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `supplier_statement_seq` int(11) NULL DEFAULT NULL COMMENT '供应商对账表主键',
  `replenishment_requisition_seq` int(11) NULL DEFAULT NULL COMMENT '材料补料表seq',
  `document_type` varchar(10) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单据类型',
  `deduction_slip_number` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '扣款单号',
  `replenishment_company` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '补料公司',
  `replenishment_company_seq` int(11) NULL DEFAULT NULL COMMENT '补料公司seq',
  `liability_allocation` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '责任归属',
  `replenishment_dept` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '补料部门',
  `replenishment_dept_seq` int(11) NULL DEFAULT NULL COMMENT '补料部门seq',
  `replenishment_group_seq` int(11) NULL DEFAULT NULL COMMENT '补料小组seq',
  `replenishment_group` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '补料小组',
  `replenishment_date` datetime NULL DEFAULT NULL COMMENT '申请日期',
  `order_filler` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '申请人',
  `supplier_seq` int(11) NULL DEFAULT NULL COMMENT '责任单位seq(供应商seq)',
  `supplier_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '责任单位(供应商名称)',
  `deduction_category` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '扣款类别',
  `deduction_description` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '扣款说明',
  `is_financial_confirmation` int(11) NULL DEFAULT NULL COMMENT '财务确认',
  `confirmation_remarks` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '确认备注',
  `is_synchronized` int(11) NULL DEFAULT 0 COMMENT '是否同步',
  `is_approved` int(11) NULL DEFAULT 0 COMMENT '是否审批',
  `approval_date` datetime NULL DEFAULT NULL COMMENT '审批日期',
  `is_reconciled` int(11) NULL DEFAULT 0 COMMENT '是否对账',
  `status` int(11) NULL DEFAULT 0 COMMENT '状态(0暂存 1提交)',
  `is_deleted` int(11) NULL DEFAULT 0 COMMENT '是否删除0否1是',
  `created_by_name` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_by_name` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人昵称',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `deduction_amount` decimal(14, 4) NULL DEFAULT 0.0000 COMMENT '扣款金额',
  `liability_ratio` decimal(5, 2) NULL DEFAULT NULL COMMENT '责任比率',
  `audit_node_status` int(11) NULL DEFAULT 0 COMMENT '审批节点状态：0==未发起，其它参考ReplenishmentSupplierDeductionSlipEnum枚举类',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `replenishment_requisition_seq`(`replenishment_requisition_seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1789 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '材料补料 供应商扣款单' ROW_FORMAT = Dynamic;

