  `attachment_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '附件名称',
  `is_deleted` tinyint(1) NULL DEFAULT 0 COMMENT '是否删除(0-否,1-是)',
