  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改日期',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `article_seq`(`article_seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '样品单（暂时作废）' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for sample_order_history_version
-- ----------------------------
DROP TABLE IF EXISTS `sample_order_history_version`;
CREATE TABLE `sample_order_history_version`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
