  `revision` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '修改内容',
  `code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单号',
  `type` int(11) NULL DEFAULT NULL COMMENT '样品类型',
  `article_seq` int(11) NULL DEFAULT NULL COMMENT '型体序号',
  `article_size_seq` int(11) NULL DEFAULT NULL COMMENT '型体size序号',
  `department_seq` int(11) NULL DEFAULT NULL COMMENT '部门序号',
  `quantity` double(11, 2) NULL DEFAULT NULL COMMENT '数量',
  `unit` int(255) NULL DEFAULT NULL COMMENT '单位',
  `version` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '开发版本',
  `development` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '开发版师',
  `date` timestamp NULL DEFAULT NULL COMMENT '样品日期',
  `business` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '开发业务',
  `customer_delivery` timestamp NULL DEFAULT NULL COMMENT '客户交期',
  `is_audit` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '是否审核',
  `is_deleted` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否删除',
  `filing_time` timestamp NULL DEFAULT NULL COMMENT '建档时间',
  `created_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '创建时间',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改日期',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `article_seq`(`article_seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '样品单历史版本（暂时作废）' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for sample_receipt
-- ----------------------------
DROP TABLE IF EXISTS `sample_receipt`;
CREATE TABLE `sample_receipt`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `sample_receipt_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品收款单号',
  `customer_seq` int(11) NULL DEFAULT NULL COMMENT '客户ID',
  `customer_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `customer_brand_seq` int(11) NULL DEFAULT NULL COMMENT '客户品牌表seq',
  `customer_brand_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户品牌名',
  `reconciliation_seq` int(11) NULL DEFAULT NULL COMMENT '应收款对账单seq',
  `receivable_type_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '应收类型code',
  `receivable_type_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '应收类型名称',
  `funds` varchar(125) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '款项',
  `quantity` int(11) NOT NULL COMMENT '数量',
  `tax_included_unit_price` decimal(10, 4) NULL DEFAULT NULL COMMENT '含税单价',
  `tax_excluded_unit_price` decimal(10, 4) NULL DEFAULT NULL COMMENT '不含税单价',
  `receivable_money` decimal(10, 2) NULL DEFAULT NULL COMMENT '应收款金额',
  `status` int(11) NULL DEFAULT 0 COMMENT '状态：0==草稿，1==提交',
  `write_off` tinyint(1) NULL DEFAULT 0 COMMENT '是否核销 0-未核销 1-已核销',
  `is_delete` tinyint(1) NULL DEFAULT 0 COMMENT '是否删除',
  `created_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_at` datetime NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  `deleted_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_at` datetime NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '样品收款单' ROW_FORMAT = Dynamic;

