  `remark` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `del_flag` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '删除标志（0代表存在 2代表删除）',
  `page_address` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '页面位置',
  `is_available` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '是否可用（0：不可用 1：可用）',
  `version` double NULL DEFAULT NULL COMMENT '版本号',
  `created_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = 'SOP工序表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for sop_workshop_section
-- ----------------------------
DROP TABLE IF EXISTS `sop_workshop_section`;
CREATE TABLE `sop_workshop_section`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `section_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工段名称',
  `section_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工段编码',
  `section_desc` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工段描述',
  `sort` int(11) NULL DEFAULT NULL COMMENT '排序',
  `create_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `create_date` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `update_date` datetime NULL DEFAULT NULL COMMENT '更新时间',
  `delete_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '删除人',
  `delete_date` datetime NULL DEFAULT NULL COMMENT '删除时间',
  `remark` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `del_flag` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '删除标志（0代表存在 2代表删除）',
  `page_address` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '页面位置',
  `is_available` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '是否可用（0：不可用 1：可用）',
  `version` double NULL DEFAULT NULL COMMENT '版本号',
  `created_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = 'SOP工段表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for stock
-- ----------------------------
DROP TABLE IF EXISTS `stock`;
CREATE TABLE `stock`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `clazz` char(2) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单据分类\r\n10 入库\r\n20 出库',
  `type` char(2) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物品类型\r\n10 物料\r\n20 样鞋\r\n30 成品鞋',
  `aritlec_seq` int(11) NULL DEFAULT NULL COMMENT '型体表序号',
  `size` double NULL DEFAULT NULL COMMENT '码号',
  `material_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码',
  `quantity` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '汇总',
  `residue_amount` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '剩余',
  `unit` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单位',
  `remark` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `is_delete` int(1) NULL DEFAULT 0 COMMENT '未删除：0 删除：1 ',
  `out_stock` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `create_date` datetime NULL DEFAULT NULL,
  `no` int(11) NULL DEFAULT NULL,
  `warehouse_no` int(11) NULL DEFAULT NULL,
  `place` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `stock_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `currency` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `amount` int(11) NULL DEFAULT NULL,
  `issue` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `org` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `tenant` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '库存' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for stock_info
-- ----------------------------
DROP TABLE IF EXISTS `stock_info`;
CREATE TABLE `stock_info`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT 'seq',
  `store_seq` int(11) NULL DEFAULT NULL COMMENT '库存表序号',
  `no` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '批次号',
  `stock_no` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '当库存类型为出库时，该字段值为出库单包含的入库批次号',
  `storage` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '数量',
  `residue_amount` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '剩余',
  `unit` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单位',
  `warehouse_no` int(11) NULL DEFAULT NULL COMMENT '仓库',
  `place` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '存储位置',
  `trading_object` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '交易对象',
  `trading_currency` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '交易货币',
  `price` decimal(10, 2) NULL DEFAULT NULL COMMENT '单价',
  `amount` double(255, 0) NULL DEFAULT NULL COMMENT '金额',
  `date` timestamp NULL DEFAULT NULL COMMENT '入/出库时间',
  `create_date` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `memo` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `is_delete` int(1) UNSIGNED ZEROFILL NULL DEFAULT 0 COMMENT '0:未删除  1:删除',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '库存详情' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for storage
-- ----------------------------
DROP TABLE IF EXISTS `storage`;
CREATE TABLE `storage`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `storehouse_seq` int(11) NULL DEFAULT NULL COMMENT '外键',
  `code` varchar(22) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '储位编号',
  `place` varchar(24) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '位置',
  `amount` varchar(24) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '容量',
  `free_space` varchar(24) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '剩余容量',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `storehouse_foregin_key`(`storehouse_seq`) USING BTREE,
  CONSTRAINT `storehouse_foregin_key` FOREIGN KEY (`storehouse_seq`) REFERENCES `storehouse` (`seq`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '储位表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for storage_stocktaking
-- ----------------------------
DROP TABLE IF EXISTS `storage_stocktaking`;
CREATE TABLE `storage_stocktaking`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '盘点单号',
  `title` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '盘点标题',
  `type_seq` int(11) NULL DEFAULT NULL COMMENT '盘点类型序号',
  `type_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '盘点类型',
  `is_lock_up` int(1) NULL DEFAULT 1 COMMENT '是否锁仓',
  `company_id` int(11) NULL DEFAULT NULL COMMENT '公司序号',
  `company_name` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司名称',
  `warehouse_seq` int(11) NULL DEFAULT NULL COMMENT '仓库序号',
  `warehouse_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库名称',
  `range_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '盘点范围',
  `range_seq` int(11) NULL DEFAULT NULL COMMENT '盘点范围',
  `is_hand` int(1) NULL DEFAULT 0 COMMENT '是否手录',
  `is_confirm` int(1) NULL DEFAULT 0 COMMENT '是否差异确认',
  `is_difference` int(1) NULL DEFAULT 0 COMMENT '是否异常',
  `is_closing_position` int(1) NULL DEFAULT 0 COMMENT '是否平仓',
  `print_count` int(11) NULL DEFAULT 0 COMMENT '打印次数',
  `status` int(2) NULL DEFAULT NULL COMMENT '单据状态：（0：草稿；1：提交；2：待审批；3：审批中；4：审核完成；10：手录草稿；11：手录提交；12：手录待审批：13：手录审批中；14：手录审批完成；20：实盘草稿；21：实盘提交；22：实盘待审批：23：实盘审批中：24：实盘审批完成）',
  `memo` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '备注',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除',
  `enable` int(1) NULL DEFAULT 1 COMMENT '是否有效',
  `init_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '初始人',
  `init_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '初始人昵称',
  `init_at` date NULL DEFAULT NULL COMMENT '初始时间',
  `stocktaking_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '实盘人',
  `stocktaking_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '实盘人昵称',
  `stocktaking_at` timestamp NULL DEFAULT NULL COMMENT '实盘人昵称',
  `created_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人昵称',
  `created_at` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人昵称',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人昵称',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `closing_position_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '平仓人',
  `closing_position_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '平仓人昵称',
  `closing_position_at` timestamp NULL DEFAULT NULL COMMENT '平仓时间',
  `confirm_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '差异确认人',
  `confirm_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '差异确认人昵称',
  `confirm_at` timestamp NULL DEFAULT NULL COMMENT '差异确认时间',
  `commit_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '提交人',
  `commit_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '提交人昵称',
  `commit_at` timestamp NULL DEFAULT NULL COMMENT '提交时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 95 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '仓库盘点' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for storage_stocktaking_closing_position
-- ----------------------------
DROP TABLE IF EXISTS `storage_stocktaking_closing_position`;
CREATE TABLE `storage_stocktaking_closing_position`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '盘点平仓单号',
  `stocktaking_seq` int(11) NULL DEFAULT NULL COMMENT '盘点seq',
  `stocktaking_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '盘点单号',
  `difference_seq` int(11) NULL DEFAULT NULL COMMENT '差异seq',
  `difference_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '盘点单号',
  `title` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '盘点标题',
  `type_seq` int(11) NULL DEFAULT NULL COMMENT '盘点类型序号',
  `type_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '盘点类型',
  `is_lock_up` int(1) NULL DEFAULT 1 COMMENT '盘点类型是否锁仓（0：否；1：是）',
  `company_name` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司名称',
  `company_id` int(11) NULL DEFAULT NULL COMMENT '公司序号',
  `warehouse_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库名称',
  `warehouse_seq` int(11) NULL DEFAULT NULL COMMENT '仓库序号',
  `range_seq` int(11) NULL DEFAULT NULL,
  `range_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `is_hand` int(1) NULL DEFAULT 0 COMMENT '是否手录',
  `is_confirm` int(1) NULL DEFAULT 0 COMMENT '是否确认',
  `is_difference` int(1) NULL DEFAULT 0 COMMENT '是否异常',
  `is_closing_position` int(1) NULL DEFAULT 0 COMMENT '是否平仓',
  `print_count` int(11) NULL DEFAULT 0 COMMENT '打印次数',
  `status` int(2) NULL DEFAULT NULL COMMENT '单据状态：（0：草稿；1、提交；2、待审批；3、审批中；4、审核完成）',
  `memo` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '备注',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除',
  `enable` int(1) NULL DEFAULT 1 COMMENT '是否有效',
  `init_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '初始人',
  `init_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '初始人昵称',
  `init_at` date NULL DEFAULT NULL COMMENT '初始时间',
  `confirm_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '确认人',
  `confirm_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '确认人昵称',
  `confirm_at` timestamp NULL DEFAULT NULL COMMENT '确认时间',
  `stocktaking_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '实盘人',
  `stocktaking_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '实盘人昵称',
  `stocktaking_at` timestamp NULL DEFAULT NULL COMMENT '实盘人昵称',
  `closing_position_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `closing_position_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `closing_position_at` timestamp NULL DEFAULT NULL,
  `commit_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `storage_store_code` int(11) NULL DEFAULT NULL COMMENT '盘点入库单',
  `storage_outbound_code` int(11) NULL DEFAULT NULL COMMENT '盘点出库单',
  `commit_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `commit_at` timestamp NULL DEFAULT NULL,
  `created_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人昵称',
  `created_at` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人昵称',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人昵称',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 77 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '仓库盘点平仓表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for storage_stocktaking_closing_position_info
-- ----------------------------
DROP TABLE IF EXISTS `storage_stocktaking_closing_position_info`;
CREATE TABLE `storage_stocktaking_closing_position_info`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `storage_closing_position_seq` int(11) NULL DEFAULT NULL,
  `storage_id` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `stocktaking_seq` int(11) NULL DEFAULT NULL,
  `po` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'PO号，也是订单标识号=行号和生产指令号一一对应',
  `manual_prod_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '手工排产单号',
  `sku` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'SKU',
  `art_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `customer_seq` int(11) NOT NULL COMMENT '客户编码',
  `customer_name` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT 'KH000000000000' COMMENT '客户名称\'KH000000000000\'虚拟客户',
  `material_category_seq` int(11) NULL DEFAULT NULL,
  `material_category_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '物料简码',
  `material_category_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '物料名称',
  `material_info_seq` int(11) NOT NULL COMMENT '物料编码ID',
  `material_info_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '物料编码',
  `material_info_size` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'size',
  `material_info_color_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '颜色名称',
  `material_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `storage_location_seq` int(11) NULL DEFAULT NULL,
  `storage_location_code` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '储位编号',
  `storage_location_name` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '储位名称',
  `product_code` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '0000000000' COMMENT '生产订单号\'0000000000\'虚拟号',
  `supply_seq` int(11) NOT NULL COMMENT '供应商Id',
  `supply_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '供应商名称',
  `warehouse_code` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '仓库编号',
  `warehouse_name` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '仓库名称',
  `system_inventory` decimal(18, 4) UNSIGNED NULL DEFAULT NULL COMMENT '仓库库数量(在库)',
  `actual_inventory` decimal(18, 4) NULL DEFAULT NULL COMMENT '实盘数量',
  `difference_inventory` decimal(18, 4) NULL DEFAULT NULL COMMENT '差异数',
  `unit` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单位',
  `position_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位seq',
  `position_code` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位code',
  `position_name` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位名称',
  `factory_id` int(11) NULL DEFAULT NULL COMMENT '所属工厂id',
  `factory_name` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '所属工厂名称',
  `remark1` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备用字段',
  `remark2` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备用字段',
  `amount` decimal(14, 4) NULL DEFAULT NULL COMMENT '金额',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '季度序号',
  `rate` decimal(18, 3) NULL DEFAULT NULL COMMENT '税率',
  `rate_price` decimal(18, 4) NULL DEFAULT NULL COMMENT '含税单价',
  `store_price` decimal(18, 4) NULL DEFAULT NULL COMMENT '库存单价',
  `inquiry_price_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价明细seq',
  `price_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价更新人',
  `price_date` datetime NULL DEFAULT NULL COMMENT '报价更新时间',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `total_qty`(`difference_inventory`) USING BTREE,
  INDEX `storeIdx`(`storage_closing_position_seq`, `material_info_seq`, `material_category_seq`, `product_code`, `manual_prod_code`, `customer_seq`, `supply_seq`, `warehouse_code`, `storage_location_seq`, `position_seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 295309 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '盘点平仓明细表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for storage_stocktaking_difference
-- ----------------------------
DROP TABLE IF EXISTS `storage_stocktaking_difference`;
CREATE TABLE `storage_stocktaking_difference`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '序号',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '盘点差异单号',
  `stocktaking_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '盘点单号',
  `title` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '盘点标题',
  `type_seq` int(11) NULL DEFAULT NULL COMMENT '盘点类型序号',
  `type_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '盘点类型',
  `range_seq` int(11) NULL DEFAULT NULL COMMENT '盘点范围',
  `range_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '盘点范围',
  `is_lock_up` int(1) NULL DEFAULT 1 COMMENT '盘点类型是否锁仓（0：否；1：是）',
  `company_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '公司名称',
  `company_id` int(11) NULL DEFAULT NULL COMMENT '公司序号',
  `warehouse_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '仓库名称',
  `warehouse_seq` int(11) NULL DEFAULT NULL COMMENT '仓库序号',
  `is_hand` int(1) NULL DEFAULT 0 COMMENT '是否手录',
  `is_confirm` int(1) NULL DEFAULT 0 COMMENT '是否确认',
  `is_difference` int(1) NULL DEFAULT 0 COMMENT '是否异常',
  `is_closing_position` int(1) NULL DEFAULT 0 COMMENT '是否平仓',
  `print_count` int(11) NULL DEFAULT 0 COMMENT '打印次数',
  `status` int(2) NULL DEFAULT NULL COMMENT '单据状态：（0：草稿；1、提交；2、待审批；3、审批中；4、审核完成）',
  `memo` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '备注',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除',
  `enable` int(1) NULL DEFAULT 1 COMMENT '是否有效',
  `init_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '初始人',
  `init_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '初始人昵称',
  `init_at` date NULL DEFAULT NULL COMMENT '初始时间',
  `confirm_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '确认人',
  `confirm_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '确认人昵称',
  `confirm_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '确认时间',
  `stocktaking_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '实盘人',
  `stocktaking_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '实盘人昵称',
  `stocktaking_at` timestamp NULL DEFAULT NULL COMMENT '实盘人昵称',
  `created_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人昵称',
  `created_at` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人昵称',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人昵称',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `commit_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `commit_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `commit_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  `closing_position_nick_name_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `closing_position_by` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `closing_position_at` timestamp NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`seq`) USING BTREE,
  UNIQUE INDEX `idx_stock_code_id`(`code`, `stocktaking_code`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 69 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '仓库盘点差异表' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for storage_stocktaking_difference_info
-- ----------------------------
DROP TABLE IF EXISTS `storage_stocktaking_difference_info`;
CREATE TABLE `storage_stocktaking_difference_info`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `storage_difference_seq` int(11) NULL DEFAULT NULL,
  `storage_id` varchar(40) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `stocktaking_seq` int(11) NULL DEFAULT NULL,
  `po` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'PO号，也是订单标识号=行号和生产指令号一一对应',
  `manual_prod_code` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '手工排产单号',
  `sku` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'SKU',
  `art_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `customer_seq` int(11) NOT NULL COMMENT '客户编码',
  `customer_name` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT 'KH000000000000' COMMENT '客户名称\'KH000000000000\'虚拟客户',
  `material_category_seq` int(11) NULL DEFAULT NULL,
  `material_category_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '物料简码',
  `material_category_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '物料名称',
  `material_info_seq` int(11) NOT NULL COMMENT '物料编码ID',
  `material_info_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '物料编码',
  `material_info_size` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'size',
  `material_info_color_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '颜色名称',
  `material_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `storage_location_seq` int(11) NULL DEFAULT NULL,
  `storage_location_code` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '储位编号',
  `storage_location_name` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '储位名称',
  `product_code` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '0000000000' COMMENT '生产订单号\'0000000000\'虚拟号',
  `supply_seq` int(11) NOT NULL COMMENT '供应商Id',
  `supply_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '供应商名称',
  `warehouse_code` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '仓库编号',
  `warehouse_name` varchar(80) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '仓库名称',
  `system_inventory` decimal(18, 4) UNSIGNED NULL DEFAULT NULL COMMENT '仓库库数量(在库)',
  `actual_inventory` decimal(18, 4) NULL DEFAULT NULL COMMENT '实盘数量',
  `difference_inventory` decimal(18, 4) NULL DEFAULT NULL COMMENT '差异数',
  `unit` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单位',
  `position_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位seq',
  `position_code` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位code',
  `position_name` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位名称',
  `factory_id` int(11) NULL DEFAULT NULL COMMENT '所属工厂id',
  `factory_name` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '所属工厂名称',
  `remark1` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备用字段',
  `remark2` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备用字段',
  `amount` decimal(14, 4) NULL DEFAULT NULL COMMENT '金额',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '季度序号',
  `rate` decimal(18, 3) NULL DEFAULT NULL COMMENT '税率',
  `rate_price` decimal(18, 4) NULL DEFAULT NULL COMMENT '含税单价',
  `store_price` decimal(18, 4) NULL DEFAULT NULL COMMENT '库存单价',
  `inquiry_price_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价明细seq',
  `price_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价更新人',
  `price_date` datetime NULL DEFAULT NULL COMMENT '报价更新时间',
  PRIMARY KEY (`seq`) USING BTREE,
  INDEX `total_qty`(`difference_inventory`) USING BTREE,
  INDEX `storeIdx`(`storage_difference_seq`, `material_info_seq`, `material_info_code`, `material_category_code`, `product_code`, `customer_seq`, `supply_seq`, `warehouse_code`, `storage_location_seq`, `position_seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 418762 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '盘点差异明细表' ROW_FORMAT = DYNAMIC;

