-- ----------------------------
-- Table structure for store
-- ----------------------------
DROP TABLE IF EXISTS `store`;
CREATE TABLE `store`  (
  `id` varchar(36) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL,
  `material_seq` int(11) NOT NULL COMMENT '物料编码ID',
  `material_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '物料编码',
  `material_category_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '物料简码',
  `material_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '物料名称',
  `product_code` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT '0000000000' COMMENT '生产订单号\'0000000000\'虚拟号',
  `customer_seq` int(11) NOT NULL COMMENT '客户编码',
  `customer_name` varchar(40) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL DEFAULT 'KH000000000000' COMMENT '客户名称\'KH000000000000\'虚拟客户',
  `supply_seq` int(11) NOT NULL COMMENT '供应商Id',
  `supply_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '供应商名称',
  `warehouse_seq` int(11) NULL DEFAULT NULL COMMENT '仓库seq',
  `warehouse_code` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '仓库编号',
  `warehouse_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '仓库名称',
  `location_seq` int(11) NULL DEFAULT NULL COMMENT '储位seq',
  `location_code` varchar(20) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '储位编号',
  `location_name` varchar(40) CHARACTER SET utf8 COLLATE utf8_general_ci NOT NULL COMMENT '储位名称',
  `on_hand_qty` decimal(30, 4) UNSIGNED NULL DEFAULT NULL COMMENT '仓库库数量(在库)',
  `on_order_qty` decimal(30, 4) NULL DEFAULT NULL COMMENT '在途数量',
  `total_qty` decimal(30, 4) NULL DEFAULT NULL COMMENT '总库存数量',
  `enable` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '1',
  `is_deleted` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_at` datetime NULL DEFAULT NULL,
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `deleted_at` datetime NULL DEFAULT NULL,
  `remark1` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备用字段',
  `remark2` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备用字段',
  `created_by_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '昵称',
  `position_seq` int(11) NULL DEFAULT NULL COMMENT '部位seq',
  `position_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位code',
  `position_name` varchar(40) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位名称',
  `transfer_inventory_qty` decimal(13, 4) NULL DEFAULT NULL COMMENT '调拨入库数量',
  `transfer_outbound_qty` decimal(13, 4) NULL DEFAULT NULL COMMENT '调拨出库数量',
  `row_no` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '订单标识号=行号和生产指令号一一对应',
  `sku` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '款式',
  `manual_prod_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '手工排产单号',
  `factory_id` int(11) NULL DEFAULT NULL COMMENT '工厂id',
  `factory_name` varchar(60) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工厂名称',
  `size` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'size',
  `color_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '颜色名称',
  `unit_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单位',
  `customer_article_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户型体编号',
  `product_seq` int(11) NULL DEFAULT NULL COMMENT '生产订单seq',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '季度序号',
  `amount` decimal(14, 4) NULL DEFAULT NULL COMMENT '金额',
  `rate` decimal(18, 3) NULL DEFAULT NULL COMMENT '税率',
  `rate_price` decimal(18, 4) NULL DEFAULT NULL COMMENT '含税单价',
  `store_price` decimal(18, 4) NULL DEFAULT NULL COMMENT '库存单价',
  `inquiry_price_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价明细seq',
  `price_by` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单价更新人',
  `price_date` datetime NULL DEFAULT NULL COMMENT '单价更新时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `storeIdx`(`material_seq`, `material_code`, `material_category_code`, `product_code`, `customer_seq`, `supply_seq`, `warehouse_seq`, `location_seq`, `position_seq`, `factory_id`) USING BTREE,
  INDEX `idx_store_code`(`factory_id`, `factory_name`, `warehouse_seq`, `warehouse_code`, `warehouse_name`, `location_seq`, `location_code`, `location_name`, `on_hand_qty`, `material_code`, `product_code`, `position_code`) USING BTREE,
  INDEX `idx_store_cover_v2`(`warehouse_name`(20), `factory_name`(30), `row_no`, `sku`(15), `position_code`(10), `material_code`(15), `on_hand_qty`) USING BTREE,
  INDEX `material_code`(`material_code`, `position_code`, `product_code`, `on_hand_qty`) USING BTREE,
  INDEX `idx_stor_v4`(`product_code`, `material_code`, `position_code`) USING BTREE,
  INDEX `idx_stor_v3`(`warehouse_name`, `factory_name`, `on_hand_qty`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '库存表' ROW_FORMAT = DYNAMIC;

