-- ----------------------------
-- Table structure for t_customer_quotation
-- ----------------------------
DROP TABLE IF EXISTS `t_customer_quotation`;
CREATE TABLE `t_customer_quotation`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `art_seq` int(11) NULL DEFAULT NULL COMMENT '产品资料主键',
  `sku` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'sku',
  `quotation_number` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价单编号',
  `logo_url` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '图片地址',
  `code` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工厂型体编号',
  `customer_seq` int(11) NULL DEFAULT NULL COMMENT '客户Id',
  `customer_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `customer_article_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户型体名称',
  `customer_article_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户型体编号',
  `product_class_seq` int(11) NULL DEFAULT NULL COMMENT '产品类别seq',
  `product_class_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品类别名称',
  `color` int(11) NULL DEFAULT NULL COMMENT '颜色序号',
  `color_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '颜色名称',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '季度序号',
  `sex` int(11) NULL DEFAULT NULL COMMENT '样鞋性别（字典表seq）',
  `sample_stage_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品阶段id',
  `sample_stage_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品阶段名称',
  `quotation_size_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价码',
  `transaction_price` decimal(10, 2) NULL DEFAULT NULL,
  `tag_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '吊牌价',
  `product_unit_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '产品单价',
  `profit_margin` decimal(10, 2) NULL DEFAULT NULL COMMENT '利润率',
  `target_unit_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '目标单价',
  `net_usage` decimal(10, 2) NULL DEFAULT NULL,
  `cost_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '成本价格',
  `total_price_materials` decimal(10, 2) NULL DEFAULT NULL COMMENT '材料总价',
  `cost_rate` decimal(10, 2) NULL DEFAULT NULL COMMENT '成本率',
  `differential_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '差异价',
  `currency` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '币种',
  `exchange_rate` decimal(10, 2) NULL DEFAULT NULL COMMENT '汇率',
  `quotation_size_code_start` decimal(5, 2) NULL DEFAULT NULL COMMENT '报价尺码范围开始',
  `quotation_size_code_end` decimal(5, 2) NULL DEFAULT NULL COMMENT '报价尺码范围结束',
  `status` int(11) NULL DEFAULT NULL COMMENT '状态',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除',
  `is_not_need_quotation` int(1) NULL DEFAULT 0 COMMENT '是否需要报价码',
  `created_at` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `created_by_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `order_quarter_code` int(11) NULL DEFAULT NULL COMMENT '下单季度序号',
  `version` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT 'V1' COMMENT '版本号',
  `art_version` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品资料版本号',
  `size_quote` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价尺码',
  `bomversionnumber` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'BOM版本号',
  `company_seq` int(11) NULL DEFAULT NULL COMMENT '公司seq',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 10 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '客户报价单' ROW_FORMAT = Dynamic;

