  `art_seq` int(11) NULL DEFAULT NULL COMMENT '型体序号',
  `art_position_seq` int(11) NULL DEFAULT NULL COMMENT '型体部位序号',
  `ie_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工艺编码',
  `ie_name` varchar(200) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工艺名称',
  `ie_memo` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工艺描述',
  `position_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位名称',
  `material_category_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '物料简码名称',
  `provider_seq` int(11) NULL DEFAULT NULL COMMENT '供应商seq',
