-- ----------------------------
-- Table structure for t_customer_quotation_material_details
-- ----------------------------
DROP TABLE IF EXISTS `t_customer_quotation_material_details`;
CREATE TABLE `t_customer_quotation_material_details`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
