  `material_category_seq` int(11) NULL DEFAULT NULL COMMENT '物料简码序号',
  `material_category_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料简码',
  `material_category_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '物料简码名称',
  `material_info_seq` int(11) NULL DEFAULT NULL COMMENT '物料编码seq',
  `material_info_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码',
  `position_seq` int(11) NULL DEFAULT NULL COMMENT '部件序号',
  `position_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位编号',
  `position_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位名称',
  `position_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位分类(改为物料分组)',
  `material_info_colour` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码颜色编码',
  `material_info_colour_name` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码颜色名称',
  `position_pieces` decimal(14, 2) NULL DEFAULT NULL COMMENT '部位片数',
  `lo_pieces` decimal(14, 2) NULL DEFAULT NULL COMMENT 'lo片数',
  `remark` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `net_usage` decimal(14, 4) NULL DEFAULT NULL COMMENT '净用量',
  `loss_rate` decimal(14, 4) NULL DEFAULT NULL COMMENT '损耗率',
  `wool_usage` decimal(14, 4) NULL DEFAULT NULL COMMENT '毛用量',
  `unit_price` decimal(14, 4) NULL DEFAULT NULL COMMENT '单价',
  `minimum_purchase_quantity` decimal(14, 4) NULL DEFAULT NULL COMMENT '最小采购量',
  `total_price` decimal(14, 4) NULL DEFAULT NULL COMMENT '总价',
  `each_expend` decimal(11, 4) NULL DEFAULT 1.0000 COMMENT '单耗',
  `unit_seq` int(11) NULL DEFAULT NULL COMMENT '单位id',
  `unit_name` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '单位名称',
  `material_info_is_out_sourcing` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否组合材料',
  `parent_seq` int(11) NULL DEFAULT NULL COMMENT '组合材料的父类seq',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '季度序号',
  `customer_seq` int(11) NULL DEFAULT NULL COMMENT '客户Id',
  `sample_stage_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品阶段名称',
  `provider_type_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `unit_price_type` int(11) NULL DEFAULT 0 COMMENT '单价类型(0未取到单价,1大货价，2样品价，3手工单价)',
  `output_quantity` decimal(14, 4) NULL DEFAULT NULL COMMENT '量产用量',
  `freight_unit_price` decimal(14, 4) NULL DEFAULT NULL COMMENT '运费单价',
  `material_freight` decimal(14, 4) NULL DEFAULT NULL COMMENT '物料运费',
  `lineno` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '行号',
  `processing_unit_price` decimal(14, 4) NULL DEFAULT NULL COMMENT '加工单价',
  `no` int(11) NULL DEFAULT NULL COMMENT '顺序号',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 7096 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '客户报价-材料明细' ROW_FORMAT = Dynamic;

