  `type` int(11) NULL DEFAULT NULL COMMENT '类别（类别值代号）',
  `clazz` int(11) NULL DEFAULT NULL COMMENT '分类（类别值代号）',
  `form` int(11) NULL DEFAULT NULL COMMENT '型态（类别值代号）',
  `specification` int(11) NULL DEFAULT NULL COMMENT '规格（类别值代号）',
