  `if_process` int(1) NULL DEFAULT NULL COMMENT '是否需要加工',
  `effect_at` datetime NULL DEFAULT NULL COMMENT '生效日期',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `created_at` datetime NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `update_at` datetime NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` datetime NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '物料基本信息' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for t_material_supplier
-- ----------------------------
DROP TABLE IF EXISTS `t_material_supplier`;
CREATE TABLE `t_material_supplier`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `material_seq` int(11) NULL DEFAULT NULL COMMENT '物料台账seq',
  `supplier_seq` int(11) NULL DEFAULT NULL COMMENT '供应商seq',
  `is_default` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '是否默认供应商:0-否,1-是',
  `material_code` varchar(125) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码',
  `material_name` varchar(125) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料名称',
  `remark` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '物料台账-供应商关联表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for t_material_tem
-- ----------------------------
DROP TABLE IF EXISTS `t_material_tem`;
CREATE TABLE `t_material_tem`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `material_seq` int(11) NULL DEFAULT NULL COMMENT '物料id',
  `tem_seq` int(11) NULL DEFAULT NULL COMMENT '临时物料id',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '临时物料-物料关系表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for t_mold_cost
-- ----------------------------
DROP TABLE IF EXISTS `t_mold_cost`;
CREATE TABLE `t_mold_cost`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `estimated_standard_cost_seq` int(11) NULL DEFAULT NULL COMMENT '预估成本主表seq',
  `estimated_order_number` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '预估单号',
  `sequence_number` int(11) NULL DEFAULT NULL COMMENT '顺序号',
  `material_seq` int(11) NULL DEFAULT NULL COMMENT '物料seq',
  `material_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料名称',
  `material_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码',
  `colour` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '颜色',
  `specifications` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '规格',
  `supplier` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商',
  `first_mold_cost` decimal(4, 2) NULL DEFAULT NULL COMMENT '第一次模具费用 ',
  `average_cost` decimal(4, 2) NULL DEFAULT NULL COMMENT '平均费用',
  `last_mold_cost` decimal(4, 2) NULL DEFAULT NULL COMMENT '最后次模具费用',
  `exchange_rate` decimal(4, 2) NULL DEFAULT NULL COMMENT '汇率',
  `currency` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '币种',
  `mold_cost` decimal(4, 2) NULL DEFAULT NULL COMMENT '模具费用',
  `unit_price` decimal(4, 2) NULL DEFAULT NULL COMMENT '单价',
  `quantity` int(11) NULL DEFAULT NULL COMMENT '数量',
  `remarks` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `version` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '版本',
  `is_effective` int(11) NULL DEFAULT NULL COMMENT '是否有效(1是0否)',
  `create_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `create_date` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `update_date` datetime NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '模具费用' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for t_om_article_commission
-- ----------------------------
DROP TABLE IF EXISTS `t_om_article_commission`;
CREATE TABLE `t_om_article_commission`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
