  `commission_category` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '佣金类别',
  `commission_unit_price` int(11) NULL DEFAULT NULL COMMENT '佣金单价',
  `commission_rate` decimal(4, 2) NULL DEFAULT NULL COMMENT '佣金比率',
  `commission_company` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '佣金公司',
  `remarks` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `version` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '版本',
  `is_effective` int(11) NULL DEFAULT NULL COMMENT '是否有效(1是0否)',
  `create_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `create_date` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `update_date` datetime NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '型体佣金' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for t_other_cost
-- ----------------------------
DROP TABLE IF EXISTS `t_other_cost`;
CREATE TABLE `t_other_cost`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `estimated_standard_cost_seq` int(11) NULL DEFAULT NULL COMMENT '预估成本主表seq',
  `estimated_order_number` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '预估单号',
  `sequence_number` int(11) NULL DEFAULT NULL COMMENT '顺序号',
  `cost_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '费用名称',
  `quotation_amount` int(11) NULL DEFAULT NULL COMMENT '报价金额',
  `currency` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '币种',
  `exchange_rate` decimal(20, 2) NULL DEFAULT NULL COMMENT '汇率',
  `local_currency_amount` int(11) NULL DEFAULT NULL COMMENT '本币金额',
  `remarks` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `version` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '版本',
  `is_effective` int(11) NULL DEFAULT NULL COMMENT '是否有效(1是0否)',
  `create_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `create_date` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `update_date` datetime NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '其他费用' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for t_product_stage
-- ----------------------------
DROP TABLE IF EXISTS `t_product_stage`;
CREATE TABLE `t_product_stage`  (
  `id` bigint(18) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '阶段代号',
  `name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '阶段名称',
  `deadline` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '处理期限',
  `number` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '排序',
  `product_type` int(11) NULL DEFAULT NULL COMMENT '产品类型',
  `time` int(11) NULL DEFAULT NULL COMMENT '年份(下拉框：在常用类别中查找)',
  `season` int(11) NULL DEFAULT NULL COMMENT '季节(下拉框：在常用类别中查找)',
  `if_delete` char(1) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '是否删除：0-否；1-是',
  `create_by_` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `create_time_` datetime(3) NULL DEFAULT NULL COMMENT '创建时间',
  `update_by_` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `update_time_` datetime(3) NULL DEFAULT NULL COMMENT '更新时间',
  `delete_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `delete_time` datetime(3) NULL DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '产品阶段设定' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for t_product_stage_user
-- ----------------------------
DROP TABLE IF EXISTS `t_product_stage_user`;
CREATE TABLE `t_product_stage_user`  (
  `id` bigint(18) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `stage_id` bigint(20) NULL DEFAULT NULL COMMENT '产品阶段ID',
  `developer_id` bigint(20) NULL DEFAULT NULL COMMENT '开发人员id',
  `developer_name` varchar(125) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '开发人员名称',
  `create_by_` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `create_time_` datetime(3) NULL DEFAULT NULL COMMENT '创建时间',
  `update_by_` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `update_time_` datetime(3) NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '产品阶段设定处理人' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for t_progress_feedback
-- ----------------------------
DROP TABLE IF EXISTS `t_progress_feedback`;
CREATE TABLE `t_progress_feedback`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `sample_order_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品单号',
  `process_number` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工序编号',
  `process_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工序名称',
  `developers` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '开发人员',
  `start_time` datetime NULL DEFAULT NULL COMMENT '开始时间',
  `completion_time` datetime NULL DEFAULT NULL COMMENT '完成时间',
  `estimated_completion_time` datetime NULL DEFAULT NULL COMMENT '预计完成时间',
  `time_consuming` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '耗时',
  `abnormal` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '是否异常',
  `remarks` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `create_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `create_date` datetime(3) NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `update_date` datetime(3) NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '样品进度回馈' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for t_sample_process
-- ----------------------------
DROP TABLE IF EXISTS `t_sample_process`;
CREATE TABLE `t_sample_process`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `process_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工序名称',
  `process_code` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工序编码',
  `product_type` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品类型',
  `deadline` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '处理期限',
  `year` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '年份',
  `quarter` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '季度',
  `sort` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '排序',
  `create_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `create_date` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `update_date` datetime NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '样品工序设定' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for t_sample_process_user
-- ----------------------------
DROP TABLE IF EXISTS `t_sample_process_user`;
CREATE TABLE `t_sample_process_user`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `sample_process_seq` int(11) NULL DEFAULT NULL COMMENT '样品工序ID',
  `developer_seq` int(11) NULL DEFAULT NULL COMMENT '处理人ID',
  `create_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '创建人',
  `create_date` datetime NULL DEFAULT NULL COMMENT '创建时间',
  `update_by` varchar(64) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT '更新人',
  `update_date` datetime NULL DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '样品工序设定处理人' ROW_FORMAT = DYNAMIC;

-- ----------------------------
-- Table structure for t_standard_cost_budget
-- ----------------------------
DROP TABLE IF EXISTS `t_standard_cost_budget`;
CREATE TABLE `t_standard_cost_budget`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `art_seq` int(11) NULL DEFAULT NULL COMMENT '产品资料主键',
  `sku` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'sku',
  `quotation_number` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价单编号',
  `logo_url` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '图片地址',
  `code` varchar(30) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工厂型体编号',
  `customer_seq` int(11) NULL DEFAULT NULL COMMENT '客户Id',
  `customer_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户名称',
  `customer_article_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户型体名称',
  `customer_article_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '客户型体编号',
  `product_class_seq` int(11) NULL DEFAULT NULL COMMENT '产品类别seq',
  `product_class_name` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品类别名称',
  `color` int(11) NULL DEFAULT NULL COMMENT '颜色序号',
  `color_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '颜色名称',
  `quarter_code` int(11) NULL DEFAULT NULL COMMENT '季度序号',
  `sex` int(11) NULL DEFAULT NULL COMMENT '样鞋性别（字典表seq）',
  `sample_stage_seq` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品阶段id',
  `sample_stage_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '样品阶段名称',
  `quotation_size_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价码',
  `transaction_price` decimal(10, 2) NULL DEFAULT NULL,
  `tag_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '吊牌价',
  `product_unit_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '产品单价',
  `profit_margin` decimal(10, 2) NULL DEFAULT NULL COMMENT '利润率',
  `target_unit_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '目标单价',
  `net_usage` decimal(10, 2) NULL DEFAULT NULL,
  `cost_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '成本价格',
  `total_price_materials` decimal(10, 2) NULL DEFAULT NULL COMMENT '材料总价',
  `cost_rate` decimal(10, 2) NULL DEFAULT NULL COMMENT '成本率',
  `differential_price` decimal(10, 2) NULL DEFAULT NULL COMMENT '差异价',
  `currency` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '币种',
  `exchange_rate` decimal(10, 2) NULL DEFAULT NULL COMMENT '汇率',
  `quotation_size_code_start` decimal(5, 2) NULL DEFAULT NULL COMMENT '报价尺码范围开始',
  `quotation_size_code_end` decimal(5, 2) NULL DEFAULT NULL COMMENT '报价尺码范围结束',
  `status` int(11) NULL DEFAULT NULL COMMENT '状态',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '创建人',
  `is_deleted` int(1) NULL DEFAULT 0 COMMENT '是否删除',
  `is_not_need_quotation` int(1) NULL DEFAULT 0 COMMENT '是否需要报价码',
  `created_at` timestamp NULL DEFAULT NULL COMMENT '创建时间',
  `updated_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '修改人',
  `updated_at` timestamp NULL DEFAULT NULL COMMENT '修改时间',
  `deleted_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '删除人',
  `deleted_at` timestamp NULL DEFAULT NULL COMMENT '删除时间',
  `created_by_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `order_quarter_code` int(11) NULL DEFAULT NULL COMMENT '下单季度序号',
  `version` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT 'V1' COMMENT '版本号',
  `art_version` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '产品资料版本号',
  `size_quote` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价尺码',
  `bomversionnumber` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT 'BOM版本号',
  `company_seq` int(11) NULL DEFAULT NULL COMMENT '公司seq',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3279 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '标准成本预算' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for t_standard_cost_ie
-- ----------------------------
DROP TABLE IF EXISTS `t_standard_cost_ie`;
CREATE TABLE `t_standard_cost_ie`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT,
  `standard_cost_budget_seq` int(11) NULL DEFAULT NULL COMMENT '客户报价主表seq',
  `art_seq` int(11) NULL DEFAULT NULL COMMENT '型体序号',
  `art_position_seq` int(11) NULL DEFAULT NULL COMMENT '型体部位序号',
  `ie_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工艺编码',
  `ie_name` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '工艺名称',
  `position_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位名称',
  `material_category_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '物料简码名称',
  `provider_seq` int(11) NULL DEFAULT NULL COMMENT '供应商seq',
  `provider_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '供应商名称',
  `unit_price` decimal(14, 4) NULL DEFAULT NULL COMMENT '单价',
  `remarks` varchar(500) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '备注',
  `created_by` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL,
  `created_at` datetime NULL DEFAULT NULL,
  `source` varchar(50) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT '0' COMMENT '来源(非0则是页面新增的）',
  PRIMARY KEY (`seq`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3360 CHARACTER SET = utf8 COLLATE = utf8_general_ci COMMENT = '客户报价工艺信息' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for t_standard_cost_material_details
-- ----------------------------
DROP TABLE IF EXISTS `t_standard_cost_material_details`;
CREATE TABLE `t_standard_cost_material_details`  (
  `seq` int(11) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `standard_cost_budget_seq` int(11) NULL DEFAULT NULL COMMENT '主表Seq',
  `quotation_supplier_seq` int(11) NULL DEFAULT NULL COMMENT '报价供应商seq',
  `quotation_supplier` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '报价供应商',
  `material_category_seq` int(11) NULL DEFAULT NULL COMMENT '物料简码序号',
  `material_category_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料简码',
  `material_category_name` text CHARACTER SET utf8 COLLATE utf8_general_ci NULL COMMENT '物料简码名称',
  `material_info_seq` int(11) NULL DEFAULT NULL COMMENT '物料编码seq',
  `material_info_code` varchar(100) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '物料编码',
  `position_seq` int(11) NULL DEFAULT NULL COMMENT '部件序号',
  `position_code` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位编号',
  `position_name` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位名称',
  `position_type` varchar(255) CHARACTER SET utf8 COLLATE utf8_general_ci NULL DEFAULT NULL COMMENT '部位分类(改为物料分组)',
