-- ----------------------------
-- View structure for andy_position
-- ----------------------------
DROP VIEW IF EXISTS `andy_position`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `andy_position` AS select `a`.`seq` AS `old_seq`,`a`.`code` AS `old_code`,`a`.`name` AS `old_name`,`b`.`seq` AS `new_seq`,`b`.`code` AS `new_code`,`b`.`name` AS `new_name` from (`position` `a` join `position` `b` on(((`a`.`deleted_by` = 'system') and (`a`.`sys_dict_seq` = `b`.`sys_dict_seq`) and (`a`.`name` = `b`.`name`) and (`b`.`is_deleted` = 0))));

-- ----------------------------
-- View structure for andy_test_0104
-- ----------------------------
DROP VIEW IF EXISTS `andy_test_0104`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `andy_test_0104` AS select `aa`.`factory_id` AS `factory_id`,`aa`.`in_warehouse_seq` AS `in_warehouse_seq`,`aa`.`in_location_seq` AS `in_location_seq`,`aa`.`product_code` AS `product_code`,`aa`.`position_code` AS `position_code`,`aa`.`material_seq` AS `material_seq`,`aa`.`customer_article_code` AS `customer_article_code`,`aa`.`sku` AS `sku`,`aa`.`row_no` AS `row_no`,`aa`.`manual_prod_code` AS `manual_prod_code`,`aa`.`material_code` AS `material_code`,`aa`.`material_name` AS `material_name`,`aa`.`color_name` AS `color_name`,`aa`.`size` AS `size`,`aa`.`factory_name` AS `factory_name`,`aa`.`in_warehouse_name` AS `in_warehouse_name`,`aa`.`in_location_name` AS `in_location_name`,`aa`.`unit_name` AS `unit_name`,`aa`.`in_rate_price` AS `in_rate_price`,`aa`.`out_rate_price` AS `out_rate_price`,sum(`aa`.`stock_num`) AS `stock_num`,sum(`aa`.`clrkInQty`) AS `clrkInQty`,sum(`aa`.`xctlInQty`) AS `xctlInQty`,sum(`aa`.`qtrkInQty`) AS `qtrkInQty`,sum(`aa`.`kcdbInQty`) AS `kcdbInQty`,sum(`aa`.`ghdbInQty`) AS `ghdbInQty`,sum(`aa`.`zcrkInQty`) AS `zcrkInQty`,sum(`aa`.`dydbInQty`) AS `dydbInQty`,sum(`aa`.`clckOutQty`) AS `clckOutQty`,sum(`aa`.`zlckOutQty`) AS `zlckOutQty`,sum(`aa`.`kctlOutQty`) AS `kctlOutQty`,sum(`aa`.`qtckOutQty`) AS `qtckOutQty`,sum(`aa`.`kcdbOutQty`) AS `kcdbOutQty`,sum(`aa`.`ghdbOutQty`) AS `ghdbOutQty`,sum(`aa`.`zcckOutQty`) AS `zcckOutQty`,sum(`aa`.`dydbOutQty`) AS `dydbOutQty`,min(`aa`.`created_at`) AS `created_at`,sum((`aa`.`stock_num` + `aa`.`finalQty`)) AS `finalQty`,`aa`.`quarterName` AS `quarterName`,`aa`.`customer_name` AS `customer_name`,`aa`.`code` AS `code`,`aa`.`class_name` AS `class_name`,`aa`.`group_name` AS `group_name`,`aa`.`product_class_name` AS `product_class_name` from (select `a`.`factory_id` AS `factory_id`,`a`.`in_warehouse_seq` AS `in_warehouse_seq`,`a`.`in_location_seq` AS `in_location_seq`,`a`.`product_code` AS `product_code`,`a`.`position_code` AS `position_code`,`a`.`material_seq` 