CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `store_inout_sum_view` AS select `a`.`customer_article_code` AS `型体`,`a`.`sku` AS `sku`,`a`.`row_no` AS `PO`,`a`.`manual_prod_code` AS `指令号`,`a`.`product_code` AS `product_code`,`a`.`position_code` AS `position_code`,`a`.`position_name` AS `部位名称`,`a`.`material_seq` AS `material_seq`,`a`.`material_code` AS `material_code`,`a`.`material_name` AS `material_name`,`a`.`color_name` AS `color_name`,`a`.`size` AS `size`,`a`.`factory_id` AS `factory_id`,`a`.`factory_name` AS `factory_name`,`a`.`in_warehouse_seq` AS `in_warehouse_seq`,`a`.`in_warehouse_name` AS `in_warehouse_name`,`a`.`in_location_seq` AS `in_location_seq`,`a`.`in_location_name` AS `in_location_name`,min(`a`.`unit_name`) AS `unit_name`,`a`.`in_rate_price` AS `入库单价`,`a`.`out_rate_price` AS `出库单价`,sum(`a`.`clrkInQty`) AS `材料入库数量`,sum(`a`.`xctlInQty`) AS `退料入库数量`,sum(`a`.`qtrkInQty`) AS `新增入库数量`,sum(`a`.`kcdbInQty`) AS `调拨入库数量`,sum(`a`.`ghdbInQty`) AS `归还入库数量`,sum(`a`.`zcrkInQty`) AS `转仓入库数量`,sum(`a`.`dydbInQty`) AS `替代品调入数量`,sum(`a`.`clckOutQty`) AS `领料出库数量`,sum(`a`.`zlckOutQty`) AS `委外出库数量`,sum(`a`.`kctlOutQty`) AS `库存直接退料数量`,sum(`a`.`qtckOutQty`) AS `新增出库数量`,sum(`a`.`kcdbOutQty`) AS `调拨出库数量`,sum(`a`.`ghdbOutQty`) AS `归还出库数量`,sum(`a`.`zcckOutQty`) AS `转仓出库数量`,sum(`a`.`dydbOutQty`) AS `替代品调出数量`,min(`a`.`created_at`) AS `created_at`,sum((`a`.`in_qty` - `a`.`out_qty`)) AS `期末库存`,`a`.`store_price` AS `store_price`,`d`.`dict_label` AS `季度`,`a`.`customer_name` AS `客户`,`o`.`code` AS `业务导单号`,`mc`.`class_name` AS `物料类别`,`mc`.`group_name` AS `物料分组`,`da`.`product_class_name` AS `鞋型系列` from ((((((`pdm`.`store_detail_inout_view` `a` left join `pdm`.`dict_data` `d` on(((`d`.`dict_code` = `a`.`quarter_code`) and (`d`.`dict_type` = 'quarter_code')))) left join `pdm`.`od_product_order_doc` `doc` on((`a`.`product_code` = `doc`.`code`))) left join `pdm`.`od_product_order_order` `po` on((`po`.`prou_order_seq` = `doc`.`seq`))) left join `pdm`.`od_order_doc_article` `da` on((`p