CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `test_new` AS select group_concat(distinct `a`.`code` order by 1 ASC separator ',') AS `code`,min(`a`.`purchaser`) AS `purchaser`,`c`.`proc_material_procurement_seq` AS `proc_material_procurement_seq`,sum(`c`.`total_purchase_quantity`) AS `total_purchase_quantity`,sum(`c`.`inspection_remaining_quantity`) AS `inspection_remaining_quantity`,sum(`c`.`remaining_quantity`) AS `remaining_quantity`,sum(`c`.`inv_remaining_quantity`) AS `inv_remaining_quantity`,min(`a`.`first_delivery_at`) AS `pmz_first_delivery_at`,max(`a`.`latest_delivery_at`) AS `latest_delivery_at`,min(`b`.`first_confirm_date`) AS `first_confirm_date`,max(`b`.`second_confirm_date`) AS `second_confirm_date`,max(`b`.`third_confirm_date`) AS `third_confirm_date` from ((`proc_material_list` `a` join `proc_material_list_info_sum` `b` on(((`a`.`seq` = `b`.`proc_material_list_seq`) and (`a`.`is_deleted` = 0) and (`b`.`is_deleted` = 0)))) join `proc_material_list_info` `c` on(((`b`.`seq` = `c`.`proc_material_list_info_sum_seq`) and (`c`.`is_deleted` = 0)))) group by `c`.`proc_material_procurement_info_seq`;

-- ----------------------------
-- Procedure structure for delete_duplicate_store
-- ----------------------------
DROP PROCEDURE IF EXISTS `delete_duplicate_store`;
delimiter ;;
CREATE PROCEDURE `delete_duplicate_store`()
BEGIN
    -- 定义变量
    DECLARE done INT DEFAULT 0;
    DECLARE id_list VARCHAR(2000); -- 存储分组id列表（逗号分隔）
    DECLARE m_seq, p_code, w_seq, l_code, f_id VARCHAR(50); -- 分组字段（根据实际类型调整）
    DECLARE m_code, prod_code, l_name VARCHAR(50);
    DECLARE id_arr TEXT;
    DECLARE retain_id INT; -- 保留的id
    DECLARE temp_id INT;
    DECLARE cur CURSOR FOR -- 游标获取分组数据
        SELECT 
            CONCAT(GROUP_CONCAT(a.id SEPARATOR ',')) AS id_list,
            a.material_seq,a.material_code,a.product_code,a.position_code,a.warehouse_seq,a.location_code,a.location_name,a.factory_id
        FROM store a
        WHERE a.on_hand_qty = 0
        GROUP BY a.material_seq,a.material_code,a.product_code,a.position_code,a.warehouse_seq,a.location_code,a.location_name,a.factory_id
        HAVING COUNT(1) > 1;
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = 1;
    
    -- 打开游标
    OPEN cur;
    read_loop: LOOP
        FETCH cur INTO id_list, m_seq, m_code, prod_code, p_code, w_seq, l_code, l_name, f_id;
        IF done THEN
            LEAVE read_loop;
        END IF;
        
        -- 随机选一个保留的id（MySQL 5.x通过字符串分割+随机数实现）
        SET @cnt = LENGTH(id_list) - LENGTH(REPLACE(id_list, ',', '')) + 1; -- 统计id个数
        SET @rand_idx = FLOOR(RAND() * @cnt) + 1; -- 随机位置（1~cnt）
        -- 分割字符串获取保留id（调用自定义split_str函数，见下文）
        SET retain_id = split_str(id_list, ',', @rand_idx);
        
        -- 删除分组中除retain_id外的所有记录
        DELETE FROM store 
        WHERE material_seq = m_seq 
          AND material_code = m_code 
          AND product_code = prod_code 
          AND position_code = p_code 
          AND warehouse_seq = w_seq 
          AND location_code = l_code 
          AND location_name = l_name 
          AND factory_id = f_id 
          AND on_hand_qty = 0 
          AND id <> retain_id;
    END LOOP;
    
    CLOSE cur;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for InsertGroupDispatchOrder
-- ----------------------------
DROP PROCEDURE IF EXISTS `InsertGroupDispatchOrder`;
delimiter ;;
CREATE PROCEDURE `InsertGroupDispatchOrder`()
BEGIN
    -- Variable declarations (all required columns)
    DECLARE v_dispatch_group_code VARCHAR(20);
    DECLARE v_firm_id INT;
    DECLARE v_firm_name VARCHAR(50);
    DECLARE v_produce_seq INT;
    DECLARE v_produce_code VARCHAR(50);  -- Added missing variable
    DECLARE v_process_id INT;
    DECLARE v_process VARCHAR(50);
    DECLARE v_po VARCHAR(50);
    DECLARE v_sku VARCHAR(50);
    DECLARE v_customer_order VARCHAR(50);
    DECLARE v_customer_name VARCHAR(50);
    DECLARE v_item_number VARCHAR(50);
    DECLARE v_pid VARCHAR(50);
    DECLARE v_created_by VARCHAR(64); 
    DECLARE v_created_at DATETIME;
    DECLARE v_mes_firm_id INT;
    DECLARE v_mes_firm_name VARCHAR(50);
    DECLARE v_quantity INT;
    DECLARE v_mes_customer_name VARCHAR(50);
    DECLARE v_is_process TINYINT;
    DECLARE v_od_product_order_code VARCHAR(255);
    DECLARE v_process_status TINYINT;
    DECLARE v_size_key VARCHAR(20);
    DECLARE v_size_value INT;
    
    -- Helper variables
    DECLARE v_cur_order VARCHAR(20) DEFAULT '';
    DECLARE v_max_item VARCHAR(10) DEFAULT '0000';
    DECLARE v_counter INT DEFAULT 0;
    DECLARE done BOOLEAN DEFAULT FALSE;
    
    -- Cursor definitions
    DECLARE cur_dept CURSOR FOR 
        SELECT distinct
            a.firm_id,
            a.firm_name,
            f.process_seq AS process_id,
            f.process_name AS process,
            a.po,
            b.sku,
            b.customer_code AS customer_order,
            c.custom_name AS customer_name,
            b.manual_prod_code AS item_number,
            pro.make_code AS pid,
            'system' AS created_by, 
            SYSDATE() AS created_at,
            a.firm_id AS mes_firm_id,
            a.firm_name AS mes_firm_name,
            a.quantity AS quantity,
            c.custom_name AS mes_customer_name,
            0 AS is_process,
            e.seq AS produce_seq,
            e.code AS produce_code,  -- Added missing column
            e.code AS od_product_order_code,
            0 AS process_status
        FROM group_dispatch_order_imp_andy a 
        INNER JOIN od_order_doc_article b 
            ON a.po = b.row_no AND b.is_deleted = 0
        INNER JOIN od_order_doc c 
            ON b.od_order_doc_seq = c.seq AND c.is_deleted = 0
        INNER JOIN od_product_order_order d 
            ON b.seq = d.order_doc_aritcle_seq AND d.order_seq = c.seq 
        INNER JOIN od_product_order_doc e 
            ON e.seq = d.prou_order_seq AND e.is_deleted = 0
        INNER JOIN (
            SELECT DISTINCT art_seq, process_seq, process_name 
            FROM om_art_position
        ) f ON e.art_seq = f.art_seq
        INNER JOIN sop_manufacturing_process pro 
            ON f.process_seq = pro.seq
				where a.po = 'MJCS0113';
    
    -- Handler for cursor completion
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    
    -- Initialize order prefix
    SET v_cur_order = CONCAT('GP', DATE_FORMAT(NOW(), '%Y%m%d'));
    
    -- Get current max sequence number
    SELECT IFNULL(MAX(RIGHT(dispatch_group_code, 4)), '0000')
    INTO v_max_item
    FROM group_dispatch_order
    WHERE left(dispatch_group_code,10) = v_cur_order;
    
    -- Open main cursor
    OPEN cur_dept;
    read_loop: LOOP
        FETCH cur_dept INTO 
            v_firm_id, v_firm_name, v_process_id, v_process, v_po,
            v_sku, v_customer_order, v_customer_name, v_item_number,
            v_pid, v_created_by, v_created_at, v_mes_firm_id, v_mes_firm_name,
            v_quantity, v_mes_customer_name, v_is_process, v_produce_seq,
            v_produce_code, v_od_product_order_code, v_process_status;
        
        IF done THEN
            LEAVE read_loop;
        END IF;
        
        -- Generate new dispatch code
        SET v_counter = v_counter + 1;
        SET v_dispatch_group_code = CONCAT(
            v_cur_order, 
            LPAD(CAST(SUBSTRING(v_max_item, 1, 4) AS UNSIGNED) + v_counter, 4, '0')
        );

						
        -- Insert main record
        INSERT INTO `pdm`.`group_dispatch_order` (
            dispatch_group_code, firm_id, firm_name, produce_seq, 
            produce_code, process_id, process, po, sku, 
            customer_order, customer_name, item_number, pid, 
            created_by, created_at, mes_firm_id, mes_firm_name, 
            quantity, mes_customer_name, is_process, 
            od_product_order_code, process_status
        ) VALUES (
            v_dispatch_group_code, v_firm_id, v_firm_name, v_produce_seq, 
            v_produce_code, v_process_id, v_process, v_po, v_sku, 
            v_customer_order, v_customer_name, v_item_number, v_pid, 
            v_created_by, v_created_at, v_mes_firm_id, v_mes_firm_name, 
            v_quantity, v_mes_customer_name, v_is_process, 
            v_od_product_order_code, v_process_status
        );
        
        -- Bulk insert size records
        INSERT INTO `pdm`.`group_dispatch_order_size` (dispatch_group_code, size_key, size_value)
        SELECT v_dispatch_group_code, size_key, size_value
        FROM group_dispatch_order_imp_andy
        WHERE po = v_po and firm_id = v_firm_id;
    END LOOP;
    
    -- Cleanup
    CLOSE cur_dept;
END
;;
delimiter ;

