            e.code AS produce_code,
            e.code AS od_product_order_code,
            0 AS process_status
        FROM group_dispatch_order_imp_andy a 
        INNER JOIN od_order_doc_article b 
            ON a.po = b.row_no AND b.is_deleted = 0
        INNER JOIN od_order_doc c 
            ON b.od_order_doc_seq = c.seq AND c.is_deleted = 0
        INNER JOIN od_product_order_order d 
            ON b.seq = d.order_doc_aritcle_seq AND d.order_seq = c.seq 
        INNER JOIN od_product_order_doc e 
            ON e.seq = d.prou_order_seq AND e.is_deleted = 0
        INNER JOIN (
            SELECT DISTINCT art_seq, process_seq, process_name 
            FROM om_art_position
        ) f ON e.art_seq = f.art_seq
        INNER JOIN sop_manufacturing_process pro 
            ON f.process_seq = pro.seq
        WHERE a.po = 'MJCS0114';
    
    -- Handler declarations LAST (after variables and cursors)
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            @sqlstate = RETURNED_SQLSTATE, 
            @errno = MYSQL_ERRNO, 
            @text = MESSAGE_TEXT;
        SET @full_error = CONCAT("ERROR ", @errno, " (", @sqlstate, "): ", @text);
        ROLLBACK;
        RESIGNAL SET MESSAGE_TEXT = @full_error;
    END;
    
    -- Main procedure logic
    START TRANSACTION;
    
    SET v_cur_order = CONCAT('GP', DATE_FORMAT(NOW(), '%Y%m%d'));
    
    SELECT IFNULL(MAX(RIGHT(dispatch_group_code, 4)), '0000')
    INTO v_max_item
    FROM group_dispatch_order
    WHERE LEFT(dispatch_group_code, 10) = v_cur_order;
    
    OPEN cur_dept;
    read_loop: LOOP
        FETCH cur_dept INTO 
            v_firm_id, v_firm_name, v_process_id, v_process, v_po,
            v_sku, v_customer_order, v_customer_name, v_item_number,
            v_pid, v_created_by, v_created_at, v_mes_firm_id, v_mes_firm_name,
            v_quantity, v_mes_customer_name, v_is_process, v_produce_seq,
            v_produce_code, v_od_product_order_code, v_process_status;
        
        IF done THEN
            LEAVE read_loop;
        END IF;
        
        SET v_counter = v_counter + 1;
        SET v_dispatch_group_code = CONCAT(
            v_cur_order, 
            LPAD(CAST(v_max_item AS UNSIGNED) + v_counter, 4, '0')
        );
        
        INSERT INTO `pdm`.`group_dispatch_order` (
            dispatch_group_code, firm_id, firm_name, produce_seq, 
            produce_code, process_id, process, po, sku, 
            customer_order, customer_name, item_number, pid, 
            created_by, created_at, mes_firm_id, mes_firm_name, 
            quantity, mes_customer_name, is_process, 
            od_product_order_code, process_status
        ) VALUES (
            v_dispatch_group_code, v_firm_id, v_firm_name, v_produce_seq, 
            v_produce_code, v_process_id, v_process, v_po, v_sku, 
            v_customer_order, v_customer_name, v_item_number, v_pid, 
            v_created_by, v_created_at, v_mes_firm_id, v_mes_firm_name, 
            v_quantity, v_mes_customer_name, v_is_process, 
            v_od_product_order_code, v_process_status
        );
        
		
				
        INSERT INTO `pdm`.`group_dispatch_order_size` (dispatch_group_code, size_key, size_value)
        SELECT v_dispatch_group_code, size_key, size_value
        FROM group_dispatch_order_imp_andy
        WHERE po = v_po AND firm_id = v_firm_id;
				
				COMMIT;
						
    END LOOP;
    
    CLOSE cur_dept;
    COMMIT;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for InsertOmArtIe
-- ----------------------------
DROP PROCEDURE IF EXISTS `InsertOmArtIe`;
delimiter ;;
CREATE PROCEDURE `InsertOmArtIe`()
BEGIN
    DECLARE done INT DEFAULT FALSE;
    DECLARE cur_id BIGINT;          -- 存储c表的主键ID
    DECLARE cur_a_seq BIGINT;       -- 存储a.seq的值
		DECLARE record_count INT DEFAULT 0;
		
    DECLARE cur_cursor CURSOR FOR 
      select om.seq,ie.art_seq
			 from om_article om INNER JOIN (
									select  b.sku,max(a.art_seq) art_seq
									from om_art_position_ie a  INNER JOIN om_article b on a.art_seq = b.seq 
									group by b.sku)  ie on om.sku = ie.sku and om.seq <> ie.art_seq
									and om.is_deleted = 0 and om.`enable` = 1
				where om.seq > ie.art_seq ;  -- 按主键排序减少锁冲突
    
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    
    -- 开启事务（每行独立事务）
    START TRANSACTION;
    
    OPEN cur_cursor;
    
    read_loop: LOOP
        FETCH cur_cursor INTO cur_id, cur_a_seq;
        IF done THEN
            LEAVE read_loop;
         END IF;
        
				-- SELECT CONCAT('处理: cur_id=', cur_id, ', cur_a_seq=', cur_a_seq) AS Processing;
				
				 -- 检查源数据是否存在
        SELECT COUNT(*) INTO @source_count 
        FROM om_art_position_ie 
        WHERE art_seq = cur_a_seq;
        
        IF @source_count = 0 THEN
            SELECT CONCAT('警告: seq=', cur_a_seq, ' 在源表中不存在数据') AS Warning;
           ITERATE read_loop;
        END IF;
				
        -- 逐行更新
        INSERT INTO `pdm`.`om_art_position_ie` ( `art_seq`, `art_position_seq`, `position_code`, `position_name`, `position_seq`, `no`, `ie_seq`, `ie_code`, `ie_name`, `memo`, `provider_seq`,`provider_name`,  `created_by`, `created_at`, `unit_price`) 
				
					select   cur_id, c.seq as art_position_seq,c.position_code,b.position_name,c.position_seq,a.no,a.ie_seq,a.ie_code,a.ie_name,a.memo,a.provider_seq,a.provider_name,'SYS' as created_by,SYSDATE() as created_at,0 as unit_price
				from om_art_position_ie a INNER join om_art_position b on a.art_seq = b.art_seq and a.art_position_seq = b.seq
																   left JOIN om_art_position c on c.art_seq = cur_id and b.position_name = c.position_name 
				where a.art_seq = cur_a_seq and c.seq is not NULL;
        
        -- 提交当前行的更新（立即释放锁）
        COMMIT;
        
        -- 开始新事务处理下一行
        START TRANSACTION;
     END LOOP;
    
    CLOSE cur_cursor;
    COMMIT;  -- 提交最后一行的事务
    SELECT 'INSERT completed successfully' AS Result;
 END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for InsertStoreOutList
-- ----------------------------
DROP PROCEDURE IF EXISTS `InsertStoreOutList`;
delimiter ;;
CREATE PROCEDURE `InsertStoreOutList`()
BEGIN
    -- All variable declarations FIRST
    DECLARE v_id VARCHAR(36);
    DECLARE v_bill_no VARCHAR(50);
    DECLARE v_bill_seq INT;
    DECLARE v_bill_info_seq INT;
    DECLARE v_material_seq INT;
    DECLARE v_material_code VARCHAR(255);
    DECLARE v_material_category_code VARCHAR(255);
    DECLARE v_material_name VARCHAR(255);
    DECLARE v_product_seq INT;
    DECLARE v_product_code VARCHAR(80);
    DECLARE v_customer_seq INT;
    DECLARE v_customer_name VARCHAR(80);
    DECLARE v_supply_seq INT;
    DECLARE v_supply_name VARCHAR(255);
    DECLARE v_batch_no INT;
    DECLARE v_warehouse_seq INT;
    DECLARE v_warehouse_code VARCHAR(80);
    DECLARE v_warehouse_name VARCHAR(80);
    DECLARE v_location_seq INT;
    DECLARE v_location_code VARCHAR(80);
    DECLARE v_location_name VARCHAR(80);
    DECLARE v_rate DECIMAL(18,3);
    DECLARE v_rate_price DECIMAL(10,2);
    DECLARE v_out_qty DECIMAL(18,4);
    DECLARE v_enable CHAR(1);
    DECLARE v_is_deleted CHAR(1);
    DECLARE v_created_by VARCHAR(255);
    DECLARE v_created_at DATETIME;
    DECLARE v_updated_by VARCHAR(255);
    DECLARE v_updated_at DATETIME;
    DECLARE v_deleted_by VARCHAR(255);
    DECLARE v_deleted_at DATETIME;
    DECLARE v_remark1 VARCHAR(255);
    DECLARE v_remark2 VARCHAR(255);
    DECLARE v_created_by_name VARCHAR(100);
    DECLARE v_position_seq INT;
    DECLARE v_position_code VARCHAR(500);
    DECLARE v_position_name VARCHAR(500);
    DECLARE v_transfer_inventory_qty DECIMAL(13,4);
    DECLARE v_transfer_outbound_qty DECIMAL(13,4);
    DECLARE v_size VARCHAR(500);
    DECLARE v_color_name VARCHAR(500);
    DECLARE v_manual_prod_code VARCHAR(200);
    DECLARE v_po VARCHAR(500);
    DECLARE v_sku VARCHAR(500);
    DECLARE v_factory_id INT;
    DECLARE v_factory_name VARCHAR(500);
    DECLARE v_row_no VARCHAR(200);
    DECLARE v_in_factory_id INT;
    DECLARE v_in_factory_name VARCHAR(500);
    DECLARE v_in_department VARCHAR(500);
    DECLARE v_in_group VARCHAR(500);
    DECLARE v_in_type VARCHAR(20);
    DECLARE v_customer_article_code VARCHAR(255);
    DECLARE v_quarter_code INT;
    DECLARE v_unit_name VARCHAR(255);
    DECLARE v_unit_seq INT;
    DECLARE v_amount DECIMAL(14,4);
    DECLARE v_out_type VARCHAR(20);
    DECLARE v_store_id VARCHAR(255);
    DECLARE v_store_in_list_id VARCHAR(255);
    DECLARE done INT DEFAULT FALSE;
    DECLARE row_count INT DEFAULT 0;
    
    -- Cursor declaration (BEFORE handlers)
    DECLARE cur_cursor CURSOR FOR 
        SELECT 
            a.bill_no,
            a.bill_seq,
            a.bill_info_seq,
            a.material_info_seq,
            a.material_info_code,
            a.material_category_code,
            a.material_category_name,
            a.product_order_seq,
            a.od_prod_order_code,
            a.customer_seq,
            a.customer_name,
            a.provider_seq,
            a.provider_name,
            1,  -- batch_number placeholder
            a.warehouse_seq,
            a.warehouse_code,
            a.warehouse_name,
            a.location_seq,
            a.location_code,
            a.location_name,
            NULL AS rate,
            round(a.out_qty,4) as out_qty,
            a.enable,
            a.is_deleted,
            a.created_by,
            a.created_at,
            a.created_by_name,
            a.position_seq,
            a.position_code,
            a.position_name,
            a.size,
            a.material_info_colour,
            a.manual_prod_code,
            a.row_no,  -- PO field
            a.sku,
            a.requisition_factory_id,
            a.requisition_factory,
            a.row_no,  -- Duplicate row_no
            a.picking_factory_id,
            a.picking_factory,
            a.picking_division,
            a.group_name,
            a.outbound_type_name,
            a.customer_article_code,
            a.quarter_code,
            a.mx_material_category_unit_name,
            a.out_type
        FROM store_out_info_view a;
    
    -- Handler declarations (AFTER cursor)
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    DECLARE CONTINUE HANDLER FOR SQLEXCEPTION 
    BEGIN
        GET DIAGNOSTICS CONDITION 1
            @sqlstate = RETURNED_SQLSTATE, 
            @errno = MYSQL_ERRNO, 
            @text = MESSAGE_TEXT;
        SELECT CONCAT('Error: ', @errno, ' (', @sqlstate, ') - ', @text) AS ErrorMessage;
    END;
    
    -- Set default values
    SET v_enable = '1';
    SET v_is_deleted = '0';
    SET v_created_at = NOW();
    SET v_updated_at = NOW();
    
    -- Debug: Check view record count
    SELECT COUNT(*) INTO @view_count FROM store_out_info_view;
    SELECT CONCAT('View contains ', @view_count, ' records') AS DebugInfo;
    
    -- Main processing
    START TRANSACTION;
    OPEN cur_cursor;
    
    read_loop: LOOP
        FETCH cur_cursor INTO 
            v_bill_no, v_bill_seq, v_bill_info_seq, v_material_seq,
            v_material_code, v_material_category_code, v_material_name, v_product_seq,
            v_product_code, v_customer_seq, v_customer_name, v_supply_seq, v_supply_name,
            v_batch_no, v_warehouse_seq, v_warehouse_code, v_warehouse_name, v_location_seq,
            v_location_code, v_location_name, v_rate, v_out_qty, v_enable,
            v_is_deleted, v_created_by, v_created_at, v_created_by_name, v_position_seq, v_position_code,
            v_position_name, v_size, v_color_name, v_manual_prod_code, v_po, v_sku, v_factory_id, v_factory_name, v_row_no,
            v_in_factory_id, v_in_factory_name, v_in_department, v_in_group, v_in_type,
            v_customer_article_code, v_quarter_code, v_unit_name, v_out_type;
        
        SET row_count = row_count + 1;
        SELECT CONCAT('Processing row #', row_count, ': ', v_bill_no, '-', v_material_code) AS Progress;
        
        IF done THEN
            SELECT CONCAT('End of cursor reached after processing ', row_count, ' rows') AS LoopStatus;
            LEAVE read_loop;
        END IF;
        
        -- Generate ID and reset variables
        SET v_id = UUID();
        SET v_rate_price = 0;
        SET v_store_id = NULL;
        SET v_store_in_list_id = NULL;
        SET v_unit_seq = NULL;
        SET v_remark1 = NULL;
        SET v_remark2 = NULL;
        SET v_transfer_inventory_qty = NULL;
        SET v_transfer_outbound_qty = NULL;
        SET v_updated_by = v_created_by;
        SET v_deleted_by = NULL;
        SET v_deleted_at = NULL;
        SET v_amount = NULL;
        
        -- Get inventory info
        BEGIN
            DECLARE CONTINUE HANDLER FOR NOT FOUND BEGIN END;
            SELECT batch_no, rate_price, 
                   ROUND(v_out_qty * rate_price, 4),
                   store_id, id
            INTO v_batch_no, v_rate_price, v_amount, v_store_id, v_store_in_list_id
            FROM store_in_list
            WHERE factory_id = v_factory_id 
              AND warehouse_seq = v_warehouse_seq 
              AND location_seq = v_location_seq 
              AND product_code = v_product_code 
              AND position_code = v_position_code 
              AND material_code = v_material_code 
              AND material_seq = v_material_seq
						 ORDER BY CREATED_AT ASC
            LIMIT 1;
        END;
        
        -- Update inventory if found
       -- IF v_store_in_list_id IS NOT NULL THEN
        --    UPDATE store_in_list 
        --    SET out_num = COALESCE(out_num, 0) + v_out_qty
        --    WHERE id = v_store_in_list_id;
      --  END IF;
        
        -- Insert record
        INSERT INTO store_out_list_andy (
            id, bill_no, bill_seq, bill_info_seq, material_seq, 
            material_code, material_category_code, material_name, product_seq,
            product_code, customer_seq, customer_name, supply_seq, supply_name,
            batch_no, warehouse_seq, warehouse_code, warehouse_name, location_seq,
            location_code, location_name, rate, rate_price, out_qty, enable,
            is_deleted, created_by, created_at, updated_by, updated_at, deleted_by,
            deleted_at, remark1, remark2, created_by_name, position_seq, position_code,
            position_name, transfer_inventory_qty, transfer_outbound_qty, size,
            color_name, manual_prod_code, po, sku, factory_id, factory_name, row_no,
            in_factory_id, in_factory_name, in_department, in_group, in_type,
            customer_article_code, quarter_code, unit_name, unit_seq, amount,
            out_type, store_id, store_in_list_id
        ) VALUES (
            v_id, v_bill_no, v_bill_seq, v_bill_info_seq, v_material_seq,
            v_material_code, v_material_category_code, v_material_name, v_product_seq,
            v_product_code, v_customer_seq, v_customer_name, v_supply_seq, v_supply_name,
            v_batch_no, v_warehouse_seq, v_warehouse_code, v_warehouse_name, v_location_seq,
            v_location_code, v_location_name, v_rate, v_rate_price, v_out_qty, v_enable,
            v_is_deleted, v_created_by, v_created_at, v_updated_by, v_updated_at, v_deleted_by,
            v_deleted_at, v_remark1, v_remark2, v_created_by_name, v_position_seq, v_position_code,
            v_position_name, v_transfer_inventory_qty, v_transfer_outbound_qty, v_size,
            v_color_name, v_manual_prod_code, v_po, v_sku, v_factory_id, v_factory_name, v_row_no,
            v_in_factory_id, v_in_factory_name, v_in_department, v_in_group, v_in_type,
            v_customer_article_code, v_quarter_code, v_unit_name, v_unit_seq, v_amount,
            v_out_type, v_store_id, v_store_in_list_id
        );
        
        SELECT CONCAT('Inserted row: ', row_count, ' (ID:', v_id, ')') AS InsertStatus;
    END LOOP;
    
    CLOSE cur_cursor;
    COMMIT;
    
    SELECT CONCAT('Completed. Processed ', row_count, ' rows.') AS FinalResult;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for RowByRowUpdateStoreDetail
-- ----------------------------
DROP PROCEDURE IF EXISTS `RowByRowUpdateStoreDetail`;
delimiter ;;
CREATE PROCEDURE `RowByRowUpdateStoreDetail`()
BEGIN
    -- 1. 声明变量（存储待更新的行标识与新值）
    DECLARE v_row_id varchar(36);               -- store_detail_list的主键（唯一定位行）
    DECLARE v_new_location_seq INT;     -- 要更新的新location_seq值
    DECLARE v_done BOOLEAN DEFAULT FALSE;-- 游标结束标志
    
    -- 2. 声明游标：获取所有需更新的记录（与原SQL逻辑一致）
    DECLARE cur CURSOR FOR 
        SELECT 
            a.id,               -- 取store_detail_list的主键
            b.location_seq      -- 取目标新值
        FROM store_out_list a
        INNER JOIN bas_company_warehouse_view b 
            ON a.warehouse_seq = b.warehouse_seq 
            AND a.location_name = b.location_name 
            AND a.location_seq <> b.location_seq  -- 仅更新不一致的行
  ;          -- 限定仓库编号
    
    -- 3. 游标结束处理器（无更多行时触发）
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET v_done = TRUE;
    
    -- 4. 打开游标并循环处理每一行
    OPEN cur;
    read_loop: LOOP
        --  fetch：将游标当前行的值存入变量
        FETCH cur INTO v_row_id, v_new_location_seq;
        
        --  终止条件：无更多行
        IF v_done THEN
            LEAVE read_loop;
        END IF;
        
        --  5. 逐行更新：用主键定位行，修改in_location_seq
        UPDATE store_out_list 
        SET location_seq = v_new_location_seq 
        WHERE id = v_row_id;  -- 主键定位确保仅更新当前行
    END LOOP;
    
    -- 6. 清理资源
    CLOSE cur;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for SafeDeleteStoreDetailList
-- ----------------------------
DROP PROCEDURE IF EXISTS `SafeDeleteStoreDetailList`;
delimiter ;;
CREATE PROCEDURE `SafeDeleteStoreDetailList`()
BEGIN
    -- 1. 声明变量：存储目标表主键及关键字段
    DECLARE done INT DEFAULT FALSE;
    DECLARE v_target_seq VARCHAR(150);          -- store_detail_list的主键（用于精准删除）
    DECLARE v_target_bill_no VARCHAR(50); -- store_detail_list的bill_no（用于条件判断）
    
    -- 2. 声明游标：按主键排序遍历目标表（避免随机锁冲突）
    -- 仅获取「主键」和「需判断的bill_no」，减少数据传输量
    DECLARE cur_target CURSOR FOR 
        SELECT 
            id,       -- 假设seq是store_detail_list的主键
            bill_no    
        FROM 
            store_detail_list 
        ORDER BY 
            id;       -- 按主键排序，保证访问顺序稳定
    
    -- 3. 异常处理：游标遍历完成后标记done为TRUE
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    
    -- 4. 初始化：开启第一个事务
    START TRANSACTION;
    
    -- 5. 打开游标并循环处理每一行
    OPEN cur_target;
    target_loop: LOOP
        -- 获取当前行数据
        FETCH cur_target INTO v_target_seq, v_target_bill_no;
        
        -- 无更多数据时退出循环
        IF done THEN
            LEAVE target_loop;
         END IF;
        
        -- 🔑 核心判断：当前bill_no是否不在两个表的联合结果中？
        -- 用EXISTS替代IN，避免全表扫描；UNION ALL合并两个表的匹配结果
        IF NOT EXISTS (
            SELECT 1 
            FROM (
                -- 检查store_in_list是否有该bill_no
                SELECT bill_no FROM store_in_list WHERE bill_no = v_target_bill_no
                UNION ALL
                -- 检查store_out_list是否有该bill_no
                SELECT bill_no FROM store_out_list WHERE bill_no = v_target_bill_no
            ) AS combined_bills
            LIMIT 1  -- 只要有一个存在，立即终止子查询
        ) THEN
            -- 满足删除条件：精准删除当前行（用主键锁定单行）
            DELETE FROM store_detail_list WHERE id = v_target_seq;
         END IF;
        
        -- ✅ 提交当前事务：释放行锁，避免锁积累
        COMMIT;
        -- 🔄 开始新事务：处理下一行
        START TRANSACTION;
     END LOOP;
    
    -- 6. 收尾：关闭游标+提交最后一行的事务
    CLOSE cur_target;
    COMMIT;
    
    SELECT 'Delete completed safely (row-by-row)' AS Result;
 END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for SafeUpdateMaterialListTodoCompany
-- ----------------------------
DROP PROCEDURE IF EXISTS `SafeUpdateMaterialListTodoCompany`;
delimiter ;;
CREATE PROCEDURE `SafeUpdateMaterialListTodoCompany`()
BEGIN
    -- 1. 声明变量：存储当前行数据
    DECLARE done INT DEFAULT FALSE;
    DECLARE v_todo_seq BIGINT;               -- 目标表(proc_material_list_todo)的主键
    DECLARE v_repl_comp_seq BIGINT;          -- 来源表(replenishment_requisition)的comp_seq
    DECLARE v_repl_comp_name VARCHAR(255);   -- 来源表的comp_name

    -- 2. 声明游标：获取需要更新的「目标表主键」及「来源表对应值」
    -- 关键：按目标表主键排序，减少锁竞争
    DECLARE cur_rows CURSOR FOR 
        SELECT 
            a.proc_material_procurement_info_seq,                -- 目标表主键（用于精准更新）
            b.comp_seq,           -- 需要设置的company_seq
            b.comp_name           -- 需要设置的company_name
        FROM 
            proc_material_list_todo a
        INNER JOIN 
            replenishment_requisition b 
            ON a.material_replenishment_seq = b.seq  -- 联表条件
        WHERE 
            a.company_seq <> b.comp_seq  -- 过滤需要更新的行
        ORDER BY 
            a.proc_material_procurement_info_seq;                     -- 按主键排序，避免随机访问锁冲突

    -- 3. 异常处理：游标遍历完成后标记done为TRUE
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    -- 4. 初始化事务（每行独立事务，更新后立即提交）
    START TRANSACTION;

    -- 5. 打开游标并循环处理每一行
    OPEN cur_rows;
    row_loop: LOOP
        -- 获取当前行数据
        FETCH cur_rows INTO v_todo_seq, v_repl_comp_seq, v_repl_comp_name;
        
        -- 无更多数据时退出循环
        IF done THEN
            LEAVE row_loop;
         END IF;

        -- 逐行更新目标表（用主键精准定位，锁范围最小）
        UPDATE 
            proc_material_list_todo 
        SET 
            company_seq = v_repl_comp_seq,
            company_name = v_repl_comp_name
        WHERE 
            proc_material_procurement_info_seq = v_todo_seq;  -- 主键定位，避免全表扫描

        -- 提交当前行的更新，立即释放行锁
        COMMIT;

        -- 开始新事务处理下一行（确保每行独立事务）
        START TRANSACTION;
     END LOOP;

    -- 6. 收尾工作
    CLOSE cur_rows;
    COMMIT;  -- 提交最后一行的 transaction（若有）
    SELECT 'Update completed safely' AS Result;
 END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for SafeUpdateProcMaterialListInfoSum
-- ----------------------------
DROP PROCEDURE IF EXISTS `SafeUpdateProcMaterialListInfoSum`;
delimiter ;;
CREATE PROCEDURE `SafeUpdateProcMaterialListInfoSum`()
BEGIN
    -- 1. 声明变量（存储待更新行的关键信息）
    DECLARE done INT DEFAULT FALSE;
    DECLARE v_target_seq BIGINT;          -- 目标表(proc_material_list_info_sum)主键（假设为seq）
    DECLARE v_new_code VARCHAR(50);        -- 新值：od_product_order_doc.code
    DECLARE v_row_no VARCHAR(50);          -- 连接条件：row_no（冗余存储，用于校验）
    DECLARE v_manual_prod_code VARCHAR(50);-- 连接条件：manual_prod_code（冗余存储，用于校验）

    -- 2. 声明游标：按目标表主键排序，获取需更新的行（核心！避免随机锁冲突）
    -- 仅查询必要字段：目标表主键(seq)、新值(code)、连接条件（用于校验）
    DECLARE cur_update CURSOR FOR 
        SELECT 
            a.seq,                   -- 目标表主键（用于精准更新）
            b.code,                  -- 要设置的新值：od_prod_order_code
            a.row_no,                -- 冗余存储连接条件（可选，用于调试）
            a.manual_prod_code       -- 冗余存储连接条件（可选，用于调试）
        FROM 
            proc_material_list_info_sum a
        INNER JOIN 
            od_product_order_doc b 
            ON a.row_no = b.row_no 
            AND a.manual_prod_code = b.manual_prod_code  -- 复合连接条件
        WHERE 
            a.od_prod_order_code <> b.code  -- 仅更新不匹配的行
            AND b.is_deleted = 0             -- 来源表未删除
            AND a.is_deleted = 0             -- 目标表未删除
        ORDER BY 
            a.seq;  -- 按目标表主键排序，顺序访问减少锁冲突

    -- 3. 异常处理：游标遍历完成后标记done=TRUE
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    -- 4. 初始化事务（每行独立事务，更新后立即提交）
    START TRANSACTION;

    -- 5. 打开游标，逐行处理
    OPEN cur_update;
    update_loop: LOOP
        -- 获取当前行数据
        FETCH cur_update INTO v_target_seq, v_new_code, v_row_no, v_manual_prod_code;
        
        -- 无数据时退出循环
        IF done THEN
            LEAVE update_loop;
        END IF;

        -- 🔑 核心：逐行精准更新（用目标表主键锁定单行）
        UPDATE proc_material_list_info_sum 
        SET od_prod_order_code = v_new_code 
        WHERE seq = v_target_seq;  -- 主键定位，仅锁单行

        -- ✅ 提交当前事务：释放行锁（关键！避免锁积累）
        COMMIT;

        -- 🔄 开始新事务处理下一行（确保每行独立事务）
        START TRANSACTION;
    END LOOP;

    -- 6. 收尾：关闭游标+提交最后一行事务
    CLOSE cur_update;
    COMMIT;

    SELECT 'Update completed safely (row-by-row)' AS Result;
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for SafeUpdateRowNo
-- ----------------------------
DROP PROCEDURE IF EXISTS `SafeUpdateRowNo`;
delimiter ;;
CREATE PROCEDURE `SafeUpdateRowNo`()
BEGIN
    -- 1. 声明变量：存储当前行数据

			DECLARE done INT DEFAULT FALSE; 
		  DECLARE v_old_ROW_NO varchar(255); 
			DECLARE v_new_row_no varchar(255);       DECLARE v_manual_prod_code varchar(255);  				
			DECLARE v_new_manual_prod_code varchar(255);  
			DECLARE v_new_customer_code varchar(255);  
      
    -- 2. 声明游标：获取需要更新的「目标表主键」及「来源表对应值」
    -- 关键：按目标表主键排序，减少锁竞争
    DECLARE cur_rows CURSOR FOR 
       select old_ROW_NO, new_row_no, manual_prod_code,new_manual_prod_code -- ,new_customer_code
         from od_order_odc_art_excel
        ORDER BY 1;                     -- 按主键排序，避免随机访问锁冲突

    -- 3. 异常处理：游标遍历完成后标记done为TRUE
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    -- 4. 初始化事务（每行独立事务，更新后立即提交）
    START TRANSACTION;

    -- 5. 打开游标并循环处理每一行
    OPEN cur_rows;
    row_loop: LOOP
        -- 获取当前行数据
        FETCH cur_rows INTO v_old_ROW_NO, v_new_row_no, v_manual_prod_code,v_new_manual_prod_code;
        
        -- 无更多数据时退出循环
        IF done THEN
            LEAVE row_loop;
         END IF;

       -- 更新正式订单
					UPDATE od_order_doc_article 
					SET row_no = v_new_row_no,sync_status = 0,manual_prod_code = v_new_manual_prod_code -- ,customer_code = v_new_customer_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND row_no = v_old_ROW_NO;

					-- 更新生产订单	

					UPDATE od_product_order_doc 
					SET row_no = v_new_row_no,manual_prod_code = v_new_manual_prod_code  -- ,customer_code = v_new_customer_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND row_no = v_old_ROW_NO;
						

					-- 更新采购需求计划	

					UPDATE proc_material_procurement 
					SET row_no = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND row_no = v_old_ROW_NO;
							
					-- proc_material_list_todo

					UPDATE proc_material_list_todo 
					SET row_no = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND row_no = v_old_ROW_NO;
						

					-- proc_material_list_info

					UPDATE proc_material_list_info 
					SET row_no = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND row_no = v_old_ROW_NO;
							

					-- proc_material_list_info_sum

					UPDATE proc_material_list_info_sum 
					SET row_no = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND row_no = v_old_ROW_NO;
						
					-- proc_material_out_process_order_info

					UPDATE proc_material_out_process_order_info 
					SET row_no = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND row_no = v_old_ROW_NO;
						

					-- proc_material_out_process_order_subtotal

					UPDATE proc_material_out_process_order_subtotal 
					SET po = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND po = v_old_ROW_NO;
						
					-- proc_material_out_process_receiving_todo
					UPDATE proc_material_out_process_receiving_todo 
					SET row_no = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND row_no = v_old_ROW_NO;
						
					-- proc_material_temporarily_receiving_info
					UPDATE proc_material_temporarily_receiving_info 
					SET po = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND po = v_old_ROW_NO;
						

					-- proc_material_temporarily_receiving_info_ext
					UPDATE proc_material_temporarily_receiving_info_ext 
					SET po = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND po = v_old_ROW_NO;

					-- proc_material_out_process_temporarily_receiving_info
					UPDATE proc_material_out_process_temporarily_receiving_info 
					SET po = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND po = v_old_ROW_NO;
						

					-- proc_material_out_process_temporarily_receiving_info_ext
					UPDATE proc_material_out_process_temporarily_receiving_info_ext 
					SET po = v_new_row_no
					WHERE
						 po = v_old_ROW_NO;
											
					-- proc_material_quality_spection_todo
					UPDATE proc_material_quality_spection_todo 
					SET po = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND po = v_old_ROW_NO;
						
						-- proc_material_quality_spection_info
					UPDATE proc_material_quality_spection_info 
					SET po = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND po = v_old_ROW_NO;
						

					-- proc_material_warehousing_todo
					UPDATE proc_material_warehousing_todo 
					SET po = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND po = v_old_ROW_NO;
						
						-- proc_material_warehousing_info
					UPDATE proc_material_warehousing_info 
					SET po = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND po = v_old_ROW_NO;
						

						-- store
					UPDATE store 
					SET row_no = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND row_no = v_old_ROW_NO;

						-- store_in_list
					UPDATE store_in_list 
					SET row_no = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND row_no = v_old_ROW_NO;
						
							-- store_detail_list
					UPDATE store_detail_list 
					SET row_no = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND row_no = v_old_ROW_NO;
						
							-- store_out_list
					UPDATE store_out_list 
					SET row_no = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND row_no = v_old_ROW_NO;
						

					-- proc_material_out_bound_info
					UPDATE proc_material_out_bound_info 
					SET row_no = v_new_row_no,manual_prod_code = v_new_manual_prod_code
					WHERE
						manual_prod_code = v_manual_prod_code
						AND row_no = v_old_ROW_NO;
						
        -- 提交当前行的更新，立即释放行锁
        COMMIT;
        		
        -- 开始新事务处理下一行（确保每行独立事务）
        START TRANSACTION;
     END LOOP;

    -- 6. 收尾工作
    CLOSE cur_rows;
    COMMIT;  -- 提交最后一行的 transaction（若有）
    SELECT 'Update completed safely' AS Result;
 END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for SafeUpdateStore
-- ----------------------------
DROP PROCEDURE IF EXISTS `SafeUpdateStore`;
delimiter ;;
CREATE PROCEDURE `SafeUpdateStore`()
BEGIN
    -- 1. 声明变量：存储当前行数据

		     DECLARE done INT DEFAULT FALSE; 
		  DECLARE v_id varchar(255); 
			DECLARE v_material_seq int(11); 
      DECLARE v_material_code varchar(255);  		
      
    -- 2. 声明游标：获取需要更新的「目标表主键」及「来源表对应值」
    -- 关键：按目标表主键排序，减少锁竞争
    DECLARE cur_rows CURSOR FOR 
       select  a.id,c.seq,c.material_code

			from store a inner join mx_material_category b on a.material_category_code = b.category_code
														inner join mx_material_info c on b.seq = c.material_category_seq and a.size = c.size_code and a.size is not null
						where   a.row_no = 'SKCSX00371' and a.material_category_code  LIKE 'D1V00004%'
						order by  CAST(a.size  AS DECIMAL(10,2)) desc  ;                     -- 按主键排序，避免随机访问锁冲突

    -- 3. 异常处理：游标遍历完成后标记done为TRUE
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;

    -- 4. 初始化事务（每行独立事务，更新后立即提交）
    START TRANSACTION;

    -- 5. 打开游标并循环处理每一行
    OPEN cur_rows;
    row_loop: LOOP
        -- 获取当前行数据
        FETCH cur_rows INTO v_id, v_material_seq, v_material_code;
        
        -- 无更多数据时退出循环
        IF done THEN
            LEAVE row_loop;
         END IF;

					UPDATE store 
					SET material_seq = v_material_seq,material_code  = v_material_code 
					WHERE  id = v_id;
						
        -- 提交当前行的更新，立即释放行锁
        COMMIT;
        		
        -- 开始新事务处理下一行（确保每行独立事务）
        START TRANSACTION;
     END LOOP;

    -- 6. 收尾工作
    CLOSE cur_rows;
    COMMIT; 
		
    SELECT 'Update completed safely' AS Result;
 END
;;
delimiter ;

-- ----------------------------
-- Function structure for split_str
-- ----------------------------
DROP FUNCTION IF EXISTS `split_str`;
delimiter ;;
CREATE FUNCTION `split_str`(x VARCHAR(2000),
    delim VARCHAR(1),
    pos INT)
 RETURNS varchar(50) CHARSET utf8
  DETERMINISTIC
BEGIN
    DECLARE start INT DEFAULT 1;
    DECLARE end INT;
    SET end = LOCATE(delim, x, start);
    WHILE pos > 1 AND end > 0 DO
        SET start = end + 1;
        SET end = LOCATE(delim, x, start);
        SET pos = pos - 1;
    END WHILE;
    IF end = 0 THEN SET end = LENGTH(x) + 1; END IF;
    RETURN SUBSTRING(x, start, end - start);
END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for UpdateMaterialProcurementInfo
-- ----------------------------
DROP PROCEDURE IF EXISTS `UpdateMaterialProcurementInfo`;
delimiter ;;
CREATE PROCEDURE `UpdateMaterialProcurementInfo`()
BEGIN
    DECLARE done INT DEFAULT FALSE;
    DECLARE cur_id BIGINT;          -- 存储c表的主键ID
    DECLARE cur_a_seq BIGINT;       -- 存储a.seq的值
    DECLARE cur_cursor CURSOR FOR 
        SELECT c.seq, a.seq
        FROM proc_material_procurement_info a
        INNER JOIN proc_material_procurement b ON b.seq = a.proc_material_procurement_seq
        INNER JOIN proc_material_list_info c 
            ON a.product_order_code = c.product_order_code
            AND a.position_code = c.position_code
            AND a.mx_material_info_code = c.mx_material_info_code
            AND c.is_deleted = 0
        WHERE 
            a.change_type IS NULL 
            AND a.is_deleted = 0 
            AND a.mx_material_category_is_out_sourcing = 0 
            AND a.seq <> c.proc_material_procurement_info_seq
        ORDER BY c.seq;  -- 按主键排序减少锁冲突
    
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    
    -- 开启事务（每行独立事务）
    START TRANSACTION;
    
    OPEN cur_cursor;
    
    read_loop: LOOP
        FETCH cur_cursor INTO cur_id, cur_a_seq;
        IF done THEN
            LEAVE read_loop;
         END IF;
        
        -- 逐行更新
        UPDATE proc_material_list_info 
        SET proc_material_procurement_info_seq = cur_a_seq
        WHERE seq = cur_id;
        
        -- 提交当前行的更新（立即释放锁）
        COMMIT;
        
        -- 开始新事务处理下一行
        START TRANSACTION;
     END LOOP;
    
    CLOSE cur_cursor;
    COMMIT;  -- 提交最后一行的事务
    SELECT 'Update completed successfully' AS Result;
 END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for UpdatePurdOutPrice
-- ----------------------------
DROP PROCEDURE IF EXISTS `UpdatePurdOutPrice`;
delimiter ;;
CREATE PROCEDURE `UpdatePurdOutPrice`()
proc_main: BEGIN
    -- ===========================================
    -- 第一部分：所有变量声明必须在BEGIN块的最前面
    -- ===========================================
    DECLARE done INT DEFAULT FALSE;
    DECLARE v_seq INT; 
    DECLARE v_company_id INT;
    DECLARE v_art_customer_seq INT; 
    DECLARE v_provider_seq INT;
    DECLARE v_quarter_code VARCHAR(255);
    DECLARE v_mx_material_info_code VARCHAR(300);
    DECLARE v_purchase_unit_price DECIMAL(18,4);
    DECLARE v_type_code VARCHAR(20);
    
    DECLARE v_inquiry_seq INT;                
    DECLARE v_bulk_unit_price DECIMAL(18,4);  
    DECLARE v_logistics_price DECIMAL(18,4);  
    DECLARE v_purd_price DECIMAL(18,4);
    
    -- 统计变量
    DECLARE v_total_processed INT DEFAULT 0;
    DECLARE v_success_count INT DEFAULT 0;
    DECLARE v_error_count INT DEFAULT 0;
    
    -- 游标声明
    DECLARE cur_rows CURSOR FOR 
      SELECT b.seq, a.receiving_company_id, b.art_customer_seq, b.provider_seq, b.order_quarter_code, b.mx_material_info_code, b.purchase_unit_price, 'A' AS type_code
      FROM proc_material_out_process_order_subtotal b 
      INNER JOIN proc_material_out_process_order a ON a.seq = b.out_process_order_seq 
    --    AND a.is_deleted = 0 AND b.is_deleted = 0
      WHERE b.art_customer_seq IS NOT NULL 
        AND b.provider_seq IS NOT NULL 
        AND b.order_quarter_code IS NOT NULL 
        AND b.mx_material_info_code IS NOT NULL
				AND IFNULL(purchase_unit_price,0) = 0 
      ORDER BY b.seq;

    -- 条件处理器
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        GET DIAGNOSTICS CONDITION 1 @error_message = MESSAGE_TEXT;
        SELECT CONCAT('SQL Error: ', @error_message) AS ErrorInfo;
        ROLLBACK;
    END;

    -- ===========================================
    -- 第二部分：业务逻辑开始（这里不能再有DECLARE语句）
    -- ===========================================
    
    -- 使用临时表方法绕过游标问题
    DROP TEMPORARY TABLE IF EXISTS temp_process_data;
    CREATE TEMPORARY TABLE temp_process_data (
        seq INT,
        receiving_company_id INT,
        art_customer_seq INT,
        provider_seq INT,
        quarter_code VARCHAR(255),
        mx_material_info_code VARCHAR(300),
        purchase_unit_price DECIMAL(18,4),
        type_code VARCHAR(20),
        process_order INT AUTO_INCREMENT PRIMARY KEY
    );
    
    -- 预加载数据到临时表
    INSERT INTO temp_process_data 
        (seq, receiving_company_id, art_customer_seq, provider_seq, 
         quarter_code, mx_material_info_code, purchase_unit_price, type_code)
    SELECT 
        b.seq, a.receiving_company_id, b.art_customer_seq, b.provider_seq, 
        b.quarter_code, b.mx_material_info_code, b.purchase_unit_price, 'A'
      FROM proc_material_out_process_order_subtotal b 
      INNER JOIN proc_material_out_process_order a ON a.seq = b.out_process_order_seq 
      AND a.is_deleted = 0 AND b.is_deleted = 0
    WHERE b.art_customer_seq IS NOT NULL 
      AND b.provider_seq IS NOT NULL 
      AND b.quarter_code IS NOT NULL 
      AND b.mx_material_info_code IS NOT NULL 
    ORDER BY b.seq;

   -- SELECT CONCAT('Loaded ', (SELECT COUNT(*) FROM temp_process_data), ' rows into temp table') AS LoadInfo;

    -- 重新定义游标指向临时表
    -- 注意：这里不能使用 DECLARE，所以我们用另一种方法
    -- 我们将直接使用临时表的自增ID来遍历
    
    SELECT MIN(process_order) INTO @min_order FROM temp_process_data;
    SELECT MAX(process_order) INTO @max_order FROM temp_process_data;
    
  --  SELECT CONCAT('Processing rows from order ', @min_order, ' to ', @max_order) AS RangeInfo;

    -- 开始事务
    START TRANSACTION;
    SET @start_time = NOW(3);

    -- 使用 WHILE 循环基于临时表的自增ID来处理数据
    SET @current_order = @min_order;
    
    WHILE @current_order <= @max_order DO
        
        -- 获取当前行的数据
        SELECT seq, receiving_company_id, art_customer_seq, provider_seq, 
               quarter_code, mx_material_info_code, purchase_unit_price, type_code
        INTO v_seq, v_company_id, v_art_customer_seq, v_provider_seq, 
             v_quarter_code, v_mx_material_info_code, v_purchase_unit_price, v_type_code
        FROM temp_process_data 
        WHERE process_order = @current_order;
        
        SET v_total_processed = v_total_processed + 1;
        
      --  SELECT CONCAT('Processing row ', v_total_processed, ' - Seq: ', v_seq, ' Order: ', @current_order) AS CurrentRowDebug;

        -- 初始化变量
        SET v_bulk_unit_price = 0;
        SET v_logistics_price = 0;
        SET v_inquiry_seq = NULL;

        BEGIN
            DECLARE EXIT HANDLER FOR SQLEXCEPTION 
            BEGIN
                GET DIAGNOSTICS CONDITION 1 @row_error_message = MESSAGE_TEXT;
                SELECT CONCAT('Row Error (Seq:', v_seq, '): ', @row_error_message) AS RowError;
                SET v_error_count = v_error_count + 1;
            END;

            -- 取物料最新单价
            SELECT t1.seq, IFNULL(t1.bulk_unit_price, 0)
            INTO v_inquiry_seq, v_bulk_unit_price
            FROM mat_price_inquiry t
            INNER JOIN (
                SELECT t1.seq, t1.supplier_seq, t1.customer_seq, t1.order_quarter_code,
                       t1.material_code, t1.bulk_unit_price, t1.mat_price_inquiry_seq
                FROM mat_price_inquiry_info t1
                WHERE t1.material_code = v_mx_material_info_code 
                  AND t1.order_quarter_code = v_quarter_code 
                  AND t1.supplier_seq = v_provider_seq 
                  AND t1.customer_seq = v_art_customer_seq
                  AND IFNULL(t1.bulk_unit_price, 0) > 0
                ORDER BY t1.seq DESC
                LIMIT 1
            ) t1 ON t.seq = t1.mat_price_inquiry_seq
           -- WHERE t.inquiry_status = '55'
            LIMIT 1;
                
            -- 取物流费用
            IF v_inquiry_seq IS NOT NULL THEN 
                SELECT IFNULL(aa.logistics_price, 0)
                INTO v_logistics_price
                FROM mat_price_inquiry_material_delivery_addr aa 
                INNER JOIN (
                    SELECT DISTINCT company_id, receipt_address 
                    FROM bas_company_contact
                ) bb ON aa.detailed_addr = bb.receipt_address
                WHERE aa.mat_price_inquiry_info_seq = v_inquiry_seq 
                  AND bb.company_id = v_company_id
                  AND IFNULL(aa.logistics_price, 0) > 0
                LIMIT 1;
                        
                IF v_logistics_price IS NULL THEN
                    SET v_logistics_price = 0;
                END IF;
            ELSE
                SET v_bulk_unit_price = 0;
                SET v_logistics_price = 0;
            END IF;
           
            SET v_purd_price = v_bulk_unit_price + v_logistics_price;
            
            -- 根据类型更新不同的表
            IF v_type_code = 'A' THEN
                UPDATE proc_material_out_process_order_subtotal
                SET purchase_unit_price = v_purd_price,
									  inquiry_price_code = CAST(v_inquiry_seq AS CHAR),
                    price_by = 'SYSTEM',
                    price_date = SYSDATE()
                WHERE seq = v_seq;
                
								
								UPDATE proc_material_out_process_order_info
								SET purchase_unit_price = v_purd_price,
									  inquiry_price_code = CAST(v_inquiry_seq AS CHAR),
                    price_by = 'SYSTEM',
                    price_date = SYSDATE()
								where out_process_order_subtotal_seq = v_seq;
								
                GET DIAGNOSTICS @update_rows = ROW_COUNT;
              --  SELECT CONCAT('Updated ', @update_rows, ' row(s) for seq ', v_seq) AS UpdateResult;
            END IF;
            
            SET v_success_count = v_success_count + 1;
        END;
        
        -- 移动到下一行
        SET @current_order = @current_order + 1;
        
        -- 每10行提交一次
        IF v_total_processed % 100 = 0 THEN
            COMMIT;
            START TRANSACTION;
        END IF;
        
    END WHILE;

    COMMIT;
    
    -- 清理临时表
    DROP TEMPORARY TABLE IF EXISTS temp_process_data;
    
    -- 计算耗时
    SET @end_time = NOW(3);
    SET @duration_seconds = TIMESTAMPDIFF(MICROSECOND, @start_time, @end_time) / 1000000;
    
    -- 详细的完成报告
    SELECT 
        'Update completed' AS Status,
        CONCAT('Total processed: ', v_total_processed) AS TotalProcessed,
        CONCAT('Success: ', v_success_count) AS SuccessCount,
        CONCAT('Errors: ', v_error_count) AS ErrorCount,
        CONCAT('Duration: ', ROUND(@duration_seconds, 2), ' seconds') AS Duration;

END proc_main
;;
delimiter ;

-- ----------------------------
-- Procedure structure for UpdatePurdPrice
-- ----------------------------
DROP PROCEDURE IF EXISTS `UpdatePurdPrice`;
delimiter ;;
CREATE PROCEDURE `UpdatePurdPrice`()
proc_main: BEGIN
    -- ===========================================
    -- 第一部分：所有变量声明必须在BEGIN块的最前面
    -- ===========================================
    DECLARE done INT DEFAULT FALSE;
    DECLARE v_seq INT; 
    DECLARE v_company_id INT;
    DECLARE v_art_customer_seq INT; 
    DECLARE v_provider_seq INT;
    DECLARE v_quarter_code VARCHAR(255);
    DECLARE v_mx_material_info_code VARCHAR(300);
    DECLARE v_purchase_unit_price DECIMAL(18,4);
    DECLARE v_type_code VARCHAR(20);
    
    DECLARE v_inquiry_seq INT;                
    DECLARE v_bulk_unit_price DECIMAL(18,4);  
    DECLARE v_logistics_price DECIMAL(18,4);  
    DECLARE v_purd_price DECIMAL(18,4);
    
    -- 统计变量
    DECLARE v_total_processed INT DEFAULT 0;
    DECLARE v_success_count INT DEFAULT 0;
    DECLARE v_error_count INT DEFAULT 0;
    
    -- 游标声明
    DECLARE cur_rows CURSOR FOR 
      SELECT b.seq, a.receiving_company_id, b.art_customer_seq, b.provider_seq, b.order_quarter_code, b.mx_material_info_code, b.purchase_unit_price, 'A' AS type_code
      FROM proc_material_list_info_sum b 
      INNER JOIN proc_material_list a ON a.seq = b.proc_material_list_seq 
     --   AND a.is_deleted = 0 AND b.is_deleted = 0
      WHERE b.art_customer_seq IS NOT NULL 
        AND b.provider_seq IS NOT NULL 
        AND b.quarter_code IS NOT NULL 
        AND b.mx_material_info_code IS NOT NULL
				AND IFNULL(purchase_unit_price,0) = 0 
      ORDER BY b.seq;

    -- 条件处理器
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        GET DIAGNOSTICS CONDITION 1 @error_message = MESSAGE_TEXT;
        SELECT CONCAT('SQL Error: ', @error_message) AS ErrorInfo;
        ROLLBACK;
    END;

    -- ===========================================
    -- 第二部分：业务逻辑开始（这里不能再有DECLARE语句）
    -- ===========================================
    
    -- 使用临时表方法绕过游标问题
    DROP TEMPORARY TABLE IF EXISTS temp_process_data;
    CREATE TEMPORARY TABLE temp_process_data (
        seq INT,
        receiving_company_id INT,
        art_customer_seq INT,
        provider_seq INT,
        quarter_code VARCHAR(255),
        mx_material_info_code VARCHAR(300),
        purchase_unit_price DECIMAL(18,4),
        type_code VARCHAR(20),
        process_order INT AUTO_INCREMENT PRIMARY KEY
    );
    
    -- 预加载数据到临时表
    INSERT INTO temp_process_data 
        (seq, receiving_company_id, art_customer_seq, provider_seq, 
         quarter_code, mx_material_info_code, purchase_unit_price, type_code)
    SELECT 
        b.seq, a.receiving_company_id, b.art_customer_seq, b.provider_seq, 
        b.quarter_code, b.mx_material_info_code, b.purchase_unit_price, 'A'
    FROM proc_material_list_info_sum b 
    INNER JOIN proc_material_list a ON a.seq = b.proc_material_list_seq 
   --   AND a.is_deleted = 0 AND b.is_deleted = 0
    WHERE b.art_customer_seq IS NOT NULL 
      AND b.provider_seq IS NOT NULL 
      AND b.order_quarter_code IS NOT NULL 
      AND b.mx_material_info_code IS NOT NULL 
    ORDER BY b.seq;

   -- SELECT CONCAT('Loaded ', (SELECT COUNT(*) FROM temp_process_data), ' rows into temp table') AS LoadInfo;

    -- 重新定义游标指向临时表
    -- 注意：这里不能使用 DECLARE，所以我们用另一种方法
    -- 我们将直接使用临时表的自增ID来遍历
    
    SELECT MIN(process_order) INTO @min_order FROM temp_process_data;
    SELECT MAX(process_order) INTO @max_order FROM temp_process_data;
    
  --  SELECT CONCAT('Processing rows from order ', @min_order, ' to ', @max_order) AS RangeInfo;

    -- 开始事务
    START TRANSACTION;
    SET @start_time = NOW(3);

    -- 使用 WHILE 循环基于临时表的自增ID来处理数据
    SET @current_order = @min_order;
    
    WHILE @current_order <= @max_order DO
        
        -- 获取当前行的数据
        SELECT seq, receiving_company_id, art_customer_seq, provider_seq, 
               quarter_code, mx_material_info_code, purchase_unit_price, type_code
        INTO v_seq, v_company_id, v_art_customer_seq, v_provider_seq, 
             v_quarter_code, v_mx_material_info_code, v_purchase_unit_price, v_type_code
        FROM temp_process_data 
        WHERE process_order = @current_order;
        
        SET v_total_processed = v_total_processed + 1;
        
      --  SELECT CONCAT('Processing row ', v_total_processed, ' - Seq: ', v_seq, ' Order: ', @current_order) AS CurrentRowDebug;

        -- 初始化变量
        SET v_bulk_unit_price = 0;
        SET v_logistics_price = 0;
        SET v_inquiry_seq = NULL;

        BEGIN
            DECLARE EXIT HANDLER FOR SQLEXCEPTION 
            BEGIN
                GET DIAGNOSTICS CONDITION 1 @row_error_message = MESSAGE_TEXT;
                SELECT CONCAT('Row Error (Seq:', v_seq, '): ', @row_error_message) AS RowError;
                SET v_error_count = v_error_count + 1;
            END;

            -- 取物料最新单价
            SELECT t1.seq, IFNULL(t1.bulk_unit_price, 0)
            INTO v_inquiry_seq, v_bulk_unit_price
            FROM mat_price_inquiry t
            INNER JOIN (
                SELECT t1.seq, t1.supplier_seq, t1.customer_seq, t1.order_quarter_code,
                       t1.material_code, t1.bulk_unit_price, t1.mat_price_inquiry_seq
                FROM mat_price_inquiry_info t1
                WHERE t1.material_code = v_mx_material_info_code 
                  AND t1.order_quarter_code = v_quarter_code 
                  AND t1.supplier_seq = v_provider_seq 
                  AND t1.customer_seq = v_art_customer_seq
                  AND IFNULL(t1.bulk_unit_price, 0) > 0
                ORDER BY t1.seq DESC
                LIMIT 1
            ) t1 ON t.seq = t1.mat_price_inquiry_seq
            -- WHERE t.inquiry_status = '55'
            LIMIT 1;
                
            -- 取物流费用
            IF v_inquiry_seq IS NOT NULL THEN 
                SELECT IFNULL(aa.logistics_price, 0)
                INTO v_logistics_price
                FROM mat_price_inquiry_material_delivery_addr aa 
                INNER JOIN (
                    SELECT DISTINCT company_id, receipt_address 
                    FROM bas_company_contact
                ) bb ON aa.detailed_addr = bb.receipt_address
                WHERE aa.mat_price_inquiry_info_seq = v_inquiry_seq 
                  AND bb.company_id = v_company_id
                  AND IFNULL(aa.logistics_price, 0) > 0
                LIMIT 1;
                        
                IF v_logistics_price IS NULL THEN
                    SET v_logistics_price = 0;
                END IF;
            ELSE
                SET v_bulk_unit_price = 0;
                SET v_logistics_price = 0;
            END IF;
           
            SET v_purd_price = v_bulk_unit_price + v_logistics_price;
            
            -- 根据类型更新不同的表
            IF v_type_code = 'A' THEN
                UPDATE proc_material_list_info_sum
                SET purchase_unit_price = v_purd_price,
									  inquiry_price_code = CAST(v_inquiry_seq AS CHAR),
                    price_by = 'SYSTEM',
                    price_date = SYSDATE()
                WHERE seq = v_seq;
                
								
								  UPDATE proc_material_list_info
                SET purchase_unit_price = v_purd_price,
									  inquiry_price_code = CAST(v_inquiry_seq AS CHAR),
                    price_by = 'SYSTEM',
                    price_date = SYSDATE()
                WHERE proc_material_list_info_sum_seq = v_seq;
								
								
                GET DIAGNOSTICS @update_rows = ROW_COUNT;
              --  SELECT CONCAT('Updated ', @update_rows, ' row(s) for seq ', v_seq) AS UpdateResult;
            END IF;
            
            SET v_success_count = v_success_count + 1;
        END;
        
        -- 移动到下一行
        SET @current_order = @current_order + 1;
        
        -- 每10行提交一次
        IF v_total_processed % 100 = 0 THEN
            COMMIT;
            START TRANSACTION;
        END IF;
        
    END WHILE;

    COMMIT;
    
    -- 清理临时表
    DROP TEMPORARY TABLE IF EXISTS temp_process_data;
    
    -- 计算耗时
    SET @end_time = NOW(3);
    SET @duration_seconds = TIMESTAMPDIFF(MICROSECOND, @start_time, @end_time) / 1000000;
    
    -- 详细的完成报告
    SELECT 
        'Update completed' AS Status,
        CONCAT('Total processed: ', v_total_processed) AS TotalProcessed,
        CONCAT('Success: ', v_success_count) AS SuccessCount,
        CONCAT('Errors: ', v_error_count) AS ErrorCount,
        CONCAT('Duration: ', ROUND(@duration_seconds, 2), ' seconds') AS Duration;

END proc_main
;;
delimiter ;

-- ----------------------------
-- Procedure structure for UpdateReplenishmentInfo
-- ----------------------------
DROP PROCEDURE IF EXISTS `UpdateReplenishmentInfo`;
delimiter ;;
CREATE PROCEDURE `UpdateReplenishmentInfo`()
BEGIN
    DECLARE done INT DEFAULT FALSE;
    DECLARE cur_id BIGINT;          -- 存储c表的主键ID
    DECLARE cur_a_seq DECIMAL(13,4);       -- 存储a.seq的值
    DECLARE cur_cursor CURSOR FOR 
        select a.seq, SUM(b.usages) as plan_usages
				from replenishment_requisition_info a  INNER JOIN od_product_order_order_position b on a.product_seq = b.od_prod_order_seq and a.position_seq = b.position_seq and a.material_info_seq= b.material_info_seq
				where IFNULL(a.usages,0) = 0 and a.provider_type_seq = 379 
				group by a.seq,a.product_seq,a.product_code,a.row_no,a.position_seq,a.material_info_seq,a.material_info_code,IFNULL(a.usages,0),
				b.position_seq ,b.material_info_seq
				having SUM(b.usages) > 0;  -- 按主键排序减少锁冲突
    
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    
    -- 开启事务（每行独立事务）
    START TRANSACTION;
    
    OPEN cur_cursor;
    
    read_loop: LOOP
        FETCH cur_cursor INTO cur_id, cur_a_seq;
        IF done THEN
            LEAVE read_loop;
         END IF;
        
        -- 逐行更新
        UPDATE replenishment_requisition_info 
        SET usages = cur_a_seq
        WHERE seq = cur_id;
        
        -- 提交当前行的更新（立即释放锁）
        COMMIT;
        
        -- 开始新事务处理下一行
        START TRANSACTION;
     END LOOP;
    
    CLOSE cur_cursor;
    COMMIT;  -- 提交最后一行的事务
    SELECT 'Update completed successfully' AS Result;
 END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for UpdateStoreCreateDate
-- ----------------------------
DROP PROCEDURE IF EXISTS `UpdateStoreCreateDate`;
delimiter ;;
CREATE PROCEDURE `UpdateStoreCreateDate`()
BEGIN
    DECLARE done INT DEFAULT FALSE;
    DECLARE v_row_no VARCHAR(60);          -- 存储c表的主键ID
    DECLARE v_material_code VARCHAR(255);       -- 存储a.seq的值
    DECLARE cur_cursor CURSOR FOR 
        SELECT row_no, material_code
        FROM store_andy_imp;  -- 按主键排序减少锁冲突
    
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    
    -- 开启事务（每行独立事务）
    START TRANSACTION;
    
    OPEN cur_cursor;
    
    read_loop: LOOP
        FETCH cur_cursor INTO v_row_no, v_material_code;
        IF done THEN
            LEAVE read_loop;
         END IF;
        
        -- 逐行更新
        update store_in_list
				set created_at = '2025-12-01 00:00:00'
				where row_no = v_row_no and material_code = v_material_code ;
				
				  -- 提交当前行的更新（立即释放锁）
        COMMIT;
				
				update store_detail_list
				set created_at = '2025-12-01 00:00:00'
				where row_no = v_row_no and material_code = v_material_code  and in_qty > 0;
								
        -- 提交当前行的更新（立即释放锁）
        COMMIT;
        
        -- 开始新事务处理下一行
        START TRANSACTION;
     END LOOP;
    
    CLOSE cur_cursor;
    COMMIT;  -- 提交最后一行的事务
    SELECT 'Update completed successfully' AS Result;
 END
;;
delimiter ;

-- ----------------------------
-- Procedure structure for UpdateStoreDetailBillPrice
-- ----------------------------
DROP PROCEDURE IF EXISTS `UpdateStoreDetailBillPrice`;
delimiter ;;
CREATE PROCEDURE `UpdateStoreDetailBillPrice`()
proc_main: BEGIN
    -- ===========================================
    -- 第一部分：所有变量声明必须在BEGIN块的最前面
    -- ===========================================
    DECLARE done INT DEFAULT FALSE;
    DECLARE v_seq VARCHAR(36);
    DECLARE v_company_id INT;
    DECLARE v_art_customer_seq INT; 
    DECLARE v_provider_seq INT;
    DECLARE v_quarter_code VARCHAR(255);
    DECLARE v_mx_material_info_code VARCHAR(300);
    DECLARE v_purchase_unit_price DECIMAL(18,4);
    DECLARE v_type_code VARCHAR(20);
    
    DECLARE v_inquiry_seq INT;                
    DECLARE v_bulk_unit_price DECIMAL(18,4);  
    DECLARE v_logistics_price DECIMAL(18,4);  
    DECLARE v_purd_price DECIMAL(18,4);
    
    -- 统计变量
    DECLARE v_total_processed INT DEFAULT 0;
    DECLARE v_success_count INT DEFAULT 0;
    DECLARE v_error_count INT DEFAULT 0;
    
    -- 游标声明
    DECLARE cur_rows CURSOR FOR
		  
			SELECT a.id,a.factory_id,a.customer_seq,a.supply_seq,a.quarter_code,a.material_code,(case when  a.in_qty > 0 then  a.in_rate_price else a.out_rate_price end)  as rate_price, case when ifnull(a.in_qty,0) > 0 then 'A'  else 'B' END AS type_code 
				FROM store_detail_list a 
				where a.is_deleted = 0 and 
							a.quarter_code is not NULL AND
							a.customer_seq is not null  and 
							a.supply_seq is not null and 
							a.material_code is not null  AND
							(case when  a.in_qty > 0 then  a.in_rate_price else a.out_rate_price end)  = 0 
			 ORDER BY a.created_at;

    -- 条件处理器
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        GET DIAGNOSTICS CONDITION 1 @error_message = MESSAGE_TEXT;
        SELECT CONCAT('SQL Error: ', @error_message) AS ErrorInfo;
        ROLLBACK;
    END;

    -- ===========================================
    -- 第二部分：业务逻辑开始（这里不能再有DECLARE语句）
    -- ===========================================
    
    -- 使用临时表方法绕过游标问题
    DROP TEMPORARY TABLE IF EXISTS temp_process_data;
    CREATE TEMPORARY TABLE temp_process_data (
        seq VARCHAR(36),
        receiving_company_id INT,
        art_customer_seq INT,
        provider_seq INT,
        quarter_code VARCHAR(255),
        mx_material_info_code VARCHAR(300),
        purchase_unit_price DECIMAL(18,4),
        type_code VARCHAR(20),
        process_order INT AUTO_INCREMENT PRIMARY KEY
    );
    
    -- 预加载数据到临时表
    INSERT INTO temp_process_data 
        (seq, receiving_company_id, art_customer_seq, provider_seq, 
         quarter_code, mx_material_info_code, purchase_unit_price, type_code)
 	   SELECT a.id,a.factory_id,a.customer_seq,a.supply_seq,
		  a.quarter_code,a.material_code,(case when  a.in_qty > 0 then  a.in_rate_price else a.out_rate_price end) , case when ifnull(a.in_qty,0) > 0 then 'A'  else 'B' END AS type_code 
				FROM store_detail_list a 
				where a.is_deleted = 0 and 
							a.quarter_code is not NULL AND
							a.customer_seq is not null  and 
							a.supply_seq is not null and 
							a.material_code is not null  AND
							(case when  a.in_qty > 0 then  a.in_rate_price else a.out_rate_price end)  = 0 
			 ORDER BY a.created_at;

   -- SELECT CONCAT('Loaded ', (SELECT COUNT(*) FROM temp_process_data), ' rows into temp table') AS LoadInfo;

    -- 重新定义游标指向临时表
    -- 注意：这里不能使用 DECLARE，所以我们用另一种方法
    -- 我们将直接使用临时表的自增ID来遍历
    
    SELECT MIN(process_order) INTO @min_order FROM temp_process_data;
    SELECT MAX(process_order) INTO @max_order FROM temp_process_data;
    
  --  SELECT CONCAT('Processing rows from order ', @min_order, ' to ', @max_order) AS RangeInfo;

    -- 开始事务
    START TRANSACTION;
    SET @start_time = NOW(3);

    -- 使用 WHILE 循环基于临时表的自增ID来处理数据
    SET @current_order = @min_order;
    
    WHILE @current_order <= @max_order DO
        
        -- 获取当前行的数据
        SELECT seq, receiving_company_id, art_customer_seq, provider_seq, 
               quarter_code, mx_material_info_code, purchase_unit_price, type_code
        INTO v_seq, v_company_id, v_art_customer_seq, v_provider_seq, 
             v_quarter_code, v_mx_material_info_code, v_purchase_unit_price, v_type_code
        FROM temp_process_data 
        WHERE process_order = @current_order;
        
        SET v_total_processed = v_total_processed + 1;
        
      --  SELECT CONCAT('Processing row ', v_total_processed, ' - Seq: ', v_seq, ' Order: ', @current_order) AS CurrentRowDebug;

        -- 初始化变量
        SET v_bulk_unit_price = 0;
        SET v_logistics_price = 0;
        SET v_inquiry_seq = NULL;

        BEGIN
            DECLARE EXIT HANDLER FOR SQLEXCEPTION 
            BEGIN
                GET DIAGNOSTICS CONDITION 1 @row_error_message = MESSAGE_TEXT;
                SELECT CONCAT('Row Error (Seq:', v_seq, '): ', @row_error_message) AS RowError;
                SET v_error_count = v_error_count + 1;
            END;

            -- 取物料最新单价
            SELECT t1.seq, IFNULL(t1.bulk_unit_price, 0)
            INTO v_inquiry_seq, v_bulk_unit_price
            FROM mat_price_inquiry t
            INNER JOIN (
                SELECT t1.seq, t1.supplier_seq, t1.customer_seq, t1.order_quarter_code,
                       t1.material_code, t1.bulk_unit_price, t1.mat_price_inquiry_seq
                FROM mat_price_inquiry_info t1
                WHERE t1.material_code = v_mx_material_info_code 
                  AND t1.order_quarter_code = v_quarter_code 
                  AND t1.supplier_seq = v_provider_seq 
                  AND t1.customer_seq = v_art_customer_seq
                  AND IFNULL(t1.bulk_unit_price, 0) > 0
                ORDER BY t1.seq DESC
                LIMIT 1
            ) t1 ON t.seq = t1.mat_price_inquiry_seq
            -- WHERE t.inquiry_status = '55'
            LIMIT 1;
                
            -- 取物流费用
            IF v_inquiry_seq IS NOT NULL THEN 
                SELECT IFNULL(aa.logistics_price, 0)
                INTO v_logistics_price
                FROM mat_price_inquiry_material_delivery_addr aa 
                INNER JOIN (
                    SELECT DISTINCT company_id, receipt_address 
                    FROM bas_company_contact
                ) bb ON aa.detailed_addr = bb.receipt_address
                WHERE aa.mat_price_inquiry_info_seq = v_inquiry_seq 
                  AND bb.company_id = v_company_id
                  AND IFNULL(aa.logistics_price, 0) > 0
                LIMIT 1;
                        
                IF v_logistics_price IS NULL THEN
                    SET v_logistics_price = 0;
                END IF;
            ELSE
                SET v_bulk_unit_price = 0;
                SET v_logistics_price = 0;
            END IF;
           
            SET v_purd_price = v_bulk_unit_price + v_logistics_price;
            
            -- 根据类型更新不同的表
            IF v_type_code = 'A' THEN
                UPDATE store_detail_list
                SET in_rate_price = v_purd_price,
								     amount = round(in_qty * v_purd_price,4),
									  inquiry_price_code = CAST(v_inquiry_seq AS CHAR),
                    price_by = 'SYSTEM',
                    price_date = SYSDATE()
                WHERE id = v_seq;
                
                GET DIAGNOSTICS @update_rows = ROW_COUNT;
							-- 	 SELECT CONCAT('Updated row ', @update_rows, ' - Seq: ', v_seq, ' purd_price: ', v_purd_price) AS UpdateResult;
            ELSE
							  UPDATE store_detail_list
                SET out_rate_price = v_purd_price,
								     amount = round(out_qty * v_purd_price,4),
									  inquiry_price_code = CAST(v_inquiry_seq AS CHAR),
                    price_by = 'SYSTEM',
                    price_date = SYSDATE()
                WHERE id = v_seq;
                
                GET DIAGNOSTICS @update_rows = ROW_COUNT;
							-- 	 SELECT CONCAT('Updated row ', @update_rows, ' - Seq: ', v_seq, ' purd_price: ', v_purd_price) AS UpdateResult;
            END IF;
            
            SET v_success_count = v_success_count + 1;
        END;
        
        -- 移动到下一行
        SET @current_order = @current_order + 1;
        
        -- 每10行提交一次
        IF v_total_processed % 100 = 0 THEN
            COMMIT;
            START TRANSACTION;
        END IF;
        
    END WHILE;

    COMMIT;
    
    -- 清理临时表
    DROP TEMPORARY TABLE IF EXISTS temp_process_data;
    
    -- 计算耗时
    SET @end_time = NOW(3);
    SET @duration_seconds = TIMESTAMPDIFF(MICROSECOND, @start_time, @end_time) / 1000000;
    
    -- 详细的完成报告
    SELECT 
        'Update completed' AS Status,
        CONCAT('Total processed: ', v_total_processed) AS TotalProcessed,
        CONCAT('Success: ', v_success_count) AS SuccessCount,
        CONCAT('Errors: ', v_error_count) AS ErrorCount,
        CONCAT('Duration: ', ROUND(@duration_seconds, 2), ' seconds') AS Duration;

END proc_main
;;
