-- ----------------------------
-- Procedure structure for UpdateStoreOutMaxPrice
-- ----------------------------
DROP PROCEDURE IF EXISTS `UpdateStoreOutMaxPrice`;
delimiter ;;
CREATE PROCEDURE `UpdateStoreOutMaxPrice`()
proc_main: BEGIN
    -- ===========================================
    -- 第一部分：所有变量声明必须在BEGIN块的最前面
    -- ===========================================
    DECLARE done INT DEFAULT FALSE;
    DECLARE v_seq INT; 
    DECLARE v_company_id INT;
    DECLARE v_art_customer_seq INT; 
    DECLARE v_provider_seq INT;
    DECLARE v_quarter_code VARCHAR(255);
    DECLARE v_mx_material_info_code VARCHAR(300);
    DECLARE v_purchase_unit_price DECIMAL(18,4);
    DECLARE v_type_code VARCHAR(20);
    
 
    -- 统计变量
    DECLARE v_total_processed INT DEFAULT 0;
    DECLARE v_success_count INT DEFAULT 0;
    DECLARE v_error_count INT DEFAULT 0;
    
    -- 游标声明
    DECLARE cur_rows CURSOR FOR 
      select a.factory_id,a.customer_seq,a.supply_seq,a.quarter_code,a.material_code,max(a.store_price) as max_store_price, 'A' AS type_code
						from store_in_list  a INNER JOIN  mx_material_category b on a.material_category_code = b.category_code and b.is_deleted = 0 and b.is_out_sourcing = 1
						GROUP BY a.factory_id,a.customer_seq,a.supply_seq,a.quarter_code,a.material_code
						having min(a.store_price) <> max(a.store_price);
     
    -- 条件处理器
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        GET DIAGNOSTICS CONDITION 1 @error_message = MESSAGE_TEXT;
        SELECT CONCAT('SQL Error: ', @error_message) AS ErrorInfo;
        ROLLBACK;
    END;

    -- ===========================================
    -- 第二部分：业务逻辑开始（这里不能再有DECLARE语句）
    -- ===========================================
    
    -- 使用临时表方法绕过游标问题
    DROP TEMPORARY TABLE IF EXISTS temp_process_data;
    CREATE TEMPORARY TABLE temp_process_data (
        receiving_company_id INT,
        art_customer_seq INT,
        provider_seq INT,
        quarter_code VARCHAR(255),
        mx_material_info_code VARCHAR(300),
        purchase_unit_price DECIMAL(18,4),
        type_code VARCHAR(20),
        process_order INT AUTO_INCREMENT PRIMARY KEY
    );
    
    -- 预加载数据到临时表
    INSERT INTO temp_process_data 
        (receiving_company_id, art_customer_seq, provider_seq, 
         quarter_code, mx_material_info_code, purchase_unit_price, type_code)
    select a.factory_id,a.customer_seq,a.supply_seq,
		       a.quarter_code,a.material_code,max(a.store_price) as max_store_price, 'A' AS type_code
						from store_in_list  a INNER JOIN  mx_material_category b on a.material_category_code = b.category_code and b.is_deleted = 0 and b.is_out_sourcing = 1
						GROUP BY a.factory_id,a.customer_seq,a.supply_seq,a.quarter_code,a.material_code
						having min(a.store_price) <> max(a.store_price);

   -- SELECT CONCAT('Loaded ', (SELECT COUNT(*) FROM temp_process_data), ' rows into temp table') AS LoadInfo;

    -- 重新定义游标指向临时表
    -- 注意：这里不能使用 DECLARE，所以我们用另一种方法
    -- 我们将直接使用临时表的自增ID来遍历
    
    SELECT MIN(process_order) INTO @min_order FROM temp_process_data;
    SELECT MAX(process_order) INTO @max_order FROM temp_process_data;
    
  --  SELECT CONCAT('Processing rows from order ', @min_order, ' to ', @max_order) AS RangeInfo;

    -- 开始事务
    START TRANSACTION;
    SET @start_time = NOW(3);

    -- 使用 WHILE 循环基于临时表的自增ID来处理数据
    SET @current_order = @min_order;
    
    WHILE @current_order <= @max_order DO
        
        -- 获取当前行的数据
        SELECT receiving_company_id, art_customer_seq, provider_seq, 
               quarter_code, mx_material_info_code, purchase_unit_price, type_code
        INTO v_company_id, v_art_customer_seq, v_provider_seq, 
             v_quarter_code, v_mx_material_info_code, v_purchase_unit_price, v_type_code
        FROM temp_process_data 
        WHERE process_order = @current_order;
        
        SET v_total_processed = v_total_processed + 1;
        
      --  SELECT CONCAT('Processing row ', v_total_processed, ' - Seq: ', v_seq, ' Order: ', @current_order) AS CurrentRowDebug;

        BEGIN
            DECLARE EXIT HANDLER FOR SQLEXCEPTION 
            BEGIN
                GET DIAGNOSTICS CONDITION 1 @row_error_message = MESSAGE_TEXT;
                SELECT CONCAT('Row Error (Seq:', v_mx_material_info_code, '): ', @row_error_message) AS RowError;
                SET v_error_count = v_error_count + 1;
            END;

        
            -- 根据类型更新不同的表
            IF v_type_code = 'A' THEN
                UPDATE store_in_list
                SET store_price = v_purchase_unit_price,
                    remark1 = '更新库存单价'
                WHERE  factory_id = v_company_id and 
								       customer_seq = v_art_customer_seq and 
											 supply_seq = v_provider_seq and 
											 quarter_code = v_quarter_code and 
											 material_code = v_mx_material_info_code;
							
                UPDATE store_out_list
                SET store_price = v_purchase_unit_price,
                    remark1 = '更新库存单价'
                 WHERE  factory_id = v_company_id and 
								       customer_seq = v_art_customer_seq and 
											 supply_seq = v_provider_seq and 
											 quarter_code = v_quarter_code and 
											 material_code = v_mx_material_info_code;
                
                UPDATE store_detail_list
                SET store_price = v_purchase_unit_price,
                    remark1 = '更新库存单价'
                WHERE  factory_id = v_company_id and 
								       customer_seq = v_art_customer_seq and 
											 supply_seq = v_provider_seq and 
											 quarter_code = v_quarter_code and 
											 material_code = v_mx_material_info_code;
                
                UPDATE store
                SET store_price = v_purchase_unit_price,
                    amount = ROUND(on_hand_qty * v_purchase_unit_price, 4),
                    remark1 = '更新库存单价'
                 WHERE  factory_id = v_company_id and 
								       customer_seq = v_art_customer_seq and 
											 supply_seq = v_provider_seq and 
											 quarter_code = v_quarter_code and 
											 material_code = v_mx_material_info_code;
                
                
                GET DIAGNOSTICS @update_rows = ROW_COUNT;
              --  SELECT CONCAT('Updated ', @update_rows, ' row(s) for seq ', v_seq) AS UpdateResult;
            END IF;
            
            SET v_success_count = v_success_count + 1;
        END;
        
        -- 移动到下一行
        SET @current_order = @current_order + 1;
        
        -- 每10行提交一次
        IF v_total_processed % 10 = 0 THEN
            COMMIT;
            START TRANSACTION;
        END IF;
        
    END WHILE;

    COMMIT;
    
    -- 清理临时表
    DROP TEMPORARY TABLE IF EXISTS temp_process_data;
    
    -- 计算耗时
    SET @end_time = NOW(3);
    SET @duration_seconds = TIMESTAMPDIFF(MICROSECOND, @start_time, @end_time) / 1000000;
    
    -- 详细的完成报告
    SELECT 
        'Update completed' AS Status,
        CONCAT('Total processed: ', v_total_processed) AS TotalProcessed,
        CONCAT('Success: ', v_success_count) AS SuccessCount,
        CONCAT('Errors: ', v_error_count) AS ErrorCount,
        CONCAT('Duration: ', ROUND(@duration_seconds, 2), ' seconds') AS Duration;

END proc_main
;;
delimiter ;

-- ----------------------------
-- Procedure structure for UpdateStoreOutPrice
-- ----------------------------
DROP PROCEDURE IF EXISTS `UpdateStoreOutPrice`;
delimiter ;;
CREATE PROCEDURE `UpdateStoreOutPrice`()
proc_main: BEGIN

    -- ===========================================
    -- 第一部分：所有变量声明必须在BEGIN块的最前面
    -- ===========================================

    DECLARE done INT DEFAULT FALSE;
    DECLARE v_product_code VARCHAR(255);
    DECLARE v_mx_material_info_code VARCHAR(300);
    DECLARE v_purchase_unit_price DECIMAL(18,4);
    DECLARE v_position_code VARCHAR(100);
    DECLARE V_key_size VARCHAR(20);
    DECLARE v_store_price DECIMAL(20,4);  -- 扩大范围和精度
    
    -- 统计变量
    DECLARE v_total_processed INT DEFAULT 0;
    DECLARE v_success_count INT DEFAULT 0;
    DECLARE v_error_count INT DEFAULT 0;
    
    -- 错误信息和边界检查
    DECLARE v_error_message TEXT DEFAULT '';
    DECLARE v_is_valid_price BOOLEAN DEFAULT TRUE;
    
    -- 游标声明
    DECLARE cur_rows CURSOR FOR
        SELECT a.product_code, a.position_code, a.material_code, a.store_price,(case when b.is_match_size = 1 then info.size_code else NULL end) as key_size
        FROM store_in_list a  
        INNER JOIN mx_material_category b ON a.material_category_code = b.category_code
            AND b.is_out_sourcing = 1 
            AND b.is_deleted = 0 
            AND a.is_deleted = 0
				INNER JOIN mx_material_info info on a.material_code = info.material_code and info.is_deleted = 0
        ORDER BY 1, 2;

    -- 条件处理器
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        GET DIAGNOSTICS CONDITION 1 @error_message = MESSAGE_TEXT;
        SELECT CONCAT('SQL Error: ', @error_message) AS ErrorInfo;
        ROLLBACK;
    END;

    -- ===========================================
    -- 第二部分：业务逻辑开始
    -- ===========================================
    
    -- 使用临时表方法绕过游标问题
    DROP TEMPORARY TABLE IF EXISTS temp_process_data;
    CREATE TEMPORARY TABLE temp_process_data (
        product_code VARCHAR(255),
        mx_material_info_code VARCHAR(300),
        purchase_unit_price DECIMAL(18,4),
        position_code VARCHAR(100),
				key_size VARCHAR(20),
        process_order INT AUTO_INCREMENT PRIMARY KEY
    );
    
    -- 预加载数据到临时表
    INSERT INTO temp_process_data 
        (product_code, mx_material_info_code, purchase_unit_price, position_code,key_size)
    SELECT a.product_code, a.material_code, a.rate_price, a.position_code,(case when b.is_match_size = 1 then info.size_code else NULL end) as key_size 
    FROM store_in_list a  
    INNER JOIN mx_material_category b ON a.material_category_code = b.category_code 
        AND b.is_out_sourcing = 1 
        AND b.is_deleted = 0 
        AND a.is_deleted = 0
		INNER JOIN mx_material_info info on a.material_code = info.material_code and info.is_deleted = 0
    ORDER BY 1, 2;

    -- 重新定义游标指向临时表
    SELECT MIN(process_order) INTO @min_order FROM temp_process_data;
    SELECT MAX(process_order) INTO @max_order FROM temp_process_data;

    -- 开始事务
    START TRANSACTION;
    SET @start_time = NOW(3);

    -- 使用 WHILE 循环基于临时表的自增ID来处理数据
    SET @current_order = @min_order;
    
    WHILE @current_order <= @max_order DO
        
        -- 获取当前行的数据
        SELECT product_code, mx_material_info_code, purchase_unit_price, position_code,key_size
        INTO v_product_code, v_mx_material_info_code, v_purchase_unit_price, v_position_code,v_key_size
        FROM temp_process_data 
        WHERE process_order = @current_order;
        
        SET v_total_processed = v_total_processed + 1;
        SET v_is_valid_price = TRUE;
        SET v_error_message = '';

        -- 初始化变量
        SET v_store_price = 0;
				
        BEGIN
            DECLARE EXIT HANDLER FOR SQLEXCEPTION 
            BEGIN
                GET DIAGNOSTICS CONDITION 1 @row_error_message = MESSAGE_TEXT;
                SELECT CONCAT('Row Error (Product:', v_product_code, ', Material:', v_mx_material_info_code, '): ', @row_error_message) AS RowError;
                SET v_error_count = v_error_count + 1;
                SET v_is_valid_price = FALSE;
            END;

            -- 按生产订单号+部位汇总单价,加工材料 尤其分码存在大小码单价，所以需按料号获取加工单价
						-- Row Error (Product:SCDD202510180124, Material:ZH0000680): Deadlock found when trying to get lock; try restarting transaction
            SELECT COALESCE(SUM(a.purchase_unit_price), 0)
            INTO v_store_price
            FROM (
											SELECT DISTINCT
													a.product_order_code,
													a.position_code,
													a.mx_material_category_code,
													a.purchase_unit_price 
											FROM proc_material_list_info a INNER JOIN proc_material_list b on a.proc_material_list_seq = b.seq and b.is_deleted = 0 and b.procurement_type = '量产采购'
											WHERE a.product_order_code = v_product_code
													AND a.position_code = v_position_code
													AND a.mx_material_category_is_match_size = 0
												  AND a.is_deleted = 0
									 UNION ALL
									   									
					        SELECT DISTINCT
													a.product_order_code,
													a.position_code,
													a.mx_material_category_code,
													a.purchase_unit_price 
											FROM proc_material_list_info a   INNER JOIN proc_material_list bb on a.proc_material_list_seq = bb.seq and bb.is_deleted = 0 and bb.procurement_type = '量产采购'
											                                 INNER JOIN mx_material_info b on a.mx_material_info_code = b.material_code and b.is_deleted = 0
											WHERE a.product_order_code = v_product_code
													AND a.position_code = v_position_code
													AND a.mx_material_category_is_match_size = 1
													and b.size_code = v_key_size
												  AND a.is_deleted = 0
									 UNION ALL
											SELECT DISTINCT
													a.product_order_code,
													a.position_code,
													a.mx_material_category_code,
													a.purchase_unit_price 
											FROM proc_material_out_process_order_info a INNER JOIN proc_material_out_process_order b on a.out_process_order_seq = b.seq and b.is_deleted = 0 and b.procurement_type = '量产加工采购'
											WHERE a.product_order_code = v_product_code
													AND a.position_code = v_position_code
													AND a.mx_material_category_is_match_size = 0
												  AND a.is_deleted = 0
									 UNION ALL
									   									
					        SELECT DISTINCT
													a.product_order_code,
													a.position_code,
													a.mx_material_category_code,
													a.purchase_unit_price 
											FROM proc_material_out_process_order_info a   INNER JOIN proc_material_out_process_order bb on a.out_process_order_seq = bb.seq and bb.is_deleted = 0 and bb.procurement_type = '量产加工采购'
											                                 INNER JOIN mx_material_info b on a.mx_material_info_code = b.material_code and b.is_deleted = 0
											WHERE a.product_order_code = v_product_code
													AND a.position_code = v_position_code
													AND a.mx_material_category_is_match_size = 1
													and b.size_code = v_key_size
												  AND a.is_deleted = 0			 
            ) a;
          
					
				
					
            -- 边界检查：确保价格在合理范围内
            IF v_store_price < 0 THEN
                SET v_error_message = CONCAT('Negative price detected: ', v_store_price);
                SET v_error_count = v_error_count + 1;
                SET v_is_valid_price = FALSE;
            ELSEIF v_store_price > 999999999999.999999 THEN  -- 扩大检查范围
                SET v_error_message = CONCAT('Price out of reasonable range: ', v_store_price);
                SET v_error_count = v_error_count + 1;
                SET v_is_valid_price = FALSE;
						ELSEIF v_store_price = 0 THEN
						    SET v_store_price =  v_purchase_unit_price ;  -- 若根据采购拿到的组合单价为0，则库存单价等于大货单价
            END IF;

            -- 只有价格有效时才进行更新
            IF v_is_valid_price THEN
                
                -- 根据类型更新不同的表
                UPDATE store_in_list
                SET store_price = v_store_price,
                    remark1 = '更新库存单价'
                WHERE product_code = v_product_code 
                    AND material_code = v_mx_material_info_code 
                    AND position_code = v_position_code;
                
                UPDATE store_out_list
                SET store_price = v_store_price,
                    remark1 = '更新库存单价'
                WHERE product_code = v_product_code 
                    AND material_code = v_mx_material_info_code 
                    AND position_code = v_position_code;
                
                UPDATE store_detail_list
                SET store_price = v_store_price,
                    remark1 = '更新库存单价'
                WHERE product_code = v_product_code 
                    AND material_code = v_mx_material_info_code 
                    AND position_code = v_position_code;
                
                UPDATE store
                SET store_price = v_store_price,
                    amount = ROUND(on_order_qty * v_store_price, 4),
                    remark1 = '更新库存单价'
                WHERE product_code = v_product_code 
                    AND material_code = v_mx_material_info_code 
                    AND position_code = v_position_code;
                
                SET v_success_count = v_success_count + 1;
            ELSE
                -- 记录错误但继续处理
                SELECT CONCAT('Skipped update due to: ', v_error_message) AS SkipReason;
            END IF;
            
        END;
        
        -- 移动到下一行
        SET @current_order = @current_order + 1;
        
        -- 每10行提交一次
        IF v_total_processed % 10 = 0 THEN
            COMMIT;
            START TRANSACTION;
        END IF;
        
    END WHILE;

    COMMIT;
    
    -- 清理临时表
    DROP TEMPORARY TABLE IF EXISTS temp_process_data;
    
    -- 计算耗时
    SET @end_time = NOW(3);
    SET @duration_seconds = TIMESTAMPDIFF(MICROSECOND, @start_time, @end_time) / 1000000;
    
    -- 详细的完成报告
    SELECT 
        'Update completed' AS Status,
        CONCAT('Total processed: ', v_total_processed) AS TotalProcessed,
        CONCAT('Success: ', v_success_count) AS SuccessCount,
        CONCAT('Errors: ', v_error_count) AS ErrorCount,
        CONCAT('Duration: ', ROUND(@duration_seconds, 2), ' seconds') AS Duration;

END proc_main
;;
delimiter ;

-- ----------------------------
-- Procedure structure for UpdateStorePrice
-- ----------------------------
DROP PROCEDURE IF EXISTS `UpdateStorePrice`;
delimiter ;;
CREATE PROCEDURE `UpdateStorePrice`()
proc_main: BEGIN
    -- ===========================================
    -- 第一部分：所有变量声明必须在BEGIN块的最前面
    -- ===========================================
    DECLARE done INT DEFAULT FALSE;
    DECLARE v_seq VARCHAR(36);
    DECLARE v_company_id INT;
    DECLARE v_art_customer_seq INT; 
    DECLARE v_provider_seq INT;
    DECLARE v_quarter_code VARCHAR(255);
    DECLARE v_mx_material_info_code VARCHAR(300);
    DECLARE v_purchase_unit_price DECIMAL(18,4);
    DECLARE v_type_code VARCHAR(20);
    
    DECLARE v_inquiry_seq INT;                
    DECLARE v_bulk_unit_price DECIMAL(18,4);  
    DECLARE v_logistics_price DECIMAL(18,4);  
    DECLARE v_purd_price DECIMAL(18,4);
    
    -- 统计变量
    DECLARE v_total_processed INT DEFAULT 0;
    DECLARE v_success_count INT DEFAULT 0;
    DECLARE v_error_count INT DEFAULT 0;
    
    -- 游标声明
    DECLARE cur_rows CURSOR FOR
		  
			SELECT a.id,a.factory_id,a.customer_seq,a.supply_seq,a.quarter_code,a.material_code,ifnull(a.rate_price,0), 'A' AS type_code 
				FROM store a 
				where a.is_deleted = 0 and 
							a.quarter_code is not NULL AND
							a.customer_seq is not null  and 
							a.supply_seq is not null and 
							a.material_code is not null  AND
							ifnull(a.rate_price,0) = 0  and
							a.on_hand_qty > 0
			 ORDER BY a.created_at;

    -- 条件处理器
    DECLARE CONTINUE HANDLER FOR NOT FOUND SET done = TRUE;
    DECLARE EXIT HANDLER FOR SQLEXCEPTION 
    BEGIN
        GET DIAGNOSTICS CONDITION 1 @error_message = MESSAGE_TEXT;
        SELECT CONCAT('SQL Error: ', @error_message) AS ErrorInfo;
        ROLLBACK;
    END;

    -- ===========================================
    -- 第二部分：业务逻辑开始（这里不能再有DECLARE语句）
    -- ===========================================
    
    -- 使用临时表方法绕过游标问题
    DROP TEMPORARY TABLE IF EXISTS temp_process_data;
    CREATE TEMPORARY TABLE temp_process_data (
        seq VARCHAR(36),
        receiving_company_id INT,
        art_customer_seq INT,
        provider_seq INT,
        quarter_code VARCHAR(255),
        mx_material_info_code VARCHAR(300),
        purchase_unit_price DECIMAL(18,4),
        type_code VARCHAR(20),
        process_order INT AUTO_INCREMENT PRIMARY KEY
    );
    
    -- 预加载数据到临时表
    INSERT INTO temp_process_data 
        (seq, receiving_company_id, art_customer_seq, provider_seq, 
         quarter_code, mx_material_info_code, purchase_unit_price, type_code)
 	   SELECT a.id,a.factory_id,a.customer_seq,a.supply_seq,
		       a.quarter_code,a.material_code,ifnull(a.rate_price,0), 'A' AS type_code 
				FROM store a 
				where a.is_deleted = 0 and 
							a.quarter_code is not NULL AND
							a.customer_seq is not null  and 
							a.supply_seq is not null and 
							a.material_code is not null AND
							ifnull(a.rate_price,0) = 0 and
							a.on_hand_qty > 0
			 ORDER BY a.created_at;

   -- SELECT CONCAT('Loaded ', (SELECT COUNT(*) FROM temp_process_data), ' rows into temp table') AS LoadInfo;

    -- 重新定义游标指向临时表
    -- 注意：这里不能使用 DECLARE，所以我们用另一种方法
    -- 我们将直接使用临时表的自增ID来遍历
    
    SELECT MIN(process_order) INTO @min_order FROM temp_process_data;
    SELECT MAX(process_order) INTO @max_order FROM temp_process_data;
    
  --  SELECT CONCAT('Processing rows from order ', @min_order, ' to ', @max_order) AS RangeInfo;

    -- 开始事务
    START TRANSACTION;
    SET @start_time = NOW(3);

    -- 使用 WHILE 循环基于临时表的自增ID来处理数据
    SET @current_order = @min_order;
    
    WHILE @current_order <= @max_order DO
        
        -- 获取当前行的数据
        SELECT seq, receiving_company_id, art_customer_seq, provider_seq, 
               quarter_code, mx_material_info_code, purchase_unit_price, type_code
        INTO v_seq, v_company_id, v_art_customer_seq, v_provider_seq, 
             v_quarter_code, v_mx_material_info_code, v_purchase_unit_price, v_type_code
        FROM temp_process_data 
        WHERE process_order = @current_order;
        
        SET v_total_processed = v_total_processed + 1;
        
      --  SELECT CONCAT('Processing row ', v_total_processed, ' - Seq: ', v_seq, ' Order: ', @current_order) AS CurrentRowDebug;

        -- 初始化变量
        SET v_bulk_unit_price = 0;
        SET v_logistics_price = 0;
        SET v_inquiry_seq = NULL;

        BEGIN
            DECLARE EXIT HANDLER FOR SQLEXCEPTION 
            BEGIN
                GET DIAGNOSTICS CONDITION 1 @row_error_message = MESSAGE_TEXT;
                SELECT CONCAT('Row Error (Seq:', v_seq, '): ', @row_error_message) AS RowError;
                SET v_error_count = v_error_count + 1;
            END;

            -- 取物料最新单价
            SELECT t1.seq, IFNULL(t1.bulk_unit_price, 0)
            INTO v_inquiry_seq, v_bulk_unit_price
            FROM mat_price_inquiry t
            INNER JOIN (
                SELECT t1.seq, t1.supplier_seq, t1.customer_seq, t1.order_quarter_code,
                       t1.material_code, t1.bulk_unit_price, t1.mat_price_inquiry_seq
                FROM mat_price_inquiry_info t1
                WHERE t1.material_code = v_mx_material_info_code 
                  AND t1.order_quarter_code = v_quarter_code 
                  AND t1.supplier_seq = v_provider_seq 
                  AND t1.customer_seq = v_art_customer_seq
                  AND IFNULL(t1.bulk_unit_price, 0) > 0
                ORDER BY t1.seq DESC
                LIMIT 1
            ) t1 ON t.seq = t1.mat_price_inquiry_seq
          --  WHERE t.inquiry_status = '55'
            LIMIT 1;
                
            -- 取物流费用
            IF v_inquiry_seq IS NOT NULL THEN 
                SELECT IFNULL(aa.logistics_price, 0)
                INTO v_logistics_price
                FROM mat_price_inquiry_material_delivery_addr aa 
                INNER JOIN (
                    SELECT DISTINCT company_id, receipt_address 
                    FROM bas_company_contact
                ) bb ON aa.detailed_addr = bb.receipt_address
                WHERE aa.mat_price_inquiry_info_seq = v_inquiry_seq 
                  AND bb.company_id = v_company_id
                  AND IFNULL(aa.logistics_price, 0) > 0
                LIMIT 1;
                        
                IF v_logistics_price IS NULL THEN
                    SET v_logistics_price = 0;
                END IF;
            ELSE
                SET v_bulk_unit_price = 0;
                SET v_logistics_price = 0;
            END IF;
           
            SET v_purd_price = v_bulk_unit_price + v_logistics_price;
            
            -- 根据类型更新不同的表
            IF v_type_code = 'A' THEN
                UPDATE store
                SET rate_price = v_purd_price,
								    amount = round(on_hand_qty * v_purd_price,4),
									  inquiry_price_code = CAST(v_inquiry_seq AS CHAR),
                    price_by = 'SYSTEM',
                    price_date = SYSDATE()
                WHERE id = v_seq;
                
                GET DIAGNOSTICS @update_rows = ROW_COUNT;
							-- 	SELECT CONCAT('Updated row ', @update_rows, ' - Seq: ', v_seq, ' purd_price: ', v_purd_price) AS UpdateResult;
              
            END IF;
            
            SET v_success_count = v_success_count + 1;
        END;
        
        -- 移动到下一行
        SET @current_order = @current_order + 1;
        
        -- 每10行提交一次
        IF v_total_processed % 100 = 0 THEN
            COMMIT;
            START TRANSACTION;
        END IF;
        
    END WHILE;

    COMMIT;
    
    -- 清理临时表
    DROP TEMPORARY TABLE IF EXISTS temp_process_data;
    
    -- 计算耗时
    SET @end_time = NOW(3);
    SET @duration_seconds = TIMESTAMPDIFF(MICROSECOND, @start_time, @end_time) / 1000000;
    
    -- 详细的完成报告
    SELECT 
        'Update completed' AS Status,
        CONCAT('Total processed: ', v_total_processed) AS TotalProcessed,
        CONCAT('Success: ', v_success_count) AS SuccessCount,
        CONCAT('Errors: ', v_error_count) AS ErrorCount,
        CONCAT('Duration: ', ROUND(@duration_seconds, 2), ' seconds') AS Duration;

END proc_main
;;
delimiter ;

-- ----------------------------
-- Event structure for ExecuteStoredProceduresWithStorePriceLogging
-- ----------------------------
DROP EVENT IF EXISTS `ExecuteStoredProceduresWithStorePriceLogging`;
delimiter ;;
CREATE EVENT `ExecuteStoredProceduresWithStorePriceLogging`
ON SCHEDULE
EVERY '1' DAY STARTS '2026-01-21 04:00:00'
DO BEGIN
    DECLARE CONTINUE HANDLER FOR SQLEXCEPTION
    BEGIN
        -- 记录错误日志到表中
        INSERT INTO procedure_execution_log 
        (procedure_name, execution_time, status, error_message)
        VALUES ('UpdatePurdOutPrice', NOW(), 'ERROR', 'Procedure execution failed');
    END;
    
    -- 记录开始时间
    INSERT INTO procedure_execution_log 
    (procedure_name, execution_time, status) 
    VALUES ('StartBatchExecution', NOW(), 'STARTED');
    
    -- 依次执行存储过程并记录状态
    CALL UpdatePurdOutPrice();
    INSERT INTO procedure_execution_log 
    (procedure_name, execution_time, status) 
    VALUES ('UpdatePurdOutPrice', NOW(), 'COMPLETED');
    
    CALL UpdatePurdPrice();
    INSERT INTO procedure_execution_log 
    (procedure_name, execution_time, status) 
    VALUES ('UpdatePurdPrice', NOW(), 'COMPLETED');
    
    CALL UpdateStoreOutPrice();
    INSERT INTO procedure_execution_log 
    (procedure_name, execution_time, status) 
    VALUES ('UpdateStoreOutPrice', NOW(), 'COMPLETED');
    
    CALL UpdateStoreOutMaxPrice();
    INSERT INTO procedure_execution_log 
    (procedure_name, execution_time, status) 
    VALUES ('UpdateStoreOutMaxPrice', NOW(), 'COMPLETED');
    
END
;;
delimiter ;

SET FOREIGN_KEY_CHECKS = 1;
